function deriveAreaReadiness(
  entry: Omit<AreaBlueprintEntry, "isPrimary" | "readiness">,
  data: ReturnType<typeof listAll>
): AreaBlueprintReadinessStatus {
  const allowedAreas = new Set<CompanyBrainArea>([
    entry.primaryArea,
    ...entry.alternateAreas,
  ]);
  const sourceCount = data.sources.filter((source) =>
    allowedAreas.has(source.area)
  ).length;
  const workItemCount = (data.workItems as WorkItem[]).filter((item) =>
    allowedAreas.has(item.area)
  ).length;
  const sessionResultCount = data.artifacts.filter(
    (artifact) =>
      artifact.artifactType === "session_result" &&
      allowedAreas.has(artifact.area)
  ).length;
  if (entry.slug === "development" && workItemCount > 0 && sessionResultCount > 0) {
    return "dogfooded";
  }
  if (workItemCount > 0 || sessionResultCount > 0) return "operational";
  if (sourceCount > 0) return "seeded";
  if (entry.activeWorkflowBlueprintRefs.length > 0) return "stub";
  return "not_started";
}

function buildAreaBlueprintRegistry(
  data: ReturnType<typeof listAll>
): AreaBlueprintRegistry {
  const generatedAt = now();
  const entries: AreaBlueprintEntry[] = AREA_BLUEPRINT_REGISTRY_BASE.map((base) => {
    const readiness = deriveAreaReadiness(base, data);
    const isPrimary = base.slug === COMPANY_OPERATING_MAP_PRIMARY;
    return { ...base, isPrimary, readiness };
  });
  const totals = {
    entryCount: entries.length,
    operationalCount: entries.filter((entry) => entry.readiness === "operational").length,
    dogfoodedCount: entries.filter((entry) => entry.readiness === "dogfooded").length,
    seededCount: entries.filter((entry) => entry.readiness === "seeded").length,
    stubCount: entries.filter((entry) => entry.readiness === "stub").length,
    notStartedCount: entries.filter((entry) => entry.readiness === "not_started").length,
    eligibleForCommandRouterCount: entries.filter((entry) => entry.eligibleForCommandRouter)
      .length,
    eligibleForGoalDecompositionCount: entries.filter(
      (entry) => entry.eligibleForGoalDecomposition
    ).length,
    eligibleForAgentRunEvaluationCount: entries.filter(
      (entry) => entry.eligibleForAgentRunEvaluation
    ).length,
  };
  return {
    generatedAt,
    primaryAreaSlug: COMPANY_OPERATING_MAP_PRIMARY,
    entries,
    totals,
  };
}

app.get("/area-blueprints", (c) => {
  const data = buildAreaBlueprintRegistry(listAll());
  return c.json({ data });
});

const WORKFLOW_DEFAULT_CONFIG: WorkflowDefinitionConfig = {
  tracker: {
    kind: "github",
    repo: "antonio-mello-ai/crewdock",
    activeMilestone: "AIOS Agent Execution v1",
    activeStates: ["open"],
    terminalStates: ["closed"],
    apiKeyEnvRef: "GITHUB_TOKEN",
  },
  polling: { intervalMs: 60000 },
  workspace: {
    root: "~/.aios/agent-workspaces",
    vcs: "git_worktree",
    baseBranch: "main",
  },
  agent: {
    command: "claude",
    args: ["-p"],
    maxConcurrentAgents: 1,
    maxTurns: 20,
    maxRetryBackoffMs: 300000,
  },
  codex: {
    approvalPolicy: "aios_writeback_policy",
    stallTimeoutMs: 300000,
    turnTimeoutMs: 3600000,
    readTimeoutMs: 5000,
  },
  hooks: {
    afterCreate: null,
    beforeRun: null,
    afterRun: null,
    beforeRemove: null,
    timeoutMs: 60000,
  },
};

function unquoteYamlString(raw: string): string {
  const trimmed = raw.trim();
  if (
    (trimmed.startsWith('"') && trimmed.endsWith('"')) ||
    (trimmed.startsWith("'") && trimmed.endsWith("'"))
  ) {
    return trimmed.slice(1, -1);
  }
  return trimmed;
}

function parseYamlScalar(raw: string): unknown {
  const trimmed = raw.trim();
  if (trimmed === "" || trimmed === "null" || trimmed === "~") return null;
  if (trimmed === "true") return true;
  if (trimmed === "false") return false;
  if (/^-?\d+$/.test(trimmed)) return Number.parseInt(trimmed, 10);
  if (/^-?\d+\.\d+$/.test(trimmed)) return Number.parseFloat(trimmed);
  if (trimmed.startsWith("[") && trimmed.endsWith("]")) {
    const inner = trimmed.slice(1, -1).trim();
    if (!inner) return [];
    return inner.split(",").map((part) => unquoteYamlString(part));
  }
  return unquoteYamlString(trimmed);
}

interface YamlLine {
  indent: number;
  content: string;
}

function parseYamlMinimal(text: string): Record<string, unknown> {
  const lines: YamlLine[] = text
    .replace(/\r\n/g, "\n")
    .split("\n")
    .filter((line) => !/^\s*#/.test(line) && line.trim() !== "")
    .map((line) => ({
      indent: line.match(/^\s*/)?.[0].length ?? 0,
      content: line,
    }));

  let cursor = 0;

  function parseBlock(parentIndent: number): Record<string, unknown> {
    const result: Record<string, unknown> = {};
    while (cursor < lines.length) {
      const line = lines[cursor];
      if (line.indent <= parentIndent) break;
      const stripped = line.content.trim();
      const keyMatch = stripped.match(/^([A-Za-z_][A-Za-z0-9_]*)\s*:\s*(.*)$/);
      if (!keyMatch) {
        cursor += 1;
        continue;
      }
      const key = keyMatch[1];
      const valuePart = keyMatch[2];
      cursor += 1;
      if (valuePart === "|" || valuePart === ">") {
        const literal = valuePart === "|";
        const buffer: string[] = [];
        const blockIndent = lines[cursor]?.indent ?? line.indent + 2;
        while (cursor < lines.length && lines[cursor].indent >= blockIndent) {
          const slice = lines[cursor].content.slice(blockIndent);
          buffer.push(slice);
          cursor += 1;
        }
        result[key] = literal ? buffer.join("\n") : buffer.join(" ").trim();
        continue;
      }
      if (valuePart === "") {
        if (cursor < lines.length && lines[cursor].indent > line.indent) {
          if (lines[cursor].content.trim().startsWith("-")) {
            const list: unknown[] = [];
            const itemIndent = lines[cursor].indent;
            while (cursor < lines.length && lines[cursor].indent === itemIndent) {
              const item = lines[cursor].content.trim();
              if (item.startsWith("- ")) list.push(parseYamlScalar(item.slice(2)));
              else if (item === "-") list.push(null);
              else break;
              cursor += 1;
            }
            result[key] = list;
          } else {
            result[key] = parseBlock(line.indent);
          }
        } else {
          result[key] = null;
        }
      } else {
        result[key] = parseYamlScalar(valuePart);
      }
    }
    return result;
  }

  cursor = 0;
  return parseBlock(-1);
}

function asString(value: unknown, fallback = ""): string {
  if (typeof value === "string") return value;
  if (value === null || value === undefined) return fallback;
  return String(value);
}

function asNumber(value: unknown, fallback: number): number {
  if (typeof value === "number" && Number.isFinite(value)) return value;
  if (typeof value === "string" && /^-?\d+(\.\d+)?$/.test(value.trim())) {
    return Number.parseFloat(value);
  }
  return fallback;
}

function asStringArray(value: unknown, fallback: string[]): string[] {
  if (Array.isArray(value)) {
    return value.filter((item): item is string => typeof item === "string");
  }
  return fallback;
}

function agentRunLaunchMetadata(
  agentRun: Pick<typeof cbAgentRuns.$inferSelect, "metadata">
): { command: string | null; args: string[] | null; runnerProfileId: string | null } {
  const metadata =
    agentRun.metadata && typeof agentRun.metadata === "object"
      ? (agentRun.metadata as Record<string, unknown>)
      : {};
  const command = asNullableString(metadata.command);
  const args = Array.isArray(metadata.args)
    ? metadata.args.filter((item): item is string => typeof item === "string")
    : null;
  return {
    command,
    args,
    runnerProfileId: asNullableString(metadata.runnerProfileId),
  };
}

function resolveAgentRunExecutionPlan(args: {
  agentRun: typeof cbAgentRuns.$inferSelect;
  workflow: WorkflowDefinition;
  request: Pick<ExecuteAgentRunRequest, "commandOverride" | "argsOverride">;
}): { command: string; args: string[]; commandSource: string; argsSource: string } {
  const metadata = agentRunLaunchMetadata(args.agentRun);
  const commandOverride = args.request.commandOverride?.trim();
  const command = commandOverride || metadata.command || args.workflow.config.agent.command;
  const commandSource = commandOverride
    ? "request.commandOverride"
    : metadata.command
      ? "agentRun.metadata.command"
      : "workflow.agent.command";
  const rawArgs = Array.isArray(args.request.argsOverride)
    ? args.request.argsOverride
    : metadata.args !== null
      ? metadata.args
      : args.workflow.config.agent.args;
  const argsSource = Array.isArray(args.request.argsOverride)
    ? "request.argsOverride"
    : metadata.args !== null
      ? "agentRun.metadata.args"
      : "workflow.agent.args";
  return { command, args: rawArgs, commandSource, argsSource };
}

function asNullableString(value: unknown): string | null {
  if (typeof value === "string" && value.trim() !== "") return value;
  return null;
}

function buildWorkflowDefinitionFromRaw(
  raw: string,
  filePath: string | null,
  source: WorkflowDefinition["source"]
): WorkflowDefinition {
  const generatedAt = now();
  const errors: string[] = [];
  const warnings: string[] = [];
  let promptTemplate = "";
  let frontMatter: Record<string, unknown> = {};
  const trimmed = raw.replace(/\r\n/g, "\n");
  if (trimmed.trim().length === 0) {
    return {
      generatedAt,
      source,
      filePath,
      raw,
      config: WORKFLOW_DEFAULT_CONFIG,
      promptTemplate: "",
      errors: ["empty workflow content"],
      warnings: [],
      isValid: false,
      branchSuggestionPattern: "<aios-issue-key>-<short-slug>",
      workspacePathPattern: "<workspace.root>/<repo>/<work-item-key>",
    };
  }
  if (trimmed.startsWith("---")) {
    const closingIndex = trimmed.indexOf("\n---", 3);
    if (closingIndex === -1) {
      errors.push("front matter is not closed by a trailing --- line");
    } else {
      const yamlBlock = trimmed.slice(3, closingIndex).replace(/^\n/, "");
      promptTemplate = trimmed.slice(closingIndex + 4).replace(/^\n/, "").trim();
      try {
        const parsed = parseYamlMinimal(yamlBlock);
        if (parsed && typeof parsed === "object") {
          frontMatter = parsed as Record<string, unknown>;
        } else {
          errors.push("front matter did not decode into a map");
        }
      } catch (err) {
        errors.push(
          `front matter parse error: ${err instanceof Error ? err.message : String(err)}`
        );
      }
    }
  } else {
    warnings.push("no YAML front matter found; using defaults");
    promptTemplate = trimmed.trim();
  }

  const trackerObj = (frontMatter.tracker ?? {}) as Record<string, unknown>;
  const pollingObj = (frontMatter.polling ?? {}) as Record<string, unknown>;
  const workspaceObj = (frontMatter.workspace ?? {}) as Record<string, unknown>;
  const agentObj = (frontMatter.agent ?? {}) as Record<string, unknown>;
  const codexObj = (frontMatter.codex ?? {}) as Record<string, unknown>;
  const hooksObj = (frontMatter.hooks ?? {}) as Record<string, unknown>;

  const trackerKindRaw = asString(trackerObj.kind, WORKFLOW_DEFAULT_CONFIG.tracker.kind);
  const trackerKind = (
    ["github", "linear", "jira", "manual"].includes(trackerKindRaw)
      ? trackerKindRaw
      : "github"
  ) as WorkflowDefinitionConfig["tracker"]["kind"];
  if (trackerKindRaw !== trackerKind) {
    warnings.push(
      `tracker.kind=${trackerKindRaw} not recognized; falling back to github`
    );
  }
  if (trackerKind === "linear" || trackerKind === "jira") {
    warnings.push(
      `tracker.kind=${trackerKind} reserved for future adapter; v0 only ships github support`
    );
  }
  const repo = asNullableString(trackerObj.repo);
  if (!repo) {
    errors.push("tracker.repo is required for tracker.kind=github in v0");
  }

  const config: WorkflowDefinitionConfig = {
    tracker: {
      kind: trackerKind,
      repo,
      activeMilestone: asNullableString(
        (trackerObj.active_milestone as unknown) ?? trackerObj.activeMilestone
      ),
      activeStates: asStringArray(
        (trackerObj.active_states as unknown) ?? trackerObj.activeStates,
        WORKFLOW_DEFAULT_CONFIG.tracker.activeStates
      ),
      terminalStates: asStringArray(
        (trackerObj.terminal_states as unknown) ?? trackerObj.terminalStates,
        WORKFLOW_DEFAULT_CONFIG.tracker.terminalStates
      ),
      apiKeyEnvRef: asNullableString(
        (trackerObj.api_key_env as unknown) ??
          trackerObj.apiKeyEnvRef ??
          WORKFLOW_DEFAULT_CONFIG.tracker.apiKeyEnvRef
      ),
    },
    polling: {
      intervalMs: asNumber(
        (pollingObj.interval_ms as unknown) ?? pollingObj.intervalMs,
        WORKFLOW_DEFAULT_CONFIG.polling.intervalMs
      ),
    },
    workspace: {
      root: asString(workspaceObj.root, WORKFLOW_DEFAULT_CONFIG.workspace.root),
      vcs: ((): WorkflowDefinitionConfig["workspace"]["vcs"] => {
        const raw = asString(workspaceObj.vcs, WORKFLOW_DEFAULT_CONFIG.workspace.vcs);
        if (raw === "git_worktree" || raw === "git_clone" || raw === "none") return raw;
        warnings.push(`workspace.vcs=${raw} not recognized; defaulting to git_worktree`);
        return "git_worktree";
      })(),
      baseBranch: asString(
        (workspaceObj.base_branch as unknown) ?? workspaceObj.baseBranch,
        WORKFLOW_DEFAULT_CONFIG.workspace.baseBranch
      ),
    },
    agent: {
      command: asString(agentObj.command, WORKFLOW_DEFAULT_CONFIG.agent.command),
      args: asStringArray(agentObj.args, WORKFLOW_DEFAULT_CONFIG.agent.args),
      maxConcurrentAgents: asNumber(
        (agentObj.max_concurrent_agents as unknown) ?? agentObj.maxConcurrentAgents,
        WORKFLOW_DEFAULT_CONFIG.agent.maxConcurrentAgents
      ),
      maxTurns: asNumber(
        (agentObj.max_turns as unknown) ?? agentObj.maxTurns,
        WORKFLOW_DEFAULT_CONFIG.agent.maxTurns
      ),
      maxRetryBackoffMs: asNumber(
        (agentObj.max_retry_backoff_ms as unknown) ?? agentObj.maxRetryBackoffMs,
        WORKFLOW_DEFAULT_CONFIG.agent.maxRetryBackoffMs
      ),
    },
    codex: {
      approvalPolicy: asString(
        (codexObj.approval_policy as unknown) ?? codexObj.approvalPolicy,
        WORKFLOW_DEFAULT_CONFIG.codex.approvalPolicy
      ),
      stallTimeoutMs: asNumber(
        (codexObj.stall_timeout_ms as unknown) ?? codexObj.stallTimeoutMs,
        WORKFLOW_DEFAULT_CONFIG.codex.stallTimeoutMs
      ),
      turnTimeoutMs: asNumber(
        (codexObj.turn_timeout_ms as unknown) ?? codexObj.turnTimeoutMs,
        WORKFLOW_DEFAULT_CONFIG.codex.turnTimeoutMs
      ),
      readTimeoutMs: asNumber(
        (codexObj.read_timeout_ms as unknown) ?? codexObj.readTimeoutMs,
        WORKFLOW_DEFAULT_CONFIG.codex.readTimeoutMs
      ),
    },
    hooks: {
      afterCreate: asNullableString(
        (hooksObj.after_create as unknown) ?? hooksObj.afterCreate
      ),
      beforeRun: asNullableString(
        (hooksObj.before_run as unknown) ?? hooksObj.beforeRun
      ),
      afterRun: asNullableString(
        (hooksObj.after_run as unknown) ?? hooksObj.afterRun
      ),
      beforeRemove: asNullableString(
        (hooksObj.before_remove as unknown) ?? hooksObj.beforeRemove
      ),
      timeoutMs: asNumber(
        (hooksObj.timeout_ms as unknown) ?? hooksObj.timeoutMs,
        WORKFLOW_DEFAULT_CONFIG.hooks.timeoutMs
      ),
    },
  };

  if (config.agent.maxConcurrentAgents <= 0) {
    errors.push("agent.max_concurrent_agents must be >= 1");
  }
  if (config.agent.maxTurns <= 0) {
    errors.push("agent.max_turns must be >= 1");
  }
  if (config.polling.intervalMs <= 0) {
    errors.push("polling.interval_ms must be > 0");
  }
  if (config.codex.turnTimeoutMs <= 0) {
    warnings.push("codex.turn_timeout_ms <= 0; turns will not time out");
  }
  if (!config.workspace.baseBranch.trim()) {
    errors.push("workspace.base_branch must be a non-empty string");
  }
  if (!promptTemplate.trim()) {
    warnings.push("prompt template body is empty; agent will receive a minimal default prompt");
  }

  return {
    generatedAt,
    source,
    filePath,
    raw,
    config,
    promptTemplate,
    errors,
    warnings,
    isValid: errors.length === 0,
    branchSuggestionPattern: "aios-<work-item-key>-<short-slug>",
    workspacePathPattern: "<workspace.root>/<repo>/<sanitized-work-item-key>",
  };
}

function loadWorkflowFromRepoRoot(): WorkflowDefinition {
  const candidates = [
    resolve(process.cwd(), "WORKFLOW.md"),
    resolve(process.cwd(), "../WORKFLOW.md"),
    resolve(process.cwd(), "../../WORKFLOW.md"),
    resolve(process.cwd(), "../../../WORKFLOW.md"),
  ];
  for (const candidate of candidates) {
    if (existsSync(candidate)) {
      const raw = readFileSync(candidate, "utf-8");
      return buildWorkflowDefinitionFromRaw(raw, candidate, "repo_workflow_md");
    }
  }
  return buildWorkflowDefinitionFromRaw(
    "---\n---\n",
    null,
    "default"
  );
}

app.get("/workflow-loader", (c) => {
  const data = loadWorkflowFromRepoRoot();
  return c.json({ data });
});

app.post("/workflow-loader/preview", async (c) => {
  const body = (await c.req
    .json<PreviewWorkflowLoaderRequest>()
    .catch(() => ({}))) as PreviewWorkflowLoaderRequest;
  if (body.rawContent !== undefined) {
    const data = buildWorkflowDefinitionFromRaw(body.rawContent, null, "inline");
    return c.json({ data });
  }
  if (body.filePath) {
    if (!existsSync(body.filePath)) {
      return c.json(
        {
          error: "not_found",
          message: `workflow file not found at ${body.filePath}`,
        },
        404
      );
    }
    const raw = readFileSync(body.filePath, "utf-8");
    const data = buildWorkflowDefinitionFromRaw(raw, body.filePath, "repo_workflow_md");
    return c.json({ data });
  }
  const data = loadWorkflowFromRepoRoot();
  return c.json({ data });
});

const AGENT_RUN_STATUS_VALUES: AgentRunStatus[] = [
  "queued",
  "claimed",
  "running",
  "retrying",
  "blocked",
  "pr_opened",
  "needs_review",
  "completed",
  "failed",
  "cancelled",
];

const AGENT_RUN_CLAIM_STATE_VALUES: AgentRunClaimState[] = [
  "unclaimed",
  "claimed",
  "running",
  "retry_queued",
  "released",
];

const AGENT_RUN_RUNNER_TYPE_VALUES: AgentRunRunnerType[] = [
  "claude_code",
  "codex",
  "symphony",
  "manual",
  "other",
];

const AGENT_RUN_TERMINAL_STATUSES: AgentRunStatus[] = [
  "completed",
  "failed",
  "cancelled",
];

const AGENT_RUN_STATUS_TRANSITIONS: Record<AgentRunStatus, AgentRunStatus[]> = {
  queued: ["claimed", "cancelled"],
  claimed: ["running", "blocked", "cancelled"],
  running: [
    "pr_opened",
    "needs_review",
    "completed",
    "failed",
    "retrying",
    "blocked",
    "cancelled",
  ],
  retrying: ["running", "cancelled", "failed"],
  blocked: ["running", "cancelled", "failed"],
  pr_opened: ["needs_review", "completed", "failed", "cancelled"],
  needs_review: ["completed", "failed", "cancelled"],
  completed: [],
  failed: [],
  cancelled: [],
};

const AGENT_RUN_STATUS_TO_CLAIM: Record<AgentRunStatus, AgentRunClaimState> = {
  queued: "unclaimed",
  claimed: "claimed",
  running: "running",
  retrying: "retry_queued",
  blocked: "claimed",
  pr_opened: "running",
  needs_review: "running",
  completed: "released",
  failed: "released",
  cancelled: "released",
};

function isValidAgentRunStatus(value: unknown): value is AgentRunStatus {
  return typeof value === "string" && (AGENT_RUN_STATUS_VALUES as string[]).includes(value);
}

function isValidAgentRunClaimState(value: unknown): value is AgentRunClaimState {
  return (
    typeof value === "string" &&
    (AGENT_RUN_CLAIM_STATE_VALUES as string[]).includes(value)
  );
}

function isValidAgentRunRunnerType(value: unknown): value is AgentRunRunnerType {
  return (
    typeof value === "string" &&
    (AGENT_RUN_RUNNER_TYPE_VALUES as string[]).includes(value)
  );
}

function validateAgentRunStatusTransition(
  from: AgentRunStatus,
  to: AgentRunStatus
): { allowed: boolean; reason: string | null } {
  if (from === to) return { allowed: true, reason: null };
  const allowedNext = AGENT_RUN_STATUS_TRANSITIONS[from] ?? [];
  if (!allowedNext.includes(to)) {
    return {
      allowed: false,
      reason: `transition ${from} -> ${to} not allowed; valid next states: ${allowedNext.join(", ") || "(terminal)"}`,
    };
  }
  return { allowed: true, reason: null };
}

function appendAgentRunAuditEntry(
  trail: AgentRun["auditTrail"],
  entry: { actor?: string | null; event: string; note?: string | null; metadata?: Record<string, unknown> | null; at?: number }
): AgentRun["auditTrail"] {
  const at = entry.at ?? now();
  return [
    ...(trail ?? []),
    {
      at,
      actor: entry.actor ?? null,
      event: entry.event,
      note: entry.note ?? null,
      metadata: entry.metadata ?? null,
    },
  ];
}

function rowToAgentRun(row: typeof cbAgentRuns.$inferSelect): AgentRun {
  return {
    id: row.id,
    workItemId: row.workItemId ?? null,
    workflowRunId: row.workflowRunId ?? null,
    agentContextId: row.agentContextId ?? null,
    sourceId: row.sourceId ?? null,
    repo: row.repo ?? null,
    branch: row.branch ?? null,
    workspaceRef: row.workspaceRef ?? null,
    runnerType: row.runnerType,
    status: row.status,
    claimState: row.claimState,
    attempt: row.attempt ?? 0,
    startedAt: row.startedAt ?? null,
    finishedAt: row.finishedAt ?? null,
    errorSummary: row.errorSummary ?? null,
    prUrl: row.prUrl ?? null,
    externalRunRef: row.externalRunRef ?? null,
    tokensInput: row.tokensInput ?? null,
    tokensOutput: row.tokensOutput ?? null,
    tokensTotal: row.tokensTotal ?? null,
    costUsd: row.costUsd ?? null,
    agentSessionId: row.agentSessionId ?? null,
    agentThreadId: row.agentThreadId ?? null,
    area: row.area,
    riskClass: row.riskClass,
    actionPolicy: row.actionPolicy,
    visibility: row.visibility,
    pid: row.pid ?? null,
    executionRef: row.executionRef ?? null,
    lastLogAt: row.lastLogAt ?? null,
    lastLogLineCount: row.lastLogLineCount ?? null,
    metadata: (row.metadata as Record<string, unknown> | null) ?? null,
    auditTrail: row.auditTrail ?? [],
    provenance: (row.provenance as Provenance | null) ?? null,
    createdAt: row.createdAt,
    updatedAt: row.updatedAt,
  };
}

function buildAgentRunSummary(
  data: ReturnType<typeof listAll>
): AgentRunSummary {
  const generatedAt = now();
  const runs = (data.agentRuns as Array<typeof cbAgentRuns.$inferSelect>).map(
    rowToAgentRun
  );
  const byStatus: Record<AgentRunStatus, number> = {
    queued: 0,
    claimed: 0,
    running: 0,
    retrying: 0,
    blocked: 0,
    pr_opened: 0,
    needs_review: 0,
    completed: 0,
    failed: 0,
    cancelled: 0,
  };
  const byClaimState: Record<AgentRunClaimState, number> = {
    unclaimed: 0,
    claimed: 0,
    running: 0,
    retry_queued: 0,
    released: 0,
  };
  const byRunnerType: Record<string, number> = {};
  for (const run of runs) {
    byStatus[run.status] = (byStatus[run.status] ?? 0) + 1;
    byClaimState[run.claimState] = (byClaimState[run.claimState] ?? 0) + 1;
    byRunnerType[run.runnerType] = (byRunnerType[run.runnerType] ?? 0) + 1;
  }
  const horizonDay = generatedAt - 24 * 60 * 60 * 1000;
  const recentCompletedCount = runs.filter(
    (run) => run.status === "completed" && (run.finishedAt ?? run.updatedAt) >= horizonDay
  ).length;
  const staleHorizon = generatedAt - 60 * 60 * 1000;
  const staleCount = runs.filter(
    (run) => run.status === "running" && run.updatedAt < staleHorizon
  ).length;
  return {
    generatedAt,
    totalCount: runs.length,
    byStatus,
    byClaimState,
    byRunnerType,
    blockedCount: byStatus.blocked,
    failedCount: byStatus.failed,
    prOpenedCount: byStatus.pr_opened,
    needsReviewCount: byStatus.needs_review,
    retryingCount: byStatus.retrying,
    recentCompletedCount,
    staleCount,
    recentRuns: runs.slice(0, 10),
  };
}

app.get("/agent-runs", (c) => {
  const url = new URL(c.req.url);
  const limitRaw = Number(url.searchParams.get("limit") ?? "50");
  const limit = Math.max(1, Math.min(200, Number.isFinite(limitRaw) ? limitRaw : 50));
  const statusParam = url.searchParams.get("status");
  const workItemId = url.searchParams.get("workItemId");
  const runnerTypeParam = url.searchParams.get("runnerType");
  const repo = url.searchParams.get("repo");
  const status = isValidAgentRunStatus(statusParam) ? statusParam : null;
  const runnerType = isValidAgentRunRunnerType(runnerTypeParam)
    ? (runnerTypeParam as AgentRunRunnerType)
    : null;
  const data = listAll();
  let runs = (data.agentRuns as Array<typeof cbAgentRuns.$inferSelect>).map(
    rowToAgentRun
  );
  if (status) runs = runs.filter((run) => run.status === status);
  if (workItemId) runs = runs.filter((run) => run.workItemId === workItemId);
  if (runnerType) runs = runs.filter((run) => run.runnerType === runnerType);
  if (repo) runs = runs.filter((run) => run.repo === repo);
  const total = runs.length;
  const items = runs.slice(0, limit);
  const response: AgentRunListResponse = {
    generatedAt: now(),
    total,
    filters: {
      status,
      workItemId: workItemId ?? null,
      runnerType,
      repo: repo ?? null,
      limit,
    },
    items,
  };
  return c.json({ data: response });
});

app.get("/agent-runs/summary", (c) => {
  const data = buildAgentRunSummary(listAll());
  return c.json({ data });
});

app.get("/agent-runs/:id", (c) => {
  const db = getDb();
  const id = c.req.param("id");
  const row = db
    .select()
    .from(cbAgentRuns)
    .where(eq(cbAgentRuns.id, id))
    .get() as typeof cbAgentRuns.$inferSelect | undefined;
  if (!row) {
    return c.json({ error: "not_found", message: "agent run not found" }, 404);
  }
  return c.json({ data: rowToAgentRun(row) });
});

app.post("/agent-runs", async (c) => {
  try {
    const db = getDb();
    const body = (await c.req
      .json<CreateAgentRunRequest>()
      .catch(() => ({}))) as CreateAgentRunRequest;
    const status: AgentRunStatus = body.status ?? "queued";
    if (!isValidAgentRunStatus(status)) {
      return c.json({ error: "validation", message: "invalid status" }, 400);
    }
    const claimState: AgentRunClaimState =
      body.claimState ?? AGENT_RUN_STATUS_TO_CLAIM[status];
    if (!isValidAgentRunClaimState(claimState)) {
      return c.json({ error: "validation", message: "invalid claimState" }, 400);
    }
    const runnerType: AgentRunRunnerType = body.runnerType ?? "manual";
    if (!isValidAgentRunRunnerType(runnerType)) {
      return c.json({ error: "validation", message: "invalid runnerType" }, 400);
    }
    const timestamp = now();
    const id = nanoid(12);
    const auditTrail = appendAgentRunAuditEntry([], {
      actor: body.actor ?? null,
      event: "agent_run_created",
      note: body.rationale ?? null,
      metadata: { status, claimState, runnerType },
      at: timestamp,
    });
    const row = {
      id,
      workItemId: body.workItemId ?? null,
      workflowRunId: body.workflowRunId ?? null,
      agentContextId: body.agentContextId ?? null,
      sourceId: body.sourceId ?? null,
      repo: body.repo ?? null,
      branch: body.branch ?? null,
      workspaceRef: body.workspaceRef ?? null,
      runnerType,
      status,
      claimState,
      attempt: body.attempt ?? 0,
      startedAt: status === "queued" ? null : timestamp,
      finishedAt: AGENT_RUN_TERMINAL_STATUSES.includes(status) ? timestamp : null,
      errorSummary: null,
      prUrl: body.prUrl ?? null,
      externalRunRef: body.externalRunRef ?? null,
      tokensInput: null,
      tokensOutput: null,
      tokensTotal: null,
      costUsd: null,
      agentSessionId: body.agentSessionId ?? null,
      agentThreadId: body.agentThreadId ?? null,
      area: (body.area ?? "development") as CompanyBrainArea,
      riskClass: (body.riskClass ?? "B") as RiskClass,
      actionPolicy: (body.actionPolicy ?? "observe_only") as ActionPolicy,
      visibility: (body.visibility ?? "internal") as Visibility,
      metadata: body.metadata ?? null,
      auditTrail,
      provenance: {
        createdFrom: "company_brain:agent_run_create",
        confidence: 1,
        extractedAt: timestamp,
        humanReviewStatus: "pending" as const,
        visibility: (body.visibility ?? "internal") as Visibility,
        notes: `runnerType=${runnerType}; status=${status}; claim=${claimState}`,
      } as Provenance,
      createdAt: timestamp,
      updatedAt: timestamp,
    };
    db.insert(cbAgentRuns).values(row as never).run();
    return c.json({ data: rowToAgentRun(row as typeof cbAgentRuns.$inferSelect) });
  } catch (err) {
    const message = err instanceof Error ? err.message : "Unknown error";
    return c.json({ error: "agent_run_create_failed", message }, 400);
  }
});

function workspaceAllowlist(): string[] {
  const raw = process.env.AIOS_AGENT_WORKSPACE_ALLOWLIST ?? "";
  return raw
    .split(/[\s,;]+/)
    .map((value) => value.trim())
    .filter((value) => value.length > 0);
}

function workspaceWritesEnabled(): boolean {
  return process.env.AIOS_AGENT_WORKSPACE_ENABLED === "true";
}

function expandHome(input: string): string {
  if (input.startsWith("~/")) return resolve(homedir(), input.slice(2));
  if (input === "~") return homedir();
  return input;
}

function sanitizeWorkspaceKey(input: string): string {
  return input.replace(/[^A-Za-z0-9._-]/g, "_");
}

function normalizeGitHubRepoName(input: string | null | undefined): string | null {
  if (!input) return null;
  const normalized = input
    .trim()
    .replace(/^git@github.com:/, "")
    .replace(/^https:\/\/(?:[^@/]+@)?github.com\//, "")
    .replace(/^https:\/\/x-access-token:[^@/]+@github.com\//, "")
    .replace(/\/issues\/?$/, "")
    .replace(/\.git$/, "");
  const [owner, name] = normalized.split("/");
  if (!owner || !name) return null;
  return `${owner}/${name}`;
}

function deriveRunSuffix(runId: string | null | undefined): string {
  if (!runId) return "";
  return runId.slice(0, 8).toLowerCase().replace(/[^a-z0-9]/g, "");
}

function deriveBranchName(
  workItemKey: string,
  runId?: string | null,
  override?: string | null
): string {
  if (override && override.trim()) return override.trim();
  const base = `aios-${sanitizeWorkspaceKey(workItemKey).toLowerCase()}`;
  const suffix = deriveRunSuffix(runId);
  return suffix ? `${base}-${suffix}` : base;
}

function resolveWorkspaceLocation(args: {
  repo: string;
  workItemKey: string;
  runId?: string | null;
  rootOverride?: string;
  baseBranch?: string;
  branchOverride?: string;
  vcs?: WorkspaceLocation["vcs"];
}): { location: WorkspaceLocation; safetyError: string | null } {
  const definition = loadWorkflowFromRepoRoot();
  const root = expandHome(args.rootOverride ?? definition.config.workspace.root);
  const baseBranch = args.baseBranch ?? definition.config.workspace.baseBranch;
  const vcs = args.vcs ?? definition.config.workspace.vcs;
  const repoSlug = sanitizeWorkspaceKey(args.repo);
  const workItemKeySanitized = sanitizeWorkspaceKey(args.workItemKey);
  const runSuffix = deriveRunSuffix(args.runId);
  const workspaceKey = runSuffix
    ? `${workItemKeySanitized}-${runSuffix}`
    : workItemKeySanitized;
  const workspacePath = resolve(root, repoSlug, workspaceKey);
  const branchName = deriveBranchName(args.workItemKey, args.runId, args.branchOverride);
  const rootAbs = resolve(root);
  const relativePath = relative(rootAbs, workspacePath);
  if (relativePath.startsWith("..") || relativePath.includes("\0")) {
    return {
      location: {
        workspaceRoot: rootAbs,
        workspacePath,
        workspaceKey,
        repoSlug,
        branchName,
        baseBranch,
        vcs,
      },
      safetyError: "computed workspace path escapes workspace root",
    };
  }
  return {
    location: {
      workspaceRoot: rootAbs,
      workspacePath,
      workspaceKey,
      repoSlug,
      branchName,
      baseBranch,
      vcs,
    },
    safetyError: null,
  };
}

function repoCacheRoot(): string {
  return expandHome(process.env.AIOS_AGENT_REPO_CACHE_ROOT ?? "~/.aios/repo-cache");
}

function gitHubGitAuthArgs(token: string | null): { args: string[]; secret: string | null } {
  if (!token) return { args: [], secret: null };
  const secret = Buffer.from(`x-access-token:${token}`, "utf8").toString("base64");
  return {
    args: [
      "-c",
      `http.https://github.com/.extraheader=AUTHORIZATION: basic ${secret}`,
    ],
    secret,
  };
}

function redactGitSnippet(
  value: string | null | undefined,
  token: string | null,
  authSecret: string | null
): string | null {
  if (!value) return null;
  let redacted = value;
  if (token) redacted = redacted.split(token).join("[REDACTED]");
  if (authSecret) redacted = redacted.split(authSecret).join("[REDACTED]");
  return redacted.trim().slice(0, 500) || null;
}

function currentRepoMatchesTarget(repo: string): boolean {
  const result = spawnSync("git", ["config", "--get", "remote.origin.url"], {
    cwd: process.cwd(),
    encoding: "utf-8",
  });
  if (result.status !== 0) return false;
  return normalizeGitHubRepoName(result.stdout) === repo;
}

function ensureWorkspaceSourceRepo(args: {
  repo: string;
  baseBranch: string;
}): {
  ok: boolean;
  sourcePath: string | null;
  blockReason: string | null;
  rationale: string[];
} {
  const repoName = normalizeGitHubRepoName(args.repo);
  const rationale: string[] = [];
  if (!repoName) {
    return {
      ok: false,
      sourcePath: null,
      blockReason: `repo ${args.repo} is not a valid GitHub owner/name repository`,
      rationale,
    };
  }

  const tokenInfo = githubPrWritebackTokenInfo();
  const auth = gitHubGitAuthArgs(tokenInfo.token);
  const runGit = (
    gitArgs: string[],
    options: { cwd?: string; commandSummary: string }
  ) => {
    const result = spawnSync("git", [...auth.args, ...gitArgs], {
      cwd: options.cwd,
      encoding: "utf-8",
    });
    const output =
      redactGitSnippet(result.stderr, tokenInfo.token, auth.secret) ??
      redactGitSnippet(result.stdout, tokenInfo.token, auth.secret) ??
      null;
    return { result, output, commandSummary: options.commandSummary };
  };

  if (currentRepoMatchesTarget(repoName)) {
    const current = process.cwd();
    rationale.push(
      `Workspace source repo uses daemon checkout because remote.origin matches ${repoName}.`
    );
    const fetch = runGit(["fetch", "origin", args.baseBranch, "--prune"], {
      cwd: current,
      commandSummary: `git fetch origin ${args.baseBranch} --prune`,
    });
    if (fetch.result.status !== 0) {
      return {
        ok: false,
        sourcePath: current,
        blockReason: `${fetch.commandSummary} failed: ${fetch.output ?? "unknown error"}`,
        rationale,
      };
    }
    rationale.push(`Fetched origin/${args.baseBranch} in daemon checkout.`);
    return { ok: true, sourcePath: current, blockReason: null, rationale };
  }

  const cacheRoot = repoCacheRoot();
  const cachePath = resolve(cacheRoot, sanitizeWorkspaceKey(repoName));
  const cloneUrl = `https://github.com/${repoName}.git`;
  mkdirSync(cacheRoot, { recursive: true });

  if (existsSync(cachePath) && !existsSync(resolve(cachePath, ".git"))) {
    return {
      ok: false,
      sourcePath: cachePath,
      blockReason: `repo cache path ${cachePath} exists but is not a git checkout`,
      rationale,
    };
  }

  if (!existsSync(cachePath)) {
    const clone = runGit(
      ["clone", "--no-checkout", "--origin", "origin", cloneUrl, cachePath],
      {
        commandSummary: `git clone --no-checkout ${cloneUrl} ${cachePath}`,
      }
    );
    if (clone.result.status !== 0) {
      return {
        ok: false,
        sourcePath: cachePath,
        blockReason: `${clone.commandSummary} failed: ${clone.output ?? "unknown error"}`,
        rationale,
      };
    }
    rationale.push(`Cloned ${repoName} into repo cache ${cachePath}.`);
  } else {
    rationale.push(`Using cached source repo ${cachePath} for ${repoName}.`);
    const remote = runGit(["remote", "set-url", "origin", cloneUrl], {
      cwd: cachePath,
      commandSummary: `git remote set-url origin ${cloneUrl}`,
    });
    if (remote.result.status !== 0) {
      return {
        ok: false,
        sourcePath: cachePath,
        blockReason: `${remote.commandSummary} failed: ${remote.output ?? "unknown error"}`,
        rationale,
      };
    }
  }

  const fetch = runGit(["fetch", "origin", args.baseBranch, "--prune"], {
    cwd: cachePath,
    commandSummary: `git fetch origin ${args.baseBranch} --prune`,
  });
  if (fetch.result.status !== 0) {
    return {
      ok: false,
      sourcePath: cachePath,
      blockReason: `${fetch.commandSummary} failed: ${fetch.output ?? "unknown error"}`,
      rationale,
    };
  }
  const verify = runGit(["rev-parse", "--verify", `origin/${args.baseBranch}`], {
    cwd: cachePath,
    commandSummary: `git rev-parse --verify origin/${args.baseBranch}`,
  });
  if (verify.result.status !== 0) {
    return {
      ok: false,
      sourcePath: cachePath,
      blockReason: `${verify.commandSummary} failed: ${verify.output ?? "unknown error"}`,
      rationale,
    };
  }
  rationale.push(`Fetched and verified origin/${args.baseBranch} for ${repoName}.`);
  return { ok: true, sourcePath: cachePath, blockReason: null, rationale };
}

function workspaceIsDirty(workspacePath: string): boolean {
  const result = spawnSync(
    "git",
    ["-C", workspacePath, "status", "--porcelain"],
    { encoding: "utf-8" }
  );
  if (result.status !== 0) return false;
  return Boolean(result.stdout && result.stdout.trim().length > 0);
}

function workspaceListed(workspacePath: string): boolean {
  if (!existsSync(workspacePath)) return false;
  const cwd = existsSync(resolve(workspacePath, ".git")) ? workspacePath : process.cwd();
  const list = spawnSync("git", ["worktree", "list", "--porcelain"], {
    cwd,
    encoding: "utf-8",
  });
  if (list.status !== 0) return false;
  const stdout = list.stdout ?? "";
  return stdout.split("\n").some((line) => line.startsWith("worktree ") && line.slice(9).trim() === workspacePath);
}

function isInternalAgentRunWorkspacePath(path: string): boolean {
  return path === ".aios-run" || path.startsWith(".aios-run/");
}

function findLatestExecutedPrProposalForWorkItem(workItemId: string | null): ExternalActionProposal | null {
  if (!workItemId) return null;
  const proposals = getDb()
    .select()
    .from(cbExternalActionProposals)
    .all() as ExternalActionProposal[];
  return (
    proposals
      .filter((proposal) => proposal.workItemId === workItemId)
      .filter((proposal) => proposal.actionType === "github_pr_create")
      .filter((proposal) => Boolean(proposal.externalUrl || proposal.externalId))
      .sort((a, b) => b.updatedAt - a.updatedAt)[0] ?? null
  );
}

function latestPatchPacketForWorkItem(workItemId: string | null): AgentRunPatchPacket | null {
  if (!workItemId) return null;
  const artifacts = getDb()
    .select()
    .from(cbArtifacts)
    .orderBy(desc(cbArtifacts.ingestedAt))
    .limit(500)
    .all() as Artifact[];
  for (const artifact of artifacts) {
    const metadata = artifact.metadata as Record<string, unknown> | null;
    if (!metadata || metadata.kind !== "agent_run_patch_packet") continue;
    const packet = metadata.packet as AgentRunPatchPacket | undefined;
    if (packet?.workItemId === workItemId) return packet;
  }
  return null;
}

function buildValidationDelta(args: {
  previous: AgentRunPatchPacket | null;
  current: AgentRunPatchPacketValidation[];
}): AgentRunPatchPacket["validationDelta"] {
  const currentFailedCount = args.current.filter((v) => v.status === "failed").length;
  const previousFailedCount = args.previous
    ? args.previous.validations.filter((v) => v.status === "failed").length
    : null;
  return {
    previousValidationCount: args.previous?.validations.length ?? null,
    currentValidationCount: args.current.length,
    previousFailedCount,
    currentFailedCount,
    failedDelta:
      previousFailedCount === null ? null : currentFailedCount - previousFailedCount,
  };
}

function collectAgentRunPatchPacket(args: {
  agentRun: typeof cbAgentRuns.$inferSelect;
}): AgentRunPatchPacket {
  const generatedAt = now();
  const run = args.agentRun;
  const workspacePath = run.workspaceRef ?? null;
  const branch = run.branch ?? null;
  const workflow = loadWorkflowFromRepoRoot();
  const baseRef = workflow.config.workspace.baseBranch ?? null;
  const logFilePath = (() => {
    if (!workspacePath) return null;
    const candidate = resolve(workspacePath, ".aios-run", `${run.id}.log`);
    return existsSync(candidate) ? candidate : null;
  })();
  const baseLogRefs = {
    logFilePath,
    lastLogAt: run.lastLogAt ?? null,
    lastLogLineCount: run.lastLogLineCount ?? null,
  };
  const previousPrProposal = findLatestExecutedPrProposalForWorkItem(
    run.workItemId ?? null
  );
  const previousPatchPacket = latestPatchPacketForWorkItem(run.workItemId ?? null);

  // Helpers reading metadata.validations populated by session_result intake.
  const validationsFromMetadata = ((): AgentRunPatchPacketValidation[] => {
    const md = run.metadata as Record<string, unknown> | null;
    const raw = md && Array.isArray(md.validations) ? (md.validations as unknown[]) : [];
    const out: AgentRunPatchPacketValidation[] = [];
    for (const v of raw) {
      if (typeof v === "object" && v !== null) {
        const rec = v as Record<string, unknown>;
        const kind = typeof rec.kind === "string" ? rec.kind : "unknown";
        const statusRaw = typeof rec.status === "string" ? rec.status : "skipped";
        const status: AgentRunPatchPacketValidation["status"] =
          statusRaw === "passed" || statusRaw === "failed" || statusRaw === "skipped"
            ? statusRaw
            : "skipped";
        const notes = typeof rec.notes === "string" ? rec.notes : null;
        out.push({ kind, status, notes });
      }
    }
    return out;
  })();
  const buildValidationEvidence = (args: {
    changedFiles: AgentRunPatchPacketChangedFile[];
    diffStat: AgentRunPatchPacket["diffStat"];
    commits: AgentRunPatchPacketCommit[];
  }): AgentRunPatchPacketValidation[] => {
    const validations = [...validationsFromMetadata];
    const seen = new Set(validations.map((item) => `${item.kind}:${item.status}`));
    const addValidation = (
      kind: string,
      status: AgentRunPatchPacketValidation["status"],
      notes: string
    ) => {
      const key = `${kind}:${status}`;
      if (seen.has(key)) return;
      seen.add(key);
      validations.push({ kind, status, notes });
    };
    if (run.status === "completed") {
      addValidation(
        "runner_exit_zero",
        "passed",
        "AgentRun reached terminal status=completed after subprocess execution."
      );
    }
    if (args.changedFiles.length > 0 || args.diffStat.filesChanged > 0) {
      addValidation(
        "patch_content",
        "passed",
        `Patch packet contains ${args.changedFiles.length} changed file entries and diffStat=${args.diffStat.filesChanged} files.`
      );
    }
    if (args.commits.length > 0) {
      addValidation(
        "git_commit",
        "passed",
        `Patch packet contains ${args.commits.length} commit(s) ahead of base.`
      );
    }
    return validations;
  };

  if (!workspacePath) {
    return {
      agentRunId: run.id,
      workItemId: run.workItemId,
      artifactId: null,
      attempt: run.attempt ?? 0,
      previousPrUrl: previousPrProposal?.externalUrl ?? null,
      generatedAt,
      status: "no_workspace",
      workspacePath: null,
      branch,
      baseRef,
      changedFiles: [],
      diffStat: { filesChanged: 0, insertions: 0, deletions: 0 },
      commits: [],
      validations: validationsFromMetadata,
      validationDelta: buildValidationDelta({
        previous: previousPatchPacket,
        current: validationsFromMetadata,
      }),
      logRefs: baseLogRefs,
      errorSummary: "AgentRun has no workspaceRef recorded",
    };
  }

  if (!existsSync(workspacePath)) {
    return {
      agentRunId: run.id,
      workItemId: run.workItemId,
      artifactId: null,
      attempt: run.attempt ?? 0,
      previousPrUrl: previousPrProposal?.externalUrl ?? null,
      generatedAt,
      status: "no_workspace",
      workspacePath,
      branch,
      baseRef,
      changedFiles: [],
      diffStat: { filesChanged: 0, insertions: 0, deletions: 0 },
      commits: [],
      validations: validationsFromMetadata,
      validationDelta: buildValidationDelta({
        previous: previousPatchPacket,
        current: validationsFromMetadata,
      }),
      logRefs: baseLogRefs,
      errorSummary: "Workspace path does not exist",
    };
  }

  // Verify a .git or .git file exists (worktrees use a .git pointer file).
  if (!existsSync(resolve(workspacePath, ".git"))) {
    return {
      agentRunId: run.id,
      workItemId: run.workItemId,
      artifactId: null,
      attempt: run.attempt ?? 0,
      previousPrUrl: previousPrProposal?.externalUrl ?? null,
      generatedAt,
      status: "no_git",
      workspacePath,
      branch,
      baseRef,
      changedFiles: [],
      diffStat: { filesChanged: 0, insertions: 0, deletions: 0 },
      commits: [],
      validations: validationsFromMetadata,
      validationDelta: buildValidationDelta({
        previous: previousPatchPacket,
        current: validationsFromMetadata,
      }),
      logRefs: baseLogRefs,
      errorSummary: "Workspace exists but is not a git checkout (no .git)",
    };
  }

  const errorSummary: string[] = [];

  // git status --porcelain for uncommitted changes. Internal runner logs are
  // ignored because they are evidence storage, not the proposed patch.
  let isDirty = false;
  const changedFiles: AgentRunPatchPacketChangedFile[] = [];
  const changedFileKeys = new Set<string>();
  const addChangedFile = (path: string, status: string) => {
    if (!path || isInternalAgentRunWorkspacePath(path)) return;
    const key = `${status}:${path}`;
    if (changedFileKeys.has(key)) return;
    changedFileKeys.add(key);
    changedFiles.push({ path, status });
  };
  try {
    const st = spawnSync("git", ["-C", workspacePath, "status", "--porcelain"], {
      encoding: "utf-8",
    });
    if (st.status === 0 && st.stdout) {
      const lines = st.stdout.split("\n").filter((l) => l.length > 0);
      for (const line of lines) {
        const status = line.slice(0, 2).trim();
        const path = line.slice(3).trim();
        addChangedFile(path, status);
      }
      isDirty = changedFiles.length > 0;
    } else if (st.status !== 0) {
      errorSummary.push(`git status failed: ${(st.stderr ?? "").trim().slice(0, 200)}`);
    }
  } catch (err) {
    errorSummary.push(
      `git status threw: ${err instanceof Error ? err.message : "unknown"}`
    );
  }

  // Committed changes against base ref. This is what PR review actually sees.
  try {
    if (baseRef) {
      const diffNames = spawnSync(
        "git",
        ["-C", workspacePath, "diff", "--name-status", baseRef + "..HEAD"],
        { encoding: "utf-8" }
      );
      if (diffNames.status === 0 && diffNames.stdout) {
        for (const line of diffNames.stdout.split("\n").filter(Boolean)) {
          const [status, ...pathParts] = line.split(/\s+/);
          const path = pathParts.join(" ").trim();
          addChangedFile(path, status);
        }
      } else if (diffNames.status !== 0) {
        errorSummary.push(
          `git diff --name-status failed: ${(diffNames.stderr ?? "").trim().slice(0, 200)}`
        );
      }
    }
  } catch (err) {
    errorSummary.push(
      `git diff --name-status threw: ${err instanceof Error ? err.message : "unknown"}`
    );
  }

  // git diff --stat (against base ref)
  let diffStat = { filesChanged: 0, insertions: 0, deletions: 0 };
  try {
    const args = baseRef
      ? ["-C", workspacePath, "diff", "--shortstat", baseRef + "..HEAD"]
      : ["-C", workspacePath, "diff", "--shortstat"];
    const ds = spawnSync("git", args, { encoding: "utf-8" });
    if (ds.status === 0 && ds.stdout) {
      // " 2 files changed, 13 insertions(+), 1 deletion(-)"
      const m = ds.stdout.trim();
      const filesMatch = m.match(/(\d+) files? changed/);
      const insMatch = m.match(/(\d+) insertions?\(\+\)/);
      const delMatch = m.match(/(\d+) deletions?\(-\)/);
      diffStat = {
        filesChanged: filesMatch ? Number(filesMatch[1]) : 0,
        insertions: insMatch ? Number(insMatch[1]) : 0,
        deletions: delMatch ? Number(delMatch[1]) : 0,
      };
    }
  } catch (err) {
    errorSummary.push(
      `git diff --shortstat threw: ${err instanceof Error ? err.message : "unknown"}`
    );
  }

  // git log against base ref (commits ahead of base)
  const commits: AgentRunPatchPacketCommit[] = [];
  try {
    const args = baseRef
      ? [
          "-C",
          workspacePath,
          "log",
          baseRef + "..HEAD",
          "--no-merges",
          "--pretty=format:%H%x1f%an%x1f%ae%x1f%at%x1f%s%x1f%b%x1e",
          "-50",
        ]
      : [
          "-C",
          workspacePath,
          "log",
          "-10",
          "--no-merges",
          "--pretty=format:%H%x1f%an%x1f%ae%x1f%at%x1f%s%x1f%b%x1e",
        ];
    const log = spawnSync("git", args, { encoding: "utf-8" });
    if (log.status === 0 && log.stdout) {
      const records = log.stdout.split("\x1e").filter((r) => r.trim().length > 0);
      for (const record of records) {
        const fields = record.trim().split("\x1f");
        if (fields.length >= 5) {
          const sha = fields[0];
          const authorName = fields[1];
          const authorEmail = fields[2];
          const committedAtSec = Number(fields[3]);
          const subject = fields[4];
          const body = fields[5] ?? "";
          commits.push({
            sha,
            authorName,
            authorEmail,
            subject,
            bodySnippet: body.trim().slice(0, 500) || null,
            committedAt: Number.isFinite(committedAtSec)
              ? committedAtSec * 1000
              : null,
          });
        }
      }
    }
  } catch (err) {
    errorSummary.push(
      `git log threw: ${err instanceof Error ? err.message : "unknown"}`
    );
  }

  const validations = buildValidationEvidence({ changedFiles, diffStat, commits });

  return {
    agentRunId: run.id,
    workItemId: run.workItemId,
    artifactId: null,
    attempt: run.attempt ?? 0,
    previousPrUrl: previousPrProposal?.externalUrl ?? null,
    generatedAt,
    status: errorSummary.length > 0 ? "error" : isDirty ? "dirty" : "clean",
    workspacePath,
    branch,
    baseRef,
    changedFiles,
    diffStat,
    commits,
    validations,
    validationDelta: buildValidationDelta({
      previous: previousPatchPacket,
      current: validations,
    }),
    logRefs: baseLogRefs,
    errorSummary: errorSummary.length > 0 ? errorSummary.join("; ") : null,
  };
}

function computeAgentRunPatchPacketSignature(args: {
  agentRun: typeof cbAgentRuns.$inferSelect;
  packet: AgentRunPatchPacket;
  repo?: string | null;
  sourceBranch?: string | null;
  baseBranch?: string | null;
}): string {
  return createHash("sha256")
    .update(
      JSON.stringify({
        agentRunId: args.agentRun.id,
        repo: args.repo ?? args.agentRun.repo ?? null,
        sourceBranch: args.sourceBranch ?? args.packet.branch ?? args.agentRun.branch ?? null,
        baseBranch: args.baseBranch ?? args.packet.baseRef ?? null,
        signatureVersion: 3,
        changedFiles: args.packet.changedFiles,
        commits: args.packet.commits.map((c) => c.sha),
        validations: args.packet.validations.map((v) => ({
          kind: v.kind,
          status: v.status,
          notes: v.notes ?? null,
        })),
      })
    )
    .digest("hex");
}

function findExistingPatchPacketArtifact(args: {
  agentRunId: string;
  packetSignature: string;
}): Artifact | null {
  const rows = getDb()
    .select()
    .from(cbArtifacts)
    .orderBy(desc(cbArtifacts.ingestedAt))
    .limit(500)
    .all() as Artifact[];
  return (
    rows.find((artifact) => {
      const metadata = artifact.metadata as Record<string, unknown> | null;
      if (!metadata || metadata.kind !== "agent_run_patch_packet") return false;
      if (metadata.packetSignature === args.packetSignature) return true;
      const packet = metadata.packet as AgentRunPatchPacket | undefined;
      return (
        packet?.agentRunId === args.agentRunId &&
        metadata.packetSignature === args.packetSignature
      );
    }) ?? null
  );
}

function persistAgentRunPatchPacket(args: {
  packet: AgentRunPatchPacket;
  agentRun: typeof cbAgentRuns.$inferSelect;
  packetSignature?: string;
}): { artifactId: string; reused: boolean; packetSignature: string } {
  const db = getDb();
  const packetSignature =
    args.packetSignature ??
    computeAgentRunPatchPacketSignature({
      agentRun: args.agentRun,
      packet: args.packet,
    });
  const existing = findExistingPatchPacketArtifact({
    agentRunId: args.agentRun.id,
    packetSignature,
  });
  if (existing) {
    args.packet.artifactId = existing.id;
    return { artifactId: existing.id, reused: true, packetSignature };
  }
  const timestamp = args.packet.generatedAt;
  const sourceArea = args.agentRun.area;
  const sourceVisibility = args.agentRun.visibility;
  const sourceId = ensureSessionResultsSource(
    sourceArea,
    sourceVisibility,
    timestamp
  );
  const artifactId = nanoid(12);
  args.packet.artifactId = artifactId;
  const rawRef = `aios://agent-run-patch-packet/${args.agentRun.id}/${timestamp}`;
  const titleParts = [
    `AgentRun ${args.agentRun.id} patch packet`,
    args.packet.status,
    `${args.packet.changedFiles.length} files`,
    `${args.packet.commits.length} commits`,
  ];
  const summary = (() => {
    const lines: string[] = [];
    lines.push(`status=${args.packet.status}`);
    lines.push(`branch=${args.packet.branch ?? "-"}`);
    lines.push(`baseRef=${args.packet.baseRef ?? "-"}`);
    lines.push(
      `diffStat=${args.packet.diffStat.filesChanged}f/${args.packet.diffStat.insertions}+${args.packet.diffStat.deletions}-`
    );
    lines.push(
      `commits=${args.packet.commits
        .map((c) => `${c.sha.slice(0, 7)} ${c.subject.slice(0, 60)}`)
        .join("; ") || "(none)"}`
    );
    if (args.packet.errorSummary) lines.push(`errorSummary=${args.packet.errorSummary}`);
    return lines.join(" | ").slice(0, 800);
  })();
  const artifactRow: Artifact = {
    id: artifactId,
    sourceId,
    artifactType: "session_result",
    area: sourceArea,
    title: titleParts.join(": ").slice(0, 240),
    summary,
    contentRef: null,
    rawRef,
    author: "operating-loop:patch-packet",
    occurredAt: timestamp,
    ingestedAt: timestamp,
    hash: createHash("sha256")
      .update(JSON.stringify({ ...args.packet, generatedAt: null }))
      .digest("hex"),
    visibility: sourceVisibility,
    provenance: {
      sourceId,
      rawRef,
      artifactId,
      createdFrom: "company_brain:agent_run_patch_packet",
      confidence: 1,
      extractedAt: timestamp,
      humanReviewStatus: "pending",
      visibility: sourceVisibility,
      notes: `agentRun=${args.agentRun.id}; status=${args.packet.status}; files=${args.packet.changedFiles.length}; commits=${args.packet.commits.length}`,
    },
    humanReviewStatus: "pending",
    confidence: 1,
    metadata: {
      kind: "agent_run_patch_packet",
      agentRunId: args.agentRun.id,
      packetSignature,
      packet: args.packet,
    },
  };
  db.insert(cbArtifacts).values(artifactRow as never).run();
  return { artifactId, reused: false, packetSignature };
}

function buildWorkspacePreparationResult(args: {
  agentRunId: string | null;
  workItemId: string | null;
  request: PrepareAgentWorkspaceRequest;
  location: WorkspaceLocation;
  status: WorkspacePreparationStatus;
  exists: boolean;
  isDirty: boolean;
  blockReasons: string[];
  rationale: string[];
  dryRun: boolean;
}): WorkspacePreparationResult {
  const definition = loadWorkflowFromRepoRoot();
  const hookSteps = [
    {
      phase: "after_create" as const,
      command: definition.config.hooks.afterCreate,
      willRun: !args.dryRun && args.status === "created",
    },
    {
      phase: "before_run" as const,
      command: definition.config.hooks.beforeRun,
      willRun:
        !args.dryRun &&
        (args.status === "created" || args.status === "reused"),
    },
  ];
  return {
    generatedAt: now(),
    agentRunId: args.agentRunId,
    workItemId: args.workItemId,
    status: args.status,
    dryRun: args.dryRun,
    location: args.location,
    exists: args.exists,
    isDirty: args.isDirty,
    blockReasons: args.blockReasons,
    hookSteps,
    rationale: args.rationale,
  };
}

app.post("/agent-runs/:id/workspace/prepare", async (c) => {
  try {
    const db = getDb();
    const id = c.req.param("id");
    const body = (await c.req
      .json<PrepareAgentWorkspaceRequest>()
      .catch(() => ({}))) as PrepareAgentWorkspaceRequest;
    const dryRun = body.dryRun !== false;
    const existing = db
      .select()
      .from(cbAgentRuns)
      .where(eq(cbAgentRuns.id, id))
      .get() as typeof cbAgentRuns.$inferSelect | undefined;
    if (!existing) {
      return c.json({ error: "not_found", message: "agent run not found" }, 404);
    }
    const repo = body.repo ?? existing.repo;
    if (!repo) {
      return c.json(
        {
          error: "validation",
          message:
            "agent run has no repo and request did not provide one; cannot derive workspace path",
        },
        400
      );
    }
    let workItemKey: string;
    if (existing.workItemId) {
      const workItem = db
        .select()
        .from(cbWorkItems)
        .where(eq(cbWorkItems.id, existing.workItemId))
        .get() as typeof cbWorkItems.$inferSelect | undefined;
      const externalIdMatch = workItem?.externalId?.match(/#(\d+)$/);
      workItemKey = externalIdMatch
        ? `${repo.replace("/", "_")}_${externalIdMatch[1]}`
        : workItem?.externalId ?? existing.workItemId;
    } else {
      workItemKey = existing.id;
    }
    const { location, safetyError } = resolveWorkspaceLocation({
      repo,
      workItemKey,
      runId: existing.id,
      rootOverride: body.workspaceRootOverride,
      baseBranch: body.baseBranch,
      branchOverride: body.branchOverride ?? existing.branch ?? undefined,
    });
    const blockReasons: string[] = [];
    const rationale: string[] = [];
    if (safetyError) blockReasons.push(safetyError);
    rationale.push(
      `Workspace path resolved to ${location.workspacePath} from root ${location.workspaceRoot}.`
    );
    rationale.push(`Branch derived as ${location.branchName} from base ${location.baseBranch}.`);
    const exists = existsSync(location.workspacePath);
    const isDirty = exists && workspaceIsDirty(location.workspacePath);
    const hasGitMetadata = exists && existsSync(resolve(location.workspacePath, ".git"));
    const isRegisteredWorktree = exists && workspaceListed(location.workspacePath);
    const allowlist = workspaceAllowlist();
    if (allowlist.length && !allowlist.includes(repo)) {
      blockReasons.push(
        `repo ${repo} is not in AIOS_AGENT_WORKSPACE_ALLOWLIST; v1 only writes when explicitly allowlisted`
      );
    }
    if (!workspaceWritesEnabled()) {
      rationale.push(
        "AIOS_AGENT_WORKSPACE_ENABLED is not 'true'; defaulting to dry-run preview without filesystem changes."
      );
    }
    let status: WorkspacePreparationStatus;
    if (blockReasons.length) {
      status = blockReasons.some((reason) => reason.includes("escapes workspace root"))
        ? "blocked_invalid_path"
        : blockReasons.some((reason) => reason.includes("AIOS_AGENT_WORKSPACE_ALLOWLIST"))
          ? "blocked_not_allowlisted"
          : "blocked_safety";
    } else if (isDirty) {
      status = "blocked_dirty";
      blockReasons.push(
        "existing workspace has uncommitted changes; refuse to clobber without explicit cleanup"
      );
    } else if (exists && (!hasGitMetadata || !isRegisteredWorktree)) {
      status = "blocked_safety";
      blockReasons.push(
        "existing workspace path is not a registered git worktree; refuse to reuse it without explicit cleanup"
      );
    } else if (exists) {
      status = "reused";
      rationale.push("Workspace directory already exists and is clean; will be reused.");
    } else if (dryRun || !workspaceWritesEnabled()) {
      status = "ready_to_create";
      rationale.push("Dry-run only; no filesystem changes performed.");
    } else {
      try {
        mkdirSync(location.workspaceRoot, { recursive: true });
        mkdirSync(resolve(location.workspaceRoot, location.repoSlug), { recursive: true });
        const sourceRepo = ensureWorkspaceSourceRepo({
          repo,
          baseBranch: location.baseBranch,
        });
        rationale.push(...sourceRepo.rationale);
        if (!sourceRepo.ok || !sourceRepo.sourcePath) {
          status = "failed";
          blockReasons.push(
            sourceRepo.blockReason ?? "could not resolve source repository for workspace"
          );
        } else {
          rationale.push(`Workspace source repo resolved to ${sourceRepo.sourcePath}.`);
          const args = [
            "-C",
            sourceRepo.sourcePath,
            "worktree",
            "add",
            "-b",
            location.branchName,
            location.workspacePath,
            `origin/${location.baseBranch}`,
          ];
          const result = spawnSync("git", args, { encoding: "utf-8" });
          if (result.status !== 0) {
            status = "failed";
            blockReasons.push(
              `git worktree add failed: ${result.stderr?.trim() || result.stdout?.trim() || "unknown error"}`
            );
          } else {
            status = "created";
            rationale.push(`git worktree add succeeded; new branch ${location.branchName}.`);
          }
        }
      } catch (err) {
        status = "failed";
        blockReasons.push(
          `workspace preparation threw: ${err instanceof Error ? err.message : String(err)}`
        );
      }
    }
    const refreshedExists = existsSync(location.workspacePath);
    const refreshedDirty = refreshedExists && workspaceIsDirty(location.workspacePath);

    if (
      (status === "created" || status === "reused") &&
      !dryRun &&
      workspaceWritesEnabled()
    ) {
      const auditTrail = appendAgentRunAuditEntry(existing.auditTrail ?? [], {
        actor: body.actor ?? null,
        event: status === "created" ? "agent_run_workspace_created" : "agent_run_workspace_reused",
        note: body.rationale ?? null,
        metadata: {
          workspacePath: location.workspacePath,
          branchName: location.branchName,
        },
      });
      db.update(cbAgentRuns)
        .set({
          workspaceRef: location.workspacePath,
          branch: location.branchName,
          repo,
          auditTrail,
          updatedAt: now(),
        } as never)
        .where(eq(cbAgentRuns.id, id))
        .run();
    } else if (dryRun || !workspaceWritesEnabled()) {
      const auditTrail = appendAgentRunAuditEntry(existing.auditTrail ?? [], {
        actor: body.actor ?? null,
        event: "agent_run_workspace_preview",
        note: body.rationale ?? null,
        metadata: {
          workspacePath: location.workspacePath,
          branchName: location.branchName,
          dryRun,
          writesEnabled: workspaceWritesEnabled(),
          status,
        },
      });
      db.update(cbAgentRuns)
        .set({ auditTrail, updatedAt: now() } as never)
        .where(eq(cbAgentRuns.id, id))
        .run();
    }

    const result = buildWorkspacePreparationResult({
      agentRunId: id,
      workItemId: existing.workItemId ?? null,
      request: body,
      location,
      status,
      exists: refreshedExists,
      isDirty: refreshedDirty,
      blockReasons,
      rationale,
      dryRun: dryRun || !workspaceWritesEnabled(),
    });
    return c.json({ data: result });
  } catch (err) {
    const message = err instanceof Error ? err.message : "Unknown error";
    return c.json({ error: "workspace_prepare_failed", message }, 400);
  }
});

async function ensureAgentRunWorkspaceReady(args: {
  agentRunId: string;
  actor: string;
  rationale: string;
}): Promise<
  | { ok: true; result: WorkspacePreparationResult }
  | { ok: false; status: number; message: string; result: WorkspacePreparationResult | null }
> {
  try {
    const prepareResp = await app.request(
      "/agent-runs/" + args.agentRunId + "/workspace/prepare",
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          actor: args.actor,
          rationale: args.rationale,
          dryRun: false,
        }),
      }
    );
    const prepared = (await prepareResp.json().catch(() => ({}))) as {
      data?: WorkspacePreparationResult;
      message?: string;
    };
    const result = prepared.data ?? null;
    if (!prepareResp.ok) {
      return {
        ok: false,
        status: prepareResp.status,
        message: prepared.message ?? `workspace prepare failed with status ${prepareResp.status}`,
        result,
      };
    }
    if (!result || (result.status !== "created" && result.status !== "reused")) {
      return {
        ok: false,
        status: 400,
        message: `workspace prepare status=${result?.status ?? "unknown"}; expected created/reused before execution`,
        result,
      };
    }
    return { ok: true, result };
  } catch (err) {
    return {
      ok: false,
      status: 400,
      message: `workspace prepare threw: ${err instanceof Error ? err.message : "unknown"}`,
      result: null,
    };
  }
}

function runnerEnabled(): boolean {
  return process.env.AIOS_AGENT_RUNNER_ENABLED === "true";
}

function runnerRepoAllowlist(): string[] {
  return (process.env.AIOS_AGENT_RUNNER_REPO_ALLOWLIST ?? "")
    .split(/[\s,;]+/)
    .map((value) => value.trim())
    .filter((value) => value.length > 0);
}

function runnerCommandAllowlist(): string[] {
  const raw = process.env.AIOS_AGENT_RUNNER_COMMAND_ALLOWLIST;
  if (raw === undefined || raw === null) {
    return ["claude", "codex", "echo", "true"];
  }
  return raw
    .split(/[\s,;]+/)
    .map((value) => value.trim())
    .filter((value) => value.length > 0);
}

function runnerAllowGithubToken(): boolean {
  return process.env.AIOS_AGENT_RUNNER_ALLOW_GITHUB_TOKEN === "true";
}

function runnerAllowSlackToken(): boolean {
  return process.env.AIOS_AGENT_RUNNER_ALLOW_SLACK_TOKEN === "true";
}

function csvEnv(value: string | undefined): string[] {
  return (value ?? "")
    .split(/[\s,;]+/)
    .map((v) => v.trim())
    .filter((v) => v.length > 0);
}

