function getRunnerProfile(id: string): RunnerProfile | null {
  return RUNNER_PROFILE_REGISTRY.find((p) => p.id === id) ?? null;
}

function isRunnerProfileEnabled(profile: RunnerProfile): boolean {
  if (profile.defaultEnabled) return true;
  if (profile.enabledEnvVar) {
    return process.env[profile.enabledEnvVar] === "true";
  }
  return false;
}

function evaluateRunnerProfile(args: {
  profileId: string;
  repo?: string | null;
  area?: CompanyBrainArea | null;
  riskClass?: RiskClass | null;
}): RunnerProfileEvaluation {
  const profile = getRunnerProfile(args.profileId);
  if (!profile) {
    return {
      profileId: args.profileId,
      available: false,
      reason: "profile_not_found",
      detail: `Runner profile "${args.profileId}" is not registered. Known: ${RUNNER_PROFILE_REGISTRY.map((p) => p.id).join(", ")}.`,
    };
  }
  if (!isRunnerProfileEnabled(profile)) {
    return {
      profileId: profile.id,
      available: false,
      reason: "profile_not_enabled",
      detail: `Profile "${profile.id}" is default-OFF; opt-in required.`,
      enabledEnvVar: profile.enabledEnvVar,
    };
  }
  const cmdAllowlist = runnerCommandAllowlist();
  if (!cmdAllowlist.includes(profile.command)) {
    return {
      profileId: profile.id,
      available: false,
      reason: "profile_command_not_allowlisted",
      detail: `Profile command ${profile.command} is not in AIOS_AGENT_RUNNER_COMMAND_ALLOWLIST=[${cmdAllowlist.join(",")}].`,
      enabledEnvVar: profile.enabledEnvVar,
    };
  }
  if (
    args.repo &&
    profile.allowedRepos !== "*" &&
    !profile.allowedRepos.includes(args.repo)
  ) {
    return {
      profileId: profile.id,
      available: false,
      reason: "profile_repo_not_allowed",
      detail: `Profile "${profile.id}" does not allow repo=${args.repo}; allowed=[${profile.allowedRepos.join(",")}].`,
    };
  }
  if (
    args.area &&
    profile.allowedAreas !== "*" &&
    !(profile.allowedAreas as string[]).includes(args.area)
  ) {
    return {
      profileId: profile.id,
      available: false,
      reason: "profile_area_not_allowed",
      detail: `Profile "${profile.id}" does not allow area=${args.area}; allowed=[${(profile.allowedAreas as string[]).join(",")}].`,
    };
  }
  // riskCeiling: A is most restrictive (only A allowed), B allows A or B,
  // C allows everything (we never use C here).
  if (args.riskClass) {
    const riskOrder: Record<string, number> = { A: 1, B: 2, C: 3, unknown: 99 };
    const requested = riskOrder[args.riskClass] ?? 99;
    const ceiling = riskOrder[profile.riskCeiling] ?? 0;
    if (requested > ceiling) {
      return {
        profileId: profile.id,
        available: false,
        reason: "profile_risk_ceiling_exceeded",
        detail: `Profile "${profile.id}" risk ceiling=${profile.riskCeiling}; requested=${args.riskClass}.`,
      };
    }
  }
  return {
    profileId: profile.id,
    available: true,
    reason: null,
    detail: `Profile "${profile.id}" available (command=${profile.command}, capabilities=[${profile.capabilities.join(",")}]).`,
  };
}

function commandPresence(command: string): RunnerProfileReadinessItem["commandPresence"] {
  const pathEnv = process.env.PATH ?? "";
  const candidates = command.includes("/")
    ? [command]
    : pathEnv.split(delimiter).filter(Boolean).map((dir) => join(dir, command));
  for (const candidate of candidates) {
    try {
      accessSync(candidate, fsConstants.X_OK);
      return {
        command,
        found: true,
        path: candidate,
        checkedWith: "path_lookup",
      };
    } catch {
      // Continue scanning PATH without executing the command.
    }
  }
  return {
    command,
    found: false,
    path: null,
    checkedWith: "path_lookup",
  };
}

function authEnvRefsForMode(mode: RunnerProfileAuthMode): string[] {
  if (mode === "github_token") return ["GITHUB_TOKEN", "GH_TOKEN"];
  if (mode === "anthropic_api_key") return ["ANTHROPIC_API_KEY"];
  if (mode === "openai_api_key") return ["OPENAI_API_KEY"];
  return [];
}

function buildRunnerProfileReadinessMatrix(args: {
  repo?: string | null;
  area?: CompanyBrainArea | null;
  riskClass?: RiskClass | null;
}): RunnerProfileReadinessMatrix {
  const generatedAt = now();
  const commandAllowlist = runnerCommandAllowlist();
  const repoAllowlist = runnerRepoAllowlist();
  const wsAllowlist = workspaceAllowlist();
  const autoConfig = autoDispatchConfig();
  const environment = {
    runnerEnabled: runnerEnabled(),
    workspaceWritesEnabled: workspaceWritesEnabled(),
    autoDispatchEnabled: autoConfig.enabled,
    commandAllowlist,
    runnerRepoAllowlist: repoAllowlist,
    workspaceAllowlist: wsAllowlist,
    autoDispatchRepoAllowlist: autoConfig.repoAllowlist,
  };
  const riskOrder: Record<string, number> = { A: 1, B: 2, C: 3, unknown: 99 };

  const profiles = RUNNER_PROFILE_REGISTRY.map((profile): RunnerProfileReadinessItem => {
    const gates: RunnerProfileReadinessItem["gates"] = [];
    const blockReasons: string[] = [];
    const addGate = (gate: RunnerProfileReadinessItem["gates"][number]) => {
      gates.push(gate);
      if (gate.status === "blocked") blockReasons.push(gate.key);
    };
    const addEnvGate = (args: {
      key: string;
      title: string;
      passed: boolean;
      detail: string;
      envRefs?: string[];
      recommendedAction: string;
    }) => {
      addGate({
        key: args.key,
        title: args.title,
        status: args.passed ? "ready" : "blocked",
        detail: args.detail,
        envRefs: args.envRefs,
        recommendedAction: args.passed ? undefined : args.recommendedAction,
      });
    };

    const enabled = isRunnerProfileEnabled(profile);
    const presence = commandPresence(profile.command);
    const commandAllowlisted = commandAllowlist.includes(profile.command);
    const repoAllowed = args.repo
      ? profile.allowedRepos === "*" && repoAllowlist.includes(args.repo)
        ? true
        : profile.allowedRepos === "*"
          ? repoAllowlist.includes(args.repo)
          : profile.allowedRepos.includes(args.repo) && repoAllowlist.includes(args.repo)
      : null;
    const workspaceRepoAllowed = args.repo
      ? wsAllowlist.length === 0 || wsAllowlist.includes(args.repo)
      : null;
    const areaAllowed = args.area
      ? profile.allowedAreas === "*" ||
        (profile.allowedAreas as CompanyBrainArea[]).includes(args.area)
      : null;
    const riskAllowed = args.riskClass
      ? (riskOrder[args.riskClass] ?? 99) <=
        (riskOrder[profile.riskCeiling] ?? 0)
      : null;
    const requiredEnvRefs = authEnvRefsForMode(profile.authMode);
    const presentEnvRefs = requiredEnvRefs.filter((ref) => Boolean(process.env[ref]));
    const authSatisfied =
      requiredEnvRefs.length === 0 ||
      (profile.authMode === "github_token"
        ? presentEnvRefs.length > 0
        : presentEnvRefs.length === requiredEnvRefs.length);
    const missingEnvRefs = authSatisfied
      ? []
      : requiredEnvRefs.filter((ref) => !presentEnvRefs.includes(ref));
    const evaluation = evaluateRunnerProfile({
      profileId: profile.id,
      repo: args.repo,
      area: args.area,
      riskClass: args.riskClass,
    });

    addEnvGate({
      key: "runner_enabled",
      title: "Runner enabled",
      passed: environment.runnerEnabled,
      detail: `AIOS_AGENT_RUNNER_ENABLED=${String(environment.runnerEnabled)}`,
      envRefs: ["AIOS_AGENT_RUNNER_ENABLED"],
      recommendedAction: "Set AIOS_AGENT_RUNNER_ENABLED=true only in a controlled runner environment.",
    });
    addEnvGate({
      key: "workspace_writes_enabled",
      title: "Workspace writes enabled",
      passed: environment.workspaceWritesEnabled,
      detail: `AIOS_AGENT_WORKSPACE_ENABLED=${String(environment.workspaceWritesEnabled)}`,
      envRefs: ["AIOS_AGENT_WORKSPACE_ENABLED"],
      recommendedAction: "Set AIOS_AGENT_WORKSPACE_ENABLED=true after repo/workspace allowlists are correct.",
    });
    addEnvGate({
      key: "profile_enabled",
      title: "Profile enabled",
      passed: enabled,
      detail: profile.defaultEnabled
        ? "Profile is default-enabled."
        : `${profile.enabledEnvVar ?? "(missing env var)"}=${String(enabled)}`,
      envRefs: profile.enabledEnvVar ? [profile.enabledEnvVar] : undefined,
      recommendedAction: profile.enabledEnvVar
        ? `Set ${profile.enabledEnvVar}=true after readiness review.`
        : "Use a registered/default-enabled profile.",
    });
    addGate({
      key: "command_present",
      title: "Command present",
      status: presence.found ? "ready" : "blocked",
      detail: presence.found
        ? `${profile.command} found at ${presence.path}`
        : `${profile.command} was not found on PATH.`,
      recommendedAction: presence.found
        ? undefined
        : `Install ${profile.command} on the runner host or choose a different profile.`,
    });
    addEnvGate({
      key: "command_allowlisted",
      title: "Command allowlisted",
      passed: commandAllowlisted,
      detail: `${profile.command} in AIOS_AGENT_RUNNER_COMMAND_ALLOWLIST=[${commandAllowlist.join(",")}]`,
      envRefs: ["AIOS_AGENT_RUNNER_COMMAND_ALLOWLIST"],
      recommendedAction: `Add ${profile.command} to AIOS_AGENT_RUNNER_COMMAND_ALLOWLIST after command review.`,
    });
    if (args.repo) {
      addEnvGate({
        key: "runner_repo_allowlisted",
        title: "Runner repo allowlisted",
        passed: repoAllowlist.includes(args.repo),
        detail: `repo=${args.repo}; allowlist=[${repoAllowlist.join(",")}]`,
        envRefs: ["AIOS_AGENT_RUNNER_REPO_ALLOWLIST"],
        recommendedAction: `Add ${args.repo} to AIOS_AGENT_RUNNER_REPO_ALLOWLIST for this pilot only.`,
      });
      addEnvGate({
        key: "workspace_repo_allowlisted",
        title: "Workspace repo allowlisted",
        passed: workspaceRepoAllowed === true,
        detail: `repo=${args.repo}; workspaceAllowlist=[${wsAllowlist.join(",") || "(empty=all)"}]`,
        envRefs: ["AIOS_AGENT_WORKSPACE_ALLOWLIST"],
        recommendedAction: `Add ${args.repo} to AIOS_AGENT_WORKSPACE_ALLOWLIST or keep it intentionally open only in local dogfood.`,
      });
      addGate({
        key: "profile_repo_allowed",
        title: "Profile repo allowed",
        status:
          profile.allowedRepos === "*" || profile.allowedRepos.includes(args.repo)
            ? "ready"
            : "blocked",
        detail:
          profile.allowedRepos === "*"
            ? "Profile allows any repo; runner repo allowlist still gates execution."
            : `profile.allowedRepos=[${profile.allowedRepos.join(",")}]; repo=${args.repo}`,
        recommendedAction:
          profile.allowedRepos === "*" || profile.allowedRepos.includes(args.repo)
            ? undefined
            : `Use a profile that explicitly allows ${args.repo}.`,
      });
    } else {
      addGate({
        key: "repo_context",
        title: "Repo context",
        status: "warn",
        detail: "No repo filter supplied; repo-specific gates are not fully evaluated.",
        recommendedAction: "Call with repo=<owner/name> before enabling a real profile.",
      });
    }
    if (args.area) {
      addGate({
        key: "profile_area_allowed",
        title: "Profile area allowed",
        status: areaAllowed ? "ready" : "blocked",
        detail:
          profile.allowedAreas === "*"
            ? "Profile allows any area."
            : `profile.allowedAreas=[${(profile.allowedAreas as CompanyBrainArea[]).join(",")}]; area=${args.area}`,
        recommendedAction: areaAllowed ? undefined : `Use an allowed area for profile ${profile.id}.`,
      });
    }
    if (args.riskClass) {
      addGate({
        key: "profile_risk_allowed",
        title: "Profile risk allowed",
        status: riskAllowed ? "ready" : "blocked",
        detail: `riskClass=${args.riskClass}; profile.riskCeiling=${profile.riskCeiling}`,
        recommendedAction: riskAllowed
          ? undefined
          : "Lower the WorkItem risk or pick a profile with a higher reviewed risk ceiling.",
      });
    }
    addGate({
      key: "auth_env_ready",
      title: "Auth env ready",
      status: authSatisfied ? "ready" : "blocked",
      detail: requiredEnvRefs.length
        ? `authMode=${profile.authMode}; present=[${presentEnvRefs.join(",") || "(none)"}]`
        : `authMode=${profile.authMode}; no secret env required.`,
      envRefs: requiredEnvRefs.length ? requiredEnvRefs : undefined,
      recommendedAction: authSatisfied
        ? undefined
        : `Provide ${missingEnvRefs.join(" or ")} only on the intended runner host.`,
    });
    addGate({
      key: "auto_dispatch_default_off",
      title: "Auto-dispatch default-off",
      status: environment.autoDispatchEnabled ? "warn" : "ready",
      detail: `AIOS_AGENT_AUTODISPATCH_ENABLED=${String(environment.autoDispatchEnabled)}`,
      envRefs: ["AIOS_AGENT_AUTODISPATCH_ENABLED"],
      recommendedAction: environment.autoDispatchEnabled
        ? "Keep max concurrency and repo/profile allowlists narrow; manual launch remains preferred for first pilot."
        : "Manual launch can be tested while broad auto-dispatch remains off.",
    });

    const status: RunnerProfileReadinessStatus = blockReasons.length
      ? "blocked"
      : gates.some((gate) => gate.status === "warn")
        ? "warn"
        : "ready";
    const firstAction =
      gates.find((gate) => gate.status === "blocked" && gate.recommendedAction)
        ?.recommendedAction ??
      gates.find((gate) => gate.status === "warn" && gate.recommendedAction)
        ?.recommendedAction ??
      "Ready for manual preview/launch in this environment; keep external writeback governed by proposals.";

    return {
      profile,
      evaluation,
      status,
      blockReasons,
      recommendedNextAction: firstAction,
      commandPresence: presence,
      commandAllowlisted,
      repoAllowed,
      areaAllowed,
      riskAllowed,
      auth: {
        mode: profile.authMode,
        requiredEnvRefs,
        presentEnvRefs,
        missingEnvRefs,
      },
      gates,
    };
  });

  const profilesByCategory = profiles.reduce<Record<string, RunnerProfileReadinessItem[]>>(
    (acc, item) => {
      acc[item.profile.category] = acc[item.profile.category] ?? [];
      acc[item.profile.category].push(item);
      return acc;
    },
    {}
  );
  return {
    generatedAt,
    filters: {
      repo: args.repo ?? null,
      area: args.area ?? null,
      riskClass: args.riskClass ?? null,
    },
    environment,
    totals: {
      total: profiles.length,
      ready: profiles.filter((item) => item.status === "ready").length,
      blocked: profiles.filter((item) => item.status === "blocked").length,
      warn: profiles.filter((item) => item.status === "warn").length,
      realAgentReady: profiles.filter(
        (item) => item.profile.category === "real_agent" && item.status === "ready"
      ).length,
      realAgentBlocked: profiles.filter(
        (item) => item.profile.category === "real_agent" && item.status === "blocked"
      ).length,
    },
    profilesByCategory,
    profiles,
  };
}

function filterReadinessMatrixProfiles(
  matrix: RunnerProfileReadinessMatrix,
  allowedRunnerProfileIds: string[]
): RunnerProfileReadinessMatrix {
  const allowed = new Set(allowedRunnerProfileIds);
  const profiles = matrix.profiles.filter((item) => allowed.has(item.profile.id));
  const profilesByCategory = profiles.reduce<Record<string, RunnerProfileReadinessItem[]>>(
    (acc, item) => {
      acc[item.profile.category] = acc[item.profile.category] ?? [];
      acc[item.profile.category].push(item);
      return acc;
    },
    {}
  );
  return {
    ...matrix,
    totals: {
      total: profiles.length,
      ready: profiles.filter((item) => item.status === "ready").length,
      blocked: profiles.filter((item) => item.status === "blocked").length,
      warn: profiles.filter((item) => item.status === "warn").length,
      realAgentReady: profiles.filter(
        (item) => item.profile.category === "real_agent" && item.status === "ready"
      ).length,
      realAgentBlocked: profiles.filter(
        (item) => item.profile.category === "real_agent" && item.status === "blocked"
      ).length,
    },
    profilesByCategory,
    profiles,
  };
}

function buildPilotTargetReadiness(target: PilotTarget): PilotTargetReadiness {
  const readiness = filterReadinessMatrixProfiles(
    buildRunnerProfileReadinessMatrix({
      repo: target.repo,
      area: target.area,
      riskClass: target.riskCeiling,
    }),
    target.allowedRunnerProfileIds
  );
  const launchableProfiles = readiness.profiles.filter(
    (item) => item.profile.category === "real_agent" || item.profile.category === "dogfood"
  );
  const readyProfileIds = launchableProfiles
    .filter((item) => item.status === "ready")
    .map((item) => item.profile.id);
  const blockedProfileIds = launchableProfiles
    .filter((item) => item.status === "blocked")
    .map((item) => item.profile.id);
  const warnProfileIds = launchableProfiles
    .filter((item) => item.status === "warn")
    .map((item) => item.profile.id);
  const blockReasons = new Set<string>();
  if (target.status !== "active") blockReasons.add(`target_${target.status}`);
  if (!launchableProfiles.length) blockReasons.add("no_launchable_profile_allowed");
  if (!readyProfileIds.length) blockReasons.add("no_ready_launchable_profile");
  for (const item of launchableProfiles) {
    for (const reason of item.blockReasons) {
      blockReasons.add(`${item.profile.id}:${reason}`);
    }
  }
  const readyForManualLaunch = target.status === "active" && readyProfileIds.length > 0;
  const status: RunnerProfileReadinessStatus = readyForManualLaunch
    ? warnProfileIds.length
      ? "warn"
      : "ready"
    : "blocked";
  const recommendedNextAction =
    target.status !== "active"
      ? `Set target status to active only after owner review; current status=${target.status}.`
      : readyForManualLaunch
        ? `Manual launch is ready for ${readyProfileIds.join(", ")}; keep auto-dispatch default-off.`
        : launchableProfiles[0]?.recommendedNextAction ??
          "Add at least one allowed launchable profile and satisfy its readiness gates.";
  return {
    status,
    readyForManualLaunch,
    readyProfileIds,
    blockedProfileIds,
    warnProfileIds,
    blockReasons: Array.from(blockReasons),
    recommendedNextAction,
    readiness,
  };
}

function listPilotTargets(args: {
  repo?: string | null;
  status?: PilotTargetStatus | "all";
}): ListPilotTargetsResponse {
  const generatedAt = now();
  const status = args.status ?? "all";
  const rows = getDb().select().from(cbPilotTargets).all() as PilotTarget[];
  const filtered = rows.filter((target) => {
    if (args.repo && target.repo !== args.repo) return false;
    if (status !== "all" && target.status !== status) return false;
    return true;
  });
  const targets = filtered
    .sort((a, b) => {
      if (a.status !== b.status) return a.status === "active" ? -1 : 1;
      return a.projectName.localeCompare(b.projectName);
    })
    .map((target) => ({
      target,
      readiness: buildPilotTargetReadiness(target),
    }));
  return {
    generatedAt,
    filters: {
      repo: args.repo ?? null,
      status,
    },
    totals: {
      total: targets.length,
      active: targets.filter((item) => item.target.status === "active").length,
      readyForManualLaunch: targets.filter(
        (item) => item.readiness.readyForManualLaunch
      ).length,
      blocked: targets.filter((item) => item.readiness.status === "blocked").length,
      warn: targets.filter((item) => item.readiness.status === "warn").length,
    },
    targets,
  };
}

function firstProjectOverallStatus(
  items: FirstProjectReadinessChecklistItem[]
): FirstProjectReadinessStatus {
  if (items.some((item) => item.status === "blocked")) return "blocked";
  if (items.some((item) => item.status === "warn")) return "warn";
  return "ready";
}

function operatingSnapshotReadinessStatus(
  status: CompanyBrainOperatingSnapshot["overallStatus"]
): FirstProjectReadinessStatus {
  if (status === "healthy") return "ready";
  if (status === "attention") return "warn";
  return "blocked";
}

function buildFirstProjectReadinessChecklist(args: {
  repo?: string | null;
  area?: CompanyBrainArea | null;
  riskClass?: RiskClass | null;
}): FirstProjectReadinessChecklist {
  const repo = args.repo?.trim() || OPERATING_CADENCE_DEFAULT_REPO;
  const area = args.area ?? "development";
  const riskClass = args.riskClass ?? "B";
  const generatedAt = now();
  const runbookPath = "docs/aios-first-project-operating-runbook.md";
  const runbookExists = existsSync(resolve(runbookPath));
  const operatingSnapshot = buildOperatingSnapshot(listAll());
  const runnerReadiness = buildRunnerProfileReadinessMatrix({ repo, area, riskClass });
  const pilotTargets = listPilotTargets({ repo, status: "all" });
  const prReviewIntake = buildAiosPrReviewIntake();
  const autoConfig = autoDispatchConfig();
  const productionDefaultOffEvidence = {
    runnerEnabled: runnerEnabled(),
    workspaceWritesEnabled: workspaceWritesEnabled(),
    autoDispatchEnabled: autoConfig.enabled,
    prWritebackEnabled: githubPrWritebackEnabled(),
    runnerRepoAllowlist: runnerRepoAllowlist(),
    workspaceAllowlist: workspaceAllowlist(),
    commandAllowlist: runnerCommandAllowlist(),
    autoDispatchRepoAllowlist: autoConfig.repoAllowlist,
  };
  const allMutatingAgentGatesOff =
    !productionDefaultOffEvidence.runnerEnabled &&
    !productionDefaultOffEvidence.workspaceWritesEnabled &&
    !productionDefaultOffEvidence.autoDispatchEnabled &&
    !productionDefaultOffEvidence.prWritebackEnabled;
  const activeTargetCount = pilotTargets.totals.active;
  const readyTargetCount = pilotTargets.totals.readyForManualLaunch;
  const pendingReviews = prReviewIntake.totals.awaitingHumanReview;

  const items: FirstProjectReadinessChecklistItem[] = [
    {
      key: "runbook_present",
      title: "First-project runbook",
      status: runbookExists ? "ready" : "blocked",
      detail: runbookExists
        ? "Canonical first-project operating runbook is present in repo docs."
        : "Canonical first-project operating runbook is missing.",
      docPath: runbookPath,
      nextAction: runbookExists
        ? "Use this runbook as the durable operator contract before enabling a project."
        : "Create docs/aios-first-project-operating-runbook.md before launching a real project run.",
      blockReasons: runbookExists ? [] : ["missing_runbook"],
    },
    {
      key: "operating_snapshot_ready",
      title: "Operating snapshot",
      status: operatingSnapshotReadinessStatus(operatingSnapshot.overallStatus),
      detail: `${operatingSnapshot.overallStatus}: ${operatingSnapshot.summary}`,
      route: "/company-brain/operating",
      apiPath: "/api/company-brain/operating-snapshot",
      nextAction:
        operatingSnapshot.overallStatus === "healthy"
          ? "Keep cadence fresh before starting the pilot."
          : "Run Operating Cadence or review the attention/error card before starting the pilot.",
      blockReasons:
        operatingSnapshot.overallStatus === "error" ||
        operatingSnapshot.overallStatus === "critical"
          ? [`operating_snapshot_${operatingSnapshot.overallStatus}`]
          : [],
    },
    {
      key: "pilot_target_registered",
      title: "Pilot target registry",
      status: activeTargetCount > 0 ? "ready" : "blocked",
      detail: `${pilotTargets.totals.total} target(s), ${activeTargetCount} active, ${readyTargetCount} manual-launch ready for ${repo}.`,
      route: "/company-brain/agent-runs",
      apiPath: `/api/company-brain/pilot-targets?repo=${encodeURIComponent(repo)}&status=all`,
      nextAction:
        activeTargetCount > 0
          ? "Keep this registry as the first-pilot allowlist; do not infer eligibility from chat history."
          : `Register ${repo} as an active pilot target before any AgentRun launch.`,
      blockReasons: activeTargetCount > 0 ? [] : ["missing_active_pilot_target"],
    },
    {
      key: "runner_readiness_visible",
      title: "Runner readiness",
      status: runnerReadiness.totals.realAgentReady > 0 ? "ready" : "warn",
      detail: `${runnerReadiness.totals.realAgentReady} real profile(s) ready, ${runnerReadiness.totals.realAgentBlocked} blocked; production default-off can intentionally keep this at warn.`,
      route: "/company-brain/agent-runs",
      apiPath: `/api/company-brain/runner-profile-readiness?repo=${encodeURIComponent(repo)}&area=${encodeURIComponent(area)}&riskClass=${encodeURIComponent(riskClass)}`,
      nextAction:
        runnerReadiness.totals.realAgentReady > 0
          ? "Manual launch may be previewed with a human actor/rationale."
          : "Enable runner/workspace/profile env gates only in a controlled session and keep the runbook kill switches open.",
    },
    {
      key: "production_default_off_visible",
      title: "Production default-off evidence",
      status: allMutatingAgentGatesOff ? "ready" : "warn",
      detail: `runner=${String(productionDefaultOffEvidence.runnerEnabled)}, workspace=${String(productionDefaultOffEvidence.workspaceWritesEnabled)}, autoDispatch=${String(productionDefaultOffEvidence.autoDispatchEnabled)}, prWriteback=${String(productionDefaultOffEvidence.prWritebackEnabled)}.`,
      route: "/company-brain/agent-runs",
      nextAction: allMutatingAgentGatesOff
        ? "Production is safe-by-default; use explicit opt-in only for a supervised pilot window."
        : "Confirm the enabled gates are intentional and documented before starting or continuing the pilot.",
    },
    {
      key: "pending_aios_pr_reviews_visible",
      title: "AIOS-authored PR review intake",
      status: pendingReviews > 0 ? "warn" : "ready",
      detail: `${prReviewIntake.totals.total} AIOS-authored PR(s) indexed; ${pendingReviews} awaiting human review; ${prReviewIntake.totals.changesRequested} changes requested.`,
      route: "/company-brain/operating",
      apiPath: "/api/company-brain/aios-pr-review-intake",
      nextAction:
        pendingReviews > 0
          ? "Review pending AIOS-authored PRs before widening the pilot."
          : "Keep syncing PR review intake before and after each AgentRun.",
    },
    {
      key: "manual_launch_governed",
      title: "Manual launch governance",
      status: readyTargetCount > 0 ? "ready" : "warn",
      detail: readyTargetCount > 0
        ? "At least one active target has a ready real-agent profile."
        : "Manual launch remains governed and blocked by readiness gates until env opt-in is explicit.",
      route: "/company-brain/agent-runs",
      apiPath: "/api/company-brain/agent-runs/launcher/preview",
      nextAction:
        "Use launcher preview first; launch requires actor, rationale and passing policy gates.",
    },
    {
      key: "allowed_actions_bounded",
      title: "Allowed actions are bounded",
      status: "ready",
      detail:
        "First pilot allows internal repo work, workspace preparation, supervised AgentRun, patch packet, PR proposal and review intake. Merge/deploy/customer repo actions stay out of scope.",
      docPath: runbookPath,
      nextAction: "Do not add a new executor or external mutation as part of this runbook issue.",
    },
    {
      key: "stop_conditions_defined",
      title: "Kill switches and stop conditions",
      status: runbookExists ? "ready" : "blocked",
      detail:
        "Runbook defines env kill switches, AgentRun cancel, workspace quarantine, PR writeback shutdown and stop conditions.",
      docPath: runbookPath,
      nextAction:
        "Keep kill-switch commands visible before enabling any real runner profile.",
      blockReasons: runbookExists ? [] : ["missing_stop_conditions_doc"],
    },
  ];
  const overallStatus = firstProjectOverallStatus(items);
  const totals = {
    itemCount: items.length,
    ready: items.filter((item) => item.status === "ready").length,
    warn: items.filter((item) => item.status === "warn").length,
    blocked: items.filter((item) => item.status === "blocked").length,
    pendingAiosPrReviews: pendingReviews,
    pilotTargets: pilotTargets.totals.total,
    launchReadyPilotTargets: readyTargetCount,
    realAgentReadyProfiles: runnerReadiness.totals.realAgentReady,
  };
  const nextActions = uniqueStrings(
    items
      .filter((item) => item.status !== "ready" && item.nextAction)
      .map((item) => item.nextAction as string)
      .concat(
        overallStatus === "ready"
          ? [
              "Use the runbook to run one supervised first-project cycle, then submit session_result and reconcile Next Work.",
            ]
          : []
      )
  ).slice(0, 5);

  return {
    generatedAt,
    repo,
    area,
    riskClass,
    overallStatus,
    summary: `First-project readiness is ${overallStatus}: ${totals.ready}/${totals.itemCount} ready, ${totals.warn} warn, ${totals.blocked} blocked. Production default-off ${allMutatingAgentGatesOff ? "preserved" : "requires review"}.`,
    runbookPath,
    productionDefaultOffEvidence,
    linkedSurfaces: {
      operatingSurface: "/company-brain/operating",
      agentRuns: "/company-brain/agent-runs",
      runnerReadinessApi: `/api/company-brain/runner-profile-readiness?repo=${encodeURIComponent(repo)}&area=${encodeURIComponent(area)}&riskClass=${encodeURIComponent(riskClass)}`,
      pilotTargetsApi: `/api/company-brain/pilot-targets?repo=${encodeURIComponent(repo)}&status=all`,
      aiosPrReviewIntakeApi: "/api/company-brain/aios-pr-review-intake",
      operatingSnapshotApi: "/api/company-brain/operating-snapshot",
    },
    totals,
    items,
    nextActions,
  };
}

const RISK_CLASS_RANK: Record<RiskClass, number> = {
  A: 1,
  B: 2,
  C: 3,
  unknown: 99,
};

function riskWithinCeiling(riskClass: RiskClass, ceiling: RiskClass): boolean {
  return (RISK_CLASS_RANK[riskClass] ?? 99) <= (RISK_CLASS_RANK[ceiling] ?? 0);
}

function runnerTypeForProfile(profile: RunnerProfile): AgentRunRunnerType {
  if (profile.id === "claude-code-real") return "claude_code";
  if (profile.id === "codex-cli-real") return "codex";
  if (profile.command === "claude") return "claude_code";
  if (profile.command === "codex") return "codex";
  return "other";
}

function repoFromWorkItem(workItem: WorkItem): string | null {
  const match = workItem.externalId?.match(/^([^#]+)#\d+$/);
  return match?.[1] ?? null;
}

function resolveAgentRunWorkItemKey(args: {
  agentRun: Pick<typeof cbAgentRuns.$inferSelect, "id" | "workItemId">;
  repo: string;
}): string {
  if (!args.agentRun.workItemId) return args.agentRun.id;
  const workItem = getDb()
    .select()
    .from(cbWorkItems)
    .where(eq(cbWorkItems.id, args.agentRun.workItemId))
    .get() as typeof cbWorkItems.$inferSelect | undefined;
  const externalIdMatch = workItem?.externalId?.match(/#(\d+)$/);
  return externalIdMatch
    ? `${args.repo.replace("/", "_")}_${externalIdMatch[1]}`
    : workItem?.externalId ?? args.agentRun.workItemId;
}

function buildLaunchPreviewAgentRun(args: {
  id: string;
  workItem: WorkItem;
  target: PilotTarget;
  profile: RunnerProfile;
  riskClass: RiskClass;
  metadata: Record<string, unknown>;
}): typeof cbAgentRuns.$inferSelect {
  const timestamp = now();
  return {
    id: args.id,
    workItemId: args.workItem.id,
    workflowRunId: null,
    agentContextId: null,
    sourceId: args.workItem.sourceId ?? null,
    repo: args.target.repo,
    branch: null,
    workspaceRef: null,
    runnerType: runnerTypeForProfile(args.profile),
    status: "queued",
    claimState: "unclaimed",
    attempt: 0,
    startedAt: null,
    finishedAt: null,
    errorSummary: null,
    prUrl: null,
    externalRunRef: null,
    tokensInput: null,
    tokensOutput: null,
    tokensTotal: null,
    costUsd: null,
    agentSessionId: null,
    agentThreadId: null,
    area: args.target.area,
    riskClass: args.riskClass,
    actionPolicy: "request_human",
    visibility: args.workItem.visibility ?? "internal",
    metadata: args.metadata,
    auditTrail: [],
    provenance: {
      sourceId: args.workItem.sourceId ?? null,
      rawRef: `aios://agent-run-launcher/${args.workItem.id}/${args.profile.id}`,
      artifactId: args.workItem.artifactId ?? null,
      createdFrom: "company_brain:agent_run_launcher_preview",
      confidence: 1,
      extractedAt: timestamp,
      humanReviewStatus: "pending",
      visibility: args.workItem.visibility ?? "internal",
      notes: `profile=${args.profile.id}; target=${args.target.id}`,
    } as Provenance,
    createdAt: timestamp,
    updatedAt: timestamp,
    lastLogAt: null,
    lastLogLineCount: null,
    pid: null,
    executionRef: null,
  } as typeof cbAgentRuns.$inferSelect;
}

function buildAgentRunLauncherPreview(args: {
  request: PreviewAgentRunLaunchRequest;
  previewAgentRunId?: string;
}): AgentRunLaunchPreview {
  const db = getDb();
  const generatedAt = now();
  const workItem = db
    .select()
    .from(cbWorkItems)
    .where(eq(cbWorkItems.id, requireText(args.request.workItemId, "workItemId")))
    .get() as WorkItem | undefined;
  if (!workItem) {
    throw new Error(`workItem ${args.request.workItemId} not found`);
  }

  const repo = repoFromWorkItem(workItem);
  const targets = listPilotTargets({ repo, status: "all" }).targets;
  const target =
    targets.find((item) => item.target.id === args.request.pilotTargetId)?.target ??
    targets.find((item) => item.target.status === "active")?.target ??
    targets[0]?.target;
  if (!target) {
    throw new Error(`no pilot target found for repo=${repo ?? "(unknown)"}`);
  }

  const targetReadiness = buildPilotTargetReadiness(target);
  const requestedProfileId =
    args.request.profileId?.trim() ||
    targetReadiness.readyProfileIds[0] ||
    target.allowedRunnerProfileIds.find((id) => getRunnerProfile(id)?.category === "real_agent") ||
    target.allowedRunnerProfileIds[0];
  if (!requestedProfileId) {
    throw new Error(`pilot target ${target.id} has no allowed runner profiles`);
  }
  const selectedProfile = getRunnerProfile(requestedProfileId);
  if (!selectedProfile) {
    throw new Error(`runner profile ${requestedProfileId} not found`);
  }
  const riskClass = args.request.riskClass ?? target.riskCeiling;
  const launchReadiness = filterReadinessMatrixProfiles(
    buildRunnerProfileReadinessMatrix({
      repo: target.repo,
      area: target.area,
      riskClass,
    }),
    target.allowedRunnerProfileIds
  );
  const profileReadiness =
    launchReadiness.profiles.find((item) => item.profile.id === selectedProfile.id) ??
    null;
  const command = args.request.commandOverride?.trim() || selectedProfile.command;
  const rawArgs =
    args.request.argsOverride && args.request.argsOverride.length
      ? args.request.argsOverride
      : selectedProfile.args;
  const launchMetadata = {
    launcher: "human_approved_agent_run",
    pilotTargetId: target.id,
    runnerProfileId: selectedProfile.id,
    runnerProfileCategory: selectedProfile.category,
    command,
    args: rawArgs,
    expectedWriteback: "none",
  };
  const previewRun = buildLaunchPreviewAgentRun({
    id: args.previewAgentRunId ?? `preview-${nanoid(8)}`,
    workItem,
    target,
    profile: selectedProfile,
    riskClass,
    metadata: launchMetadata,
  });
  const policy = evaluateRunnerPolicy({
    agentRun: previewRun,
    request: {
      actor: args.request.actor ?? null,
      rationale: args.request.rationale ?? null,
      intent: "real_execution",
      commandOverride: command,
      workspaceRootOverride: args.request.workspaceRootOverride ?? null,
    },
  });
  const blockReasons = new Set<string>();
  if (target.status !== "active") blockReasons.add(`target_${target.status}`);
  if (!target.allowedRunnerProfileIds.includes(selectedProfile.id)) {
    blockReasons.add("profile_not_allowed_for_target");
  }
  if (!riskWithinCeiling(riskClass, target.riskCeiling)) {
    blockReasons.add("risk_exceeds_target_ceiling");
  }
  if (!profileReadiness) {
    blockReasons.add("profile_not_in_target_readiness");
  } else if (profileReadiness.status !== "ready") {
    blockReasons.add("profile_not_ready");
    for (const reason of profileReadiness.blockReasons) {
      blockReasons.add(`${selectedProfile.id}:${reason}`);
    }
  }
  if (!policy.realExecutionAllowed) {
    for (const reason of policy.blockReasons) blockReasons.add(reason);
  }
  const canLaunch = blockReasons.size === 0;
  const expectedWriteBoundaries = {
    repo: target.repo,
    workspacePath: policy.workspaceSummary.workspacePath,
    branchName: policy.workspaceSummary.branchName,
    command,
    args: rawArgs,
    profileCapabilities: selectedProfile.capabilities,
    envAllowedKeys: policy.subprocessEnv.allowedKeys,
    envRedactedKeys: policy.subprocessEnv.redactedKeys,
    allowedFilesystemRoots: [policy.workspaceSummary.workspacePath],
    externalWritebackAllowed: false as const,
    blockedExternalActions: [
      "auto_merge",
      "auto_deploy",
      "direct_github_writeback",
      "customer_repo",
      "billing",
      "permissions",
    ],
  };
  const recommendedNextAction = canLaunch
    ? "Create the approved AgentRun, then execute it through the existing supervised runner controls."
    : profileReadiness?.recommendedNextAction ??
      policy.policySummary ??
      "Resolve launcher and runner policy blockers before creating an AgentRun.";
  return {
    generatedAt,
    workItem,
    pilotTarget: target,
    targetReadiness,
    selectedProfile,
    profileReadiness,
    policy,
    riskClass,
    command,
    args: rawArgs,
    expectedWriteBoundaries,
    canLaunch,
    blockReasons: Array.from(blockReasons),
    recommendedNextAction,
  };
}

function autoDispatchEnabled(): boolean {
  return process.env.AIOS_AGENT_AUTODISPATCH_ENABLED === "true";
}

function autoDispatchConfig(): AutoDispatchPolicyConfig {
  const tokenBudget = Number(
    process.env.AIOS_AGENT_AUTODISPATCH_TOKEN_BUDGET ?? "100000"
  );
  const cooldownMs = Number(
    process.env.AIOS_AGENT_AUTODISPATCH_COOLDOWN_MS ?? "900000"
  );
  const maxRuntimeMs = Number(
    process.env.AIOS_AGENT_AUTODISPATCH_MAX_RUNTIME_MS ?? "600000"
  );
  const maxConcurrency = Number(
    process.env.AIOS_AGENT_AUTODISPATCH_MAX_CONCURRENCY ?? "1"
  );
  return {
    enabled: autoDispatchEnabled(),
    repoAllowlist: csvEnv(process.env.AIOS_AGENT_AUTODISPATCH_REPO_ALLOWLIST),
    workflowAllowlist: csvEnv(
      process.env.AIOS_AGENT_AUTODISPATCH_WORKFLOW_ALLOWLIST
    ),
    areaAllowlist: csvEnv(process.env.AIOS_AGENT_AUTODISPATCH_AREA_ALLOWLIST),
    requireRiskA:
      process.env.AIOS_AGENT_AUTODISPATCH_REQUIRE_RISK_A !== "false",
    maxConcurrency: Number.isFinite(maxConcurrency) && maxConcurrency > 0
      ? maxConcurrency
      : 1,
    tokenBudget: Number.isFinite(tokenBudget) && tokenBudget > 0
      ? tokenBudget
      : 100000,
    cooldownMs: Number.isFinite(cooldownMs) && cooldownMs >= 0
      ? cooldownMs
      : 900000,
    maxRuntimeMs: Number.isFinite(maxRuntimeMs) && maxRuntimeMs > 0
      ? maxRuntimeMs
      : 600000,
    defaultActor:
      process.env.AIOS_AGENT_AUTODISPATCH_DEFAULT_ACTOR?.trim() ||
      "operating-loop:auto-dispatch",
    defaultRationale:
      process.env.AIOS_AGENT_AUTODISPATCH_DEFAULT_RATIONALE?.trim() ||
      "Auto-dispatched by Operating Loop after eligibility evaluation",
    commandOverride:
      process.env.AIOS_AGENT_AUTODISPATCH_COMMAND_OVERRIDE?.trim() || null,
    profileId:
      process.env.AIOS_AGENT_AUTODISPATCH_PROFILE_ID?.trim() || null,
  };
}

function buildAutoDispatchRuntimeState(
  config: AutoDispatchPolicyConfig
): AutoDispatchRuntimeState {
  const generatedAt = now();
  const db = getDb();

  const activeRuns = db
    .select()
    .from(cbAgentRuns)
    .where(
      sqlOr(
        eq(cbAgentRuns.status, "running"),
        eq(cbAgentRuns.status, "claimed"),
        eq(cbAgentRuns.status, "queued")
      )
    )
    .all() as Array<typeof cbAgentRuns.$inferSelect>;
  const activeAgentRunCount = activeRuns.filter(
    (r) => r.status === "running" || r.status === "claimed"
  ).length;

  // last auto-dispatch is the most recent agent_run_real_execution_started
  // event in audit trail with actor matching defaultActor prefix.
  const recentRuns = db
    .select()
    .from(cbAgentRuns)
    .orderBy(desc(cbAgentRuns.startedAt))
    .limit(50)
    .all() as Array<typeof cbAgentRuns.$inferSelect>;
  let lastAutoDispatchAt: number | null = null;
  for (const r of recentRuns) {
    const audit = (r.auditTrail ?? []) as Array<{
      at: number;
      actor: string | null;
      event: string;
    }>;
    for (const entry of audit) {
      if (
        entry.actor &&
        entry.actor.startsWith("operating-loop:auto-dispatch") &&
        (entry.event === "agent_run_real_execution_started" ||
          entry.event === "agent_run_async_dispatched")
      ) {
        if (!lastAutoDispatchAt || entry.at > lastAutoDispatchAt) {
          lastAutoDispatchAt = entry.at;
        }
      }
    }
  }
  const cooldownExpiresAt = lastAutoDispatchAt
    ? lastAutoDispatchAt + config.cooldownMs
    : null;
  const cooldownRemainingMs = cooldownExpiresAt
    ? Math.max(0, cooldownExpiresAt - generatedAt)
    : 0;

  // tokens spent in the cooldown window (used as the budget window)
  const windowStart = generatedAt - config.cooldownMs;
  let tokensSpentInWindow = 0;
  for (const r of recentRuns) {
    if ((r.startedAt ?? 0) < windowStart) continue;
    const audit = (r.auditTrail ?? []) as Array<{ actor: string | null }>;
    const isAuto = audit.some(
      (e) =>
        e.actor && e.actor.startsWith("operating-loop:auto-dispatch")
    );
    if (!isAuto) continue;
    tokensSpentInWindow += r.tokensTotal ?? 0;
  }

  return {
    generatedAt,
    activeAgentRunCount,
    lastAutoDispatchAt,
    cooldownExpiresAt,
    cooldownRemainingMs,
    tokensSpentInWindow,
    tokensAvailableInWindow: Math.max(
      0,
      config.tokenBudget - tokensSpentInWindow
    ),
  };
}

function evaluateAutoDispatchEligibility(args: {
  workItem: WorkItem | null;
  suggestion: AgentRunSuggestion | null;
  actorOverride?: string;
  rationaleOverride?: string;
}): AutoDispatchEligibility {
  const generatedAt = now();
  const config = autoDispatchConfig();
  const runtime = buildAutoDispatchRuntimeState(config);
  const gates: AutoDispatchGate[] = [];
  const blockReasons: string[] = [];
  const satisfiedGates: string[] = [];
  let firstBlockDecision: AutoDispatchDecision | null = null;
  const setBlock = (decision: AutoDispatchDecision) => {
    if (!firstBlockDecision) firstBlockDecision = decision;
  };

  // 1. Default-off (env gate)
  if (!config.enabled) {
    gates.push({
      key: "autodispatch_env_enabled",
      title: "Auto-dispatch env-enabled",
      status: "failed",
      detail:
        "AIOS_AGENT_AUTODISPATCH_ENABLED is not set to true; auto-dispatch is default-off.",
      remediation:
        "Set AIOS_AGENT_AUTODISPATCH_ENABLED=true on a controlled environment after the rest of the gates pass.",
      envRefs: ["AIOS_AGENT_AUTODISPATCH_ENABLED"],
      expectedFormat: "boolean string ('true' or unset)",
      exampleValue: "true",
      docsLink: "WORKFLOW.md#auto-dispatch-env-vars",
    });
    blockReasons.push("autodispatch_disabled");
    setBlock("blocked_default_off");
  } else {
    gates.push({
      key: "autodispatch_env_enabled",
      title: "Auto-dispatch env-enabled",
      status: "passed",
      detail: "AIOS_AGENT_AUTODISPATCH_ENABLED=true",
    });
    satisfiedGates.push("autodispatch_env_enabled");
  }

  // 2. Repo allowlist (workflow tracker.repo + WorkItem repo)
  const workflow = loadWorkflowFromRepoRoot();
  const repo = workflow.config.tracker.repo ?? null;
  if (!config.repoAllowlist.length) {
    gates.push({
      key: "repo_allowed",
      title: "Repo allowlisted for auto-dispatch",
      status: "failed",
      detail:
        "AIOS_AGENT_AUTODISPATCH_REPO_ALLOWLIST is empty; auto-dispatch refuses to act on any repo.",
      remediation:
        "Set AIOS_AGENT_AUTODISPATCH_REPO_ALLOWLIST to a CSV of allowlisted repos (owner/name).",
      envRefs: ["AIOS_AGENT_AUTODISPATCH_REPO_ALLOWLIST"],
      expectedFormat: "CSV of GitHub repo identifiers in `owner/name` form (NOT filesystem paths)",
      exampleValue: "antonio-mello-ai/crewdock",
      docsLink: "WORKFLOW.md#auto-dispatch-env-vars",
    });
    blockReasons.push("autodispatch_repo_allowlist_empty");
    setBlock("blocked_repo");
  } else if (!repo) {
    gates.push({
      key: "repo_allowed",
      title: "Repo allowlisted for auto-dispatch",
      status: "failed",
      detail: "WORKFLOW.md tracker.repo is missing.",
      remediation:
        "Set tracker.repo in WORKFLOW.md before enabling auto-dispatch.",
      docsLink: "WORKFLOW.md#tracker",
    });
    blockReasons.push("autodispatch_repo_missing");
    setBlock("blocked_repo");
  } else if (!config.repoAllowlist.includes(repo)) {
    gates.push({
      key: "repo_allowed",
      title: "Repo allowlisted for auto-dispatch",
      status: "failed",
      detail: `repo=${repo} is not in AIOS_AGENT_AUTODISPATCH_REPO_ALLOWLIST.`,
      remediation: `Add ${repo} to AIOS_AGENT_AUTODISPATCH_REPO_ALLOWLIST or fix tracker.repo.`,
      envRefs: ["AIOS_AGENT_AUTODISPATCH_REPO_ALLOWLIST"],
      expectedFormat: "CSV of GitHub repo identifiers in `owner/name` form",
      exampleValue: repo,
      docsLink: "WORKFLOW.md#auto-dispatch-env-vars",
    });
    blockReasons.push("autodispatch_repo_not_allowed");
    setBlock("blocked_repo");
  } else {
    gates.push({
      key: "repo_allowed",
      title: "Repo allowlisted for auto-dispatch",
      status: "passed",
      detail: `repo=${repo} ∈ AIOS_AGENT_AUTODISPATCH_REPO_ALLOWLIST`,
    });
    satisfiedGates.push("repo_allowed");
  }

  // 3. Workflow allowlist (registered workflow blueprint refs)
  if (!config.workflowAllowlist.length) {
    gates.push({
      key: "workflow_allowed",
      title: "Workflow allowlisted for auto-dispatch",
      status: "failed",
      detail:
        "AIOS_AGENT_AUTODISPATCH_WORKFLOW_ALLOWLIST is empty; auto-dispatch refuses to act on any workflow blueprint.",
      remediation:
        "Set AIOS_AGENT_AUTODISPATCH_WORKFLOW_ALLOWLIST to a CSV of workflow blueprint ids registered in cb_workflow_blueprints.",
      envRefs: ["AIOS_AGENT_AUTODISPATCH_WORKFLOW_ALLOWLIST"],
      expectedFormat: "CSV of workflow blueprint ids (matches cb_workflow_blueprints.id, NOT a free-form ref string)",
      exampleValue: "development-blueprint-v0",
      docsLink: "WORKFLOW.md#auto-dispatch-env-vars",
    });
    blockReasons.push("autodispatch_workflow_allowlist_empty");
    setBlock("blocked_workflow");
  } else {
    const db = getDb();
    const blueprints = db.select().from(cbWorkflowBlueprints).all();
    const blueprintRefs = blueprints
      .map((b) => b.id)
      .filter((v): v is string => typeof v === "string" && v.length > 0);
    const matchedRefs = config.workflowAllowlist.filter((ref) =>
      blueprintRefs.includes(ref)
    );
    if (!matchedRefs.length) {
      gates.push({
        key: "workflow_allowed",
        title: "Workflow allowlisted for auto-dispatch",
        status: "failed",
        detail: `Allowlist=[${config.workflowAllowlist.join(",")}] does not match any registered workflow blueprint id (registered=${blueprintRefs.length}; first 3=[${blueprintRefs.slice(0, 3).join(",")}]).`,
        remediation:
          "Register a workflow blueprint with one of the allowlisted ids (POST /workflow-blueprints + #95 stable id contract), or update the allowlist to a registered id.",
        envRefs: ["AIOS_AGENT_AUTODISPATCH_WORKFLOW_ALLOWLIST"],
        expectedFormat: "CSV of workflow blueprint ids (must match cb_workflow_blueprints.id exactly)",
        exampleValue: blueprintRefs[0] ?? "development-blueprint-v0",
        docsLink: "WORKFLOW.md#auto-dispatch-env-vars",
      });
      blockReasons.push("autodispatch_workflow_not_allowed");
      setBlock("blocked_workflow");
    } else {
      gates.push({
        key: "workflow_allowed",
        title: "Workflow allowlisted for auto-dispatch",
        status: "passed",
        detail: `Allowlisted blueprint refs registered: [${matchedRefs.join(",")}]`,
      });
      satisfiedGates.push("workflow_allowed");
    }
  }

  // 4. Area allowlist (WorkItem.area)
  if (!args.workItem) {
    gates.push({
      key: "area_allowed",
      title: "Area allowlisted for auto-dispatch",
      status: "warn",
      detail:
        "No WorkItem context provided; cannot evaluate area gate. Returning warn (not block) for global preview.",
    });
  } else if (!config.areaAllowlist.length) {
    gates.push({
      key: "area_allowed",
      title: "Area allowlisted for auto-dispatch",
      status: "failed",
      detail:
        "AIOS_AGENT_AUTODISPATCH_AREA_ALLOWLIST is empty; auto-dispatch refuses to act on any area.",
      remediation:
        "Set AIOS_AGENT_AUTODISPATCH_AREA_ALLOWLIST to a CSV of allowlisted areas.",
      envRefs: ["AIOS_AGENT_AUTODISPATCH_AREA_ALLOWLIST"],
      expectedFormat:
        "CSV of CompanyBrainArea values: strategy, development, operations, product, marketing, sales, finance, people, customer, platform",
      exampleValue: "development,platform",
      docsLink: "WORKFLOW.md#auto-dispatch-env-vars",
    });
    blockReasons.push("autodispatch_area_allowlist_empty");
    setBlock("blocked_area");
  } else if (!config.areaAllowlist.includes(args.workItem.area)) {
    gates.push({
      key: "area_allowed",
      title: "Area allowlisted for auto-dispatch",
      status: "failed",
      detail: `WorkItem.area=${args.workItem.area} ∉ allowlist=[${config.areaAllowlist.join(",")}]`,
      remediation: `Add ${args.workItem.area} to AIOS_AGENT_AUTODISPATCH_AREA_ALLOWLIST or pick a different WorkItem.`,
      envRefs: ["AIOS_AGENT_AUTODISPATCH_AREA_ALLOWLIST"],
      expectedFormat: "CSV of CompanyBrainArea values",
      exampleValue: [...config.areaAllowlist, args.workItem.area].join(","),
      docsLink: "WORKFLOW.md#auto-dispatch-env-vars",
    });
    blockReasons.push("autodispatch_area_not_allowed");
    setBlock("blocked_area");
  } else {
    gates.push({
      key: "area_allowed",
      title: "Area allowlisted for auto-dispatch",
      status: "passed",
      detail: `WorkItem.area=${args.workItem.area} ∈ allowlist`,
    });
    satisfiedGates.push("area_allowed");
  }

  // 5. Risk class — must be A when requireRiskA=true
  if (!args.workItem) {
    gates.push({
      key: "risk_class_allowed",
      title: "Risk class allowed",
      status: "warn",
      detail:
        "No WorkItem context provided; cannot evaluate risk class gate.",
    });
  } else if (config.requireRiskA && args.workItem.riskClass !== "A") {
    gates.push({
      key: "risk_class_allowed",
      title: "Risk class allowed",
      status: "failed",
      detail: `requireRiskA=true and WorkItem.riskClass=${args.workItem.riskClass} (need A).`,
      remediation:
        "Reduce risk class to A with documented rationale, or disable requireRiskA after independent review.",
      envRefs: ["AIOS_AGENT_AUTODISPATCH_REQUIRE_RISK_A"],
      expectedFormat: "boolean string (default 'true' enforces Risk A only; set 'false' to allow Risk B)",
      exampleValue: "false",
      docsLink: "WORKFLOW.md#auto-dispatch-env-vars",
    });
    blockReasons.push("autodispatch_risk_not_a");
    setBlock("blocked_risk");
  } else if (
    args.workItem.riskClass === "C" ||
    args.workItem.riskClass === "unknown"
  ) {
    gates.push({
      key: "risk_class_allowed",
      title: "Risk class allowed",
      status: "failed",
      detail: `WorkItem.riskClass=${args.workItem.riskClass} blocked by Writeback Policy Matrix.`,
      remediation: "Refactor to Risk A or B with HITL approval and audit.",
      docsLink: "docs/decisions/writeback-policy-matrix.md",
    });
    blockReasons.push("autodispatch_risk_blocked");
    setBlock("blocked_risk");
  } else {
    gates.push({
      key: "risk_class_allowed",
      title: "Risk class allowed",
      status: "passed",
      detail: `riskClass=${args.workItem.riskClass}; requireRiskA=${config.requireRiskA}`,
    });
    satisfiedGates.push("risk_class_allowed");
  }

  // 6. WorkItem status + not-blocked + non-destructive label heuristic
  if (!args.workItem) {
    gates.push({
      key: "work_item_eligible",
      title: "WorkItem eligible for auto-dispatch",
      status: "warn",
      detail: "No WorkItem context provided.",
    });
  } else {
    const allowedStatuses = ["new", "triage", "planned", "in_progress"];
    const destructiveLabelTokens = [
      "deploy",
      "merge",
      "release",
      "delete",
      "destructive",
      "hotfix",
    ];
    const labels = args.workItem.labels ?? [];
    const hasDestructive = labels.some((label) =>
      destructiveLabelTokens.some((token) =>
        label.toLowerCase().includes(token)
      )
    );
    if (!allowedStatuses.includes(args.workItem.status)) {
      gates.push({
        key: "work_item_eligible",
        title: "WorkItem eligible for auto-dispatch",
        status: "failed",
        detail: `WorkItem.status=${args.workItem.status} ∉ allowedStatuses=[${allowedStatuses.join(",")}]`,
        remediation:
          "Pick a WorkItem in new/triage/planned/in_progress before auto-dispatching.",
      });
      blockReasons.push("autodispatch_work_item_status_invalid");
      setBlock("blocked_work_item");
    } else if (args.workItem.blockedReason) {
      gates.push({
        key: "work_item_eligible",
        title: "WorkItem eligible for auto-dispatch",
        status: "failed",
        detail: `WorkItem.blockedReason="${args.workItem.blockedReason.slice(0, 120)}"`,
        remediation: "Resolve the blocker before auto-dispatch.",
      });
      blockReasons.push("autodispatch_work_item_blocked");
      setBlock("blocked_work_item");
    } else if (hasDestructive) {
      gates.push({
        key: "work_item_eligible",
        title: "WorkItem eligible for auto-dispatch",
        status: "failed",
        detail: `WorkItem.labels contains destructive token: ${labels.filter((l) => destructiveLabelTokens.some((t) => l.toLowerCase().includes(t))).join(",")}`,
        remediation:
          "Remove destructive labels or run manually with full HITL gate.",
      });
      blockReasons.push("autodispatch_work_item_destructive");
      setBlock("blocked_work_item");
    } else {
      gates.push({
        key: "work_item_eligible",
        title: "WorkItem eligible for auto-dispatch",
        status: "passed",
        detail: `status=${args.workItem.status}; not blocked; no destructive labels`,
      });
      satisfiedGates.push("work_item_eligible");
    }
  }

  // 7. Manual runner policy chain
  let manualRunnerPolicyDecision: RunnerPolicyDecision | null = null;
  if (args.workItem) {
    const syntheticRun = {
      id: `autodispatch-eligibility-${args.workItem.id}`,
      workItemId: args.workItem.id,
      workflowRunId: null,
      agentContextId: null,
      sourceId: args.workItem.sourceId ?? null,
      repo,
      branch: null,
      workspaceRef: null,
      runnerType: "claude_code" as AgentRunRunnerType,
      status: "queued" as AgentRunStatus,
      claimState: "unclaimed" as const,
      attempt: 0,
      startedAt: null,
      finishedAt: null,
      errorSummary: null,
      prUrl: null,
      externalRunRef: null,
      tokensInput: null,
      tokensOutput: null,
      tokensTotal: null,
      costUsd: null,
      agentSessionId: null,
      agentThreadId: null,
      area: args.workItem.area,
      riskClass: args.workItem.riskClass,
      actionPolicy: "observe_only" as const,
      visibility: args.workItem.visibility ?? "internal",
      pid: null,
      executionRef: null,
      lastLogAt: null,
      lastLogLineCount: null,
      metadata: null,
      auditTrail: [],
      provenance: null,
      createdAt: now(),
      updatedAt: now(),
    } as unknown as typeof cbAgentRuns.$inferSelect;
    // Resolve effective command for the chained manual policy. Profile
    // selection takes precedence over commandOverride.
    let effectiveCommandOverride: string | undefined =
      config.commandOverride ?? undefined;
    if (config.profileId) {
      const profile = getRunnerProfile(config.profileId);
      if (profile) {
        effectiveCommandOverride = profile.command;
      }
    }
    try {
      const policy = evaluateRunnerPolicy({
        agentRun: syntheticRun,
        request: {
          intent: "real_execution",
          actor: args.actorOverride ?? config.defaultActor,
          rationale: args.rationaleOverride ?? config.defaultRationale,
          commandOverride: effectiveCommandOverride,
        },
      });
      manualRunnerPolicyDecision = policy.decision;
      if (policy.decision === "allowed_real_execution") {
        gates.push({
          key: "manual_runner_policy_passed",
          title: "Manual runner policy passes",
          status: "passed",
          detail: `evaluateRunnerPolicy=${policy.decision}`,
        });
        satisfiedGates.push("manual_runner_policy_passed");
      } else {
        // Pull blocked manual gates so operators can see the exact env var
        // they need to fix without re-evaluating /policy/evaluate.
        const failedManualGates = policy.gates
          .filter((g) => g.status === "failed")
          .map((g) => g.key);
        const manualEnvHint = (() => {
          const hints: string[] = [];
          if (policy.blockReasons.includes("workspace_not_allowlisted")) {
            hints.push(
              "AIOS_AGENT_WORKSPACE_ALLOWLIST=<owner/name> (CSV of GitHub repo identifiers, NOT filesystem paths)"
            );
          }
          if (policy.blockReasons.includes("command_not_allowlisted")) {
            hints.push(
              "AIOS_AGENT_RUNNER_COMMAND_ALLOWLIST=claude,echo,true (CSV of allowed binaries; must include WORKFLOW.md agent.command)"
            );
          }
          if (policy.blockReasons.includes("runner_disabled")) {
            hints.push("AIOS_AGENT_RUNNER_ENABLED=true (master switch for manual runner)");
          }
          if (policy.blockReasons.includes("repo_not_allowlisted")) {
            hints.push(
              "AIOS_AGENT_RUNNER_REPO_ALLOWLIST=<owner/name> (CSV mirrors AUTODISPATCH_REPO_ALLOWLIST)"
            );
          }
          return hints;
        })();
        gates.push({
          key: "manual_runner_policy_passed",
          title: "Manual runner policy passes",
          status: "failed",
          detail: `evaluateRunnerPolicy=${policy.decision}; satisfiedGates=${policy.gates.filter((g) => g.status === "passed").length}; manualBlockReasons=[${policy.blockReasons.join(",")}]; failedGates=[${failedManualGates.join(",")}]`,
          remediation:
            manualEnvHint.length > 0
              ? `Fix manual runner policy first: ${manualEnvHint.join("; ")}`
              : "Fix manual runner policy gates first; auto-dispatch chains the same policy. Run POST /agent-runs/:id/policy/evaluate for full gate detail.",
          envRefs: [
            "AIOS_AGENT_RUNNER_ENABLED",
            "AIOS_AGENT_RUNNER_REPO_ALLOWLIST",
            "AIOS_AGENT_RUNNER_COMMAND_ALLOWLIST",
            "AIOS_AGENT_WORKSPACE_ALLOWLIST",
          ],
          expectedFormat:
            "All four manual runner env vars must be set; AIOS_AGENT_WORKSPACE_ALLOWLIST takes repo identifiers (owner/name), NOT filesystem paths",
          exampleValue:
            "AIOS_AGENT_WORKSPACE_ALLOWLIST=" + (repo ?? "antonio-mello-ai/crewdock"),
          docsLink: "WORKFLOW.md#manual-runner-env-vars",
        });
        blockReasons.push("autodispatch_runner_policy_blocked");
        setBlock("blocked_runner_policy");
      }
    } catch (err) {
      gates.push({
        key: "manual_runner_policy_passed",
        title: "Manual runner policy passes",
        status: "failed",
        detail: `evaluateRunnerPolicy threw: ${err instanceof Error ? err.message : "unknown error"}`,
      });
      blockReasons.push("autodispatch_runner_policy_threw");
      setBlock("blocked_runner_policy");
    }
  } else {
    gates.push({
      key: "manual_runner_policy_passed",
      title: "Manual runner policy passes",
      status: "warn",
      detail: "No WorkItem context provided; cannot chain manual runner policy.",
    });
  }

  // 8. Concurrency cap
  if (runtime.activeAgentRunCount >= config.maxConcurrency) {
    gates.push({
      key: "concurrency_under_limit",
      title: "Concurrency under limit",
      status: "failed",
      detail: `activeAgentRunCount=${runtime.activeAgentRunCount} >= maxConcurrency=${config.maxConcurrency}`,
      remediation:
        "Wait for current AgentRuns to terminate or raise AIOS_AGENT_AUTODISPATCH_MAX_CONCURRENCY.",
    });
    blockReasons.push("autodispatch_concurrency_full");
    setBlock("blocked_concurrency");
  } else {
    gates.push({
      key: "concurrency_under_limit",
      title: "Concurrency under limit",
      status: "passed",
      detail: `active=${runtime.activeAgentRunCount}/${config.maxConcurrency}`,
    });
    satisfiedGates.push("concurrency_under_limit");
  }

  // 9. Cooldown
  if (runtime.cooldownRemainingMs > 0) {
    gates.push({
      key: "cooldown_elapsed",
      title: "Cooldown elapsed",
      status: "failed",
      detail: `cooldownRemainingMs=${runtime.cooldownRemainingMs}; lastAutoDispatchAt=${runtime.lastAutoDispatchAt}`,
      remediation: `Wait ${Math.ceil(runtime.cooldownRemainingMs / 1000)}s before next auto-dispatch.`,
    });
    blockReasons.push("autodispatch_cooldown_active");
    setBlock("blocked_cooldown");
  } else {
    gates.push({
      key: "cooldown_elapsed",
      title: "Cooldown elapsed",
      status: "passed",
      detail: `cooldownMs=${config.cooldownMs}; lastAutoDispatchAt=${runtime.lastAutoDispatchAt ?? "never"}`,
    });
    satisfiedGates.push("cooldown_elapsed");
  }

  // 10. Token budget
  if (runtime.tokensAvailableInWindow <= 0) {
    gates.push({
      key: "token_budget_remaining",
      title: "Token budget remaining",
      status: "failed",
      detail: `tokensSpentInWindow=${runtime.tokensSpentInWindow} >= tokenBudget=${config.tokenBudget}`,
      remediation:
        "Wait for cooldown window to roll over or raise AIOS_AGENT_AUTODISPATCH_TOKEN_BUDGET.",
    });
    blockReasons.push("autodispatch_token_budget_exhausted");
    setBlock("blocked_token_budget");
  } else {
    gates.push({
      key: "token_budget_remaining",
      title: "Token budget remaining",
      status: "passed",
      detail: `available=${runtime.tokensAvailableInWindow}/${config.tokenBudget}`,
    });
    satisfiedGates.push("token_budget_remaining");
  }

  // 11. Actor + rationale
  const effectiveActor = (args.actorOverride ?? config.defaultActor).trim();
  const effectiveRationale = (args.rationaleOverride ?? config.defaultRationale).trim();
  if (!effectiveActor || !effectiveRationale) {
    gates.push({
      key: "actor_rationale_present",
      title: "Actor + rationale present",
      status: "failed",
      detail: `actor="${effectiveActor}"; rationale length=${effectiveRationale.length}`,
      remediation:
        "Set AIOS_AGENT_AUTODISPATCH_DEFAULT_ACTOR and AIOS_AGENT_AUTODISPATCH_DEFAULT_RATIONALE.",
    });
    blockReasons.push("autodispatch_actor_or_rationale_missing");
    setBlock("blocked_actor_rationale");
  } else {
    gates.push({
      key: "actor_rationale_present",
      title: "Actor + rationale present",
      status: "passed",
      detail: `actor=${effectiveActor}; rationale=${effectiveRationale.slice(0, 80)}`,
    });
    satisfiedGates.push("actor_rationale_present");
  }

  // 12. Runner profile (optional — only enforced when profileId is set).
  if (config.profileId) {
    const profileEval = evaluateRunnerProfile({
      profileId: config.profileId,
      repo,
      area: args.workItem?.area ?? null,
      riskClass: args.workItem?.riskClass ?? null,
    });
    if (!profileEval.available) {
      gates.push({
        key: "runner_profile_available",
        title: "Runner profile available",
        status: "failed",
        detail: profileEval.detail,
        remediation: profileEval.enabledEnvVar
          ? `Set ${profileEval.enabledEnvVar}=true to enable this profile, or pick a different AIOS_AGENT_AUTODISPATCH_PROFILE_ID.`
          : "Pick a registered, enabled profile via AIOS_AGENT_AUTODISPATCH_PROFILE_ID.",
        envRefs: profileEval.enabledEnvVar
          ? [
              "AIOS_AGENT_AUTODISPATCH_PROFILE_ID",
              profileEval.enabledEnvVar,
            ]
          : ["AIOS_AGENT_AUTODISPATCH_PROFILE_ID"],
        expectedFormat: "Registered runner profile id (see GET /runner-profiles)",
        exampleValue: "noop-echo",
        docsLink: "WORKFLOW.md#runner-profile-registry",
      });
      blockReasons.push(`autodispatch_profile_${profileEval.reason ?? "unavailable"}`);
      setBlock("blocked_runner_policy");
    } else {
      gates.push({
        key: "runner_profile_available",
        title: "Runner profile available",
        status: "passed",
        detail: profileEval.detail,
      });
      satisfiedGates.push("runner_profile_available");
    }
  } else {
    gates.push({
      key: "runner_profile_available",
      title: "Runner profile available",
      status: "warn",
      detail:
        "No AIOS_AGENT_AUTODISPATCH_PROFILE_ID set; falling back to commandOverride or WORKFLOW.md agent.command. Set a profile id for typed runner selection.",
      envRefs: ["AIOS_AGENT_AUTODISPATCH_PROFILE_ID"],
      expectedFormat: "Registered runner profile id (see GET /runner-profiles)",
      exampleValue: "noop-echo",
      docsLink: "WORKFLOW.md#runner-profile-registry",
    });
  }

  const decision: AutoDispatchDecision = firstBlockDecision ?? "eligible";
  const eligible = decision === "eligible" && !blockReasons.length;

  return {
    generatedAt,
    agentRunSuggestionId: args.suggestion?.id ?? null,
    workItemId: args.workItem?.id ?? null,
    decision,
    eligible,
    gates,
    blockReasons,
    satisfiedGates,
    config,
    runtime,
    manualRunnerPolicyDecision,
  };
}

function buildAutoDispatchPolicySummary(): AutoDispatchPolicySummary {
  const config = autoDispatchConfig();
  const runtime = buildAutoDispatchRuntimeState(config);

  // Optional eligibilityPreview: top suggestion if present
  let eligibilityPreview: AutoDispatchEligibility | null = null;
  try {
    const db = getDb();
    const top = db
      .select()
      .from(cbAgentRunSuggestions)
      .where(eq(cbAgentRunSuggestions.status, "active"))
      .orderBy(desc(cbAgentRunSuggestions.createdAt))
      .limit(1)
      .get() as AgentRunSuggestion | undefined;
    if (top) {
      const data = listAll();
      const wi = (data.workItems as WorkItem[]).find((w) => w.id === top.workItemId) ?? null;
      eligibilityPreview = evaluateAutoDispatchEligibility({
        workItem: wi,
        suggestion: top,
      });
    } else {
      // Global preview without WorkItem context (only env gates evaluated).
      eligibilityPreview = evaluateAutoDispatchEligibility({
        workItem: null,
        suggestion: null,
      });
    }
  } catch (err) {
    console.error("[company-brain] buildAutoDispatchPolicySummary preview failed", err);
  }

  return {
    generatedAt: now(),
    config,
    runtime,
    eligibilityPreview,
  };
}

app.get("/agent-runs/:id/patch-packet", (c) => {
  const db = getDb();
  const id = c.req.param("id");
  const persistFlag = c.req.query("persist") === "true";
  const run = db
    .select()
    .from(cbAgentRuns)
    .where(eq(cbAgentRuns.id, id))
    .get() as typeof cbAgentRuns.$inferSelect | undefined;
  if (!run) {
    return c.json({ error: "not_found", message: "agent run not found" }, 404);
  }
  const packet = collectAgentRunPatchPacket({ agentRun: run });
  if (persistFlag) {
    try {
      const { artifactId } = persistAgentRunPatchPacket({ packet, agentRun: run });
      packet.artifactId = artifactId;
    } catch (err) {
      console.error("[company-brain] persistAgentRunPatchPacket failed", err);
    }
  }
  const response: CollectAgentRunPatchPacketResponse = {
    generatedAt: now(),
    packet,
  };
  return c.json({ data: response });
});

function githubPrWritebackEnabled(): boolean {
  return process.env.AIOS_AGENT_GITHUB_PR_WRITEBACK_ENABLED === "true";
}

function githubPrWritebackRepoAllowlist(): string[] {
  return csvEnv(process.env.AIOS_AGENT_GITHUB_PR_WRITEBACK_REPO_ALLOWLIST);
}

function autoDispatchPrProposalEnabled(): boolean {
  return process.env.AIOS_AGENT_AUTODISPATCH_PR_PROPOSAL_ENABLED === "true";
}

function autoDispatchPrProposalRepoAllowlist(): string[] {
  const explicit = csvEnv(process.env.AIOS_AGENT_AUTODISPATCH_PR_PROPOSAL_REPO_ALLOWLIST);
  return explicit.length ? explicit : csvEnv(process.env.AIOS_AGENT_AUTODISPATCH_REPO_ALLOWLIST);
}

const AIOS_PR_MARKER_PREFIX = "<!-- aios:proposalId=";

function buildAiosPrMarker(args: {
  proposalId: string;
  agentRunId: string;
  patchPacketSignature: string;
}): string {
  return `${AIOS_PR_MARKER_PREFIX}${args.proposalId}:agentRunId=${args.agentRunId}:sig=${args.patchPacketSignature.slice(0, 12)} -->`;
}

function parseGitHubPrNumber(value: string | null | undefined): number | null {
  if (!value) return null;
  const match = value.match(/\/pull\/(\d+)(?:\D|$)/) ?? value.match(/^(\d+)$/);
  if (!match) return null;
  const parsed = Number(match[1]);
  return Number.isFinite(parsed) ? parsed : null;
}

function iterationGate(
  key: string,
  status: GitHubPrIterationGate["status"],
  detail: string
): GitHubPrIterationGate {
  return { key, status, detail };
}

async function buildGitHubPrIterationPlan(args: {
  workItemId: string | null;
  repo: string;
  baseBranch: string;
}): Promise<GitHubPrIterationPlan> {
  const openNew = (
    rationale: string,
    gates: GitHubPrIterationGate[] = []
  ): GitHubPrIterationPlan => ({
    decision: "open_new_pr",
    rationale,
    existingProposalId: null,
    existingPrNumber: null,
    existingPrUrl: null,
    existingSourceBranch: null,
    existingBaseBranch: null,
    existingState: null,
    existingMerged: null,
    markerMatched: null,
    gates,
  });

  if (!args.workItemId) {
    return openNew("No WorkItem linked to AgentRun; opening a new PR proposal.");
  }

  const candidates = (getDb()
    .select()
    .from(cbExternalActionProposals)
    .all() as ExternalActionProposal[])
    .filter((proposal) => proposal.workItemId === args.workItemId)
    .filter((proposal) => proposal.actionType === "github_pr_create")
    .filter((proposal) => Boolean(proposal.externalUrl || proposal.externalId))
    .sort((a, b) => b.updatedAt - a.updatedAt);
  const candidate = candidates[0] ?? null;
  if (!candidate) {
    return openNew("No executed github_pr_create proposal found for this WorkItem.");
  }

  const candidatePayload = candidate.payload as unknown as Partial<GitHubPrProposalPayload>;
  const prNumber =
    parseGitHubPrNumber(candidate.externalUrl) ??
    parseGitHubPrNumber(candidate.externalId);
  const gates: GitHubPrIterationGate[] = [];
  const candidateRepo = typeof candidatePayload.repo === "string" ? candidatePayload.repo : null;
  const candidateBase =
    typeof candidatePayload.baseBranch === "string" ? candidatePayload.baseBranch : null;
  const candidateSource =
    typeof candidatePayload.sourceBranch === "string" ? candidatePayload.sourceBranch : null;
  gates.push(
    iterationGate(
      "same_repo",
      candidateRepo === args.repo ? "passed" : "failed",
      `candidate.repo=${candidateRepo ?? "(missing)"}; current.repo=${args.repo}`
    )
  );
  gates.push(
    iterationGate(
      "same_base_branch",
      candidateBase === args.baseBranch ? "passed" : "failed",
      `candidate.base=${candidateBase ?? "(missing)"}; current.base=${args.baseBranch}`
    )
  );
  gates.push(
    iterationGate(
      "pr_number_present",
      prNumber ? "passed" : "failed",
      `candidate.externalId=${candidate.externalId ?? "-"}; externalUrl=${candidate.externalUrl ?? "-"}`
    )
  );
  if (!candidateRepo || candidateRepo !== args.repo || !candidateBase || candidateBase !== args.baseBranch || !candidateSource || !prNumber) {
    return {
      decision: "open_new_pr",
      rationale:
        "Existing proposal is not eligible for same-PR iteration; opening a new PR proposal.",
      existingProposalId: candidate.id,
      existingPrNumber: prNumber,
      existingPrUrl: candidate.externalUrl,
      existingSourceBranch: candidateSource,
      existingBaseBranch: candidateBase,
      existingState: null,
      existingMerged: null,
      markerMatched: null,
      gates,
    };
  }

  let existingState: string | null = null;
  let existingMerged: boolean | null = null;
  let markerMatched: boolean | null = null;
  try {
    const parsed = parseGitHubRepo(args.repo);
    const pr = await githubApiRequest<{
      number: number;
      html_url: string;
      state: string;
      merged: boolean;
      body: string | null;
      head: { ref: string };
      base: { ref: string };
    }>(`/repos/${parsed.owner}/${parsed.name}/pulls/${prNumber}`, {
      requireToken: true,
    });
    existingState = pr.state;
    existingMerged = Boolean(pr.merged);
    markerMatched =
      (pr.body ?? "").includes(`aios:proposalId=${candidate.id}`) ||
      (pr.body ?? "").includes(AIOS_PR_MARKER_PREFIX);
    gates.push(
      iterationGate(
        "non_merged_open_pr",
        pr.state === "open" && !pr.merged ? "passed" : "failed",
        `state=${pr.state}; merged=${pr.merged}`
      )
    );
    gates.push(
      iterationGate(
        "marker_matched",
        markerMatched ? "passed" : "failed",
        markerMatched
          ? "AIOS marker found in existing PR body."
          : "AIOS marker missing from existing PR body."
      )
    );
    gates.push(
      iterationGate(
        "head_branch_available",
        pr.head.ref === candidateSource ? "passed" : "failed",
        `pr.head=${pr.head.ref}; candidate.sourceBranch=${candidateSource}`
      )
    );
    gates.push(
      iterationGate(
        "base_branch_available",
        pr.base.ref === candidateBase ? "passed" : "failed",
        `pr.base=${pr.base.ref}; candidate.baseBranch=${candidateBase}`
      )
    );
  } catch (err) {
    gates.push(
      iterationGate(
        "github_pr_read",
        "warn",
        `Could not verify existing PR via GitHub API: ${err instanceof Error ? err.message : "unknown"}`
      )
    );
    return {
      decision: "open_new_pr",
      rationale:
        "Existing proposal found, but PR state could not be verified; opening a new PR proposal.",
      existingProposalId: candidate.id,
      existingPrNumber: prNumber,
      existingPrUrl: candidate.externalUrl,
      existingSourceBranch: candidateSource,
      existingBaseBranch: candidateBase,
      existingState,
      existingMerged,
      markerMatched,
      gates,
    };
  }

  const eligible = gates.every((gate) => gate.status !== "failed");
  return {
    decision: eligible ? "update_existing_pr" : "open_new_pr",
    rationale: eligible
      ? "Existing AIOS-authored PR is eligible for same-PR iteration."
      : "Existing PR failed one or more iteration gates; opening a new PR proposal.",
    existingProposalId: candidate.id,
    existingPrNumber: prNumber,
    existingPrUrl: candidate.externalUrl,
    existingSourceBranch: candidateSource,
    existingBaseBranch: candidateBase,
    existingState,
    existingMerged,
    markerMatched,
    gates,
  };
}

function githubPrWritebackTokenInfo(): {
  token: string | null;
  source: "GITHUB_TOKEN" | "GH_TOKEN" | null;
} {
  const githubToken = getSecretEnv("GITHUB_TOKEN");
  if (githubToken) return { token: githubToken, source: "GITHUB_TOKEN" };
  const ghToken = getSecretEnv("GH_TOKEN");
  if (ghToken) return { token: ghToken, source: "GH_TOKEN" };
  return { token: null, source: null };
}

function redactSnippet(value: string | null | undefined, secret?: string | null): string | null {
  if (!value) return null;
  const withoutSecret = secret ? value.split(secret).join("[REDACTED]") : value;
  return withoutSecret.trim().slice(0, 500) || null;
}

function preflightGate(args: {
  key: string;
  title: string;
  status: GitHubPrWritebackPreflightGate["status"];
  detail: string;
  remediation?: string | null;
  metadata?: Record<string, unknown> | null;
}): GitHubPrWritebackPreflightGate {
  return {
    key: args.key,
    title: args.title,
    status: args.status,
    detail: args.detail,
    remediation: args.remediation ?? null,
    metadata: args.metadata ?? null,
  };
}

function persistGitHubPrWritebackPreflightArtifact(args: {
  proposal: ExternalActionProposal;
  preflight: Omit<GitHubPrWritebackPreflightResponse, "proposal" | "artifactId">;
}): string {
  const db = getDb();
  const timestamp = args.preflight.generatedAt;
  const visibility = args.proposal.visibility;
  const sourceId = ensureSessionResultsSource("development", visibility, timestamp);
  const artifactId = nanoid(12);
  const rawRef = `aios://github-pr-writeback-preflight/${args.proposal.id}/${timestamp}`;
  const summary = [
    `status=${args.preflight.status}`,
    `repo=${args.preflight.repo ?? "-"}`,
    `sourceBranch=${args.preflight.sourceBranch ?? "-"}`,
    `baseBranch=${args.preflight.baseBranch ?? "-"}`,
    `tokenSource=${args.preflight.tokenSource ?? "-"}`,
    `pushProbe=${args.preflight.pushProbe.status}`,
  ].join(" | ");
  const artifact: Artifact = {
    id: artifactId,
    sourceId,
    artifactType: "session_result",
    area: "development",
    title: `GitHub PR writeback preflight: ${args.proposal.id}`.slice(0, 240),
    summary,
    contentRef: null,
    rawRef,
    author: "company-brain:github-pr-writeback-preflight",
    occurredAt: timestamp,
    ingestedAt: timestamp,
    hash: createHash("sha256")
      .update(JSON.stringify(args.preflight))
      .digest("hex"),
    visibility,
    provenance: {
      sourceId,
      rawRef,
      artifactId,
      createdFrom: "company_brain:github_pr_writeback_preflight",
      confidence: 1,
      extractedAt: timestamp,
      humanReviewStatus: "pending",
      visibility,
      notes: `proposal=${args.proposal.id}; status=${args.preflight.status}; pushProbe=${args.preflight.pushProbe.status}`,
    },
    humanReviewStatus: "pending",
    confidence: 1,
    metadata: {
      kind: "github_pr_writeback_preflight",
      proposalId: args.proposal.id,
      preflight: args.preflight,
    },
  };
  db.insert(cbArtifacts).values(artifact as never).run();
  return artifactId;
}

async function buildGitHubPrWritebackPreflight(args: {
  proposal: ExternalActionProposal;
  actor: string;
  rationale: string;
  pushProbe: boolean;
  persistArtifact: boolean;
}): Promise<GitHubPrWritebackPreflightResponse> {
  const db = getDb();
  const generatedAt = now();
  const proposal = args.proposal;
  const payload = proposal.payload as unknown as Partial<GitHubPrProposalPayload>;
  const repo = typeof payload.repo === "string" ? payload.repo : null;
  const sourceBranch =
    typeof payload.sourceBranch === "string" ? payload.sourceBranch : null;
  const baseBranch =
    typeof payload.baseBranch === "string" ? payload.baseBranch : null;
  const agentRunId =
    typeof payload.agentRunId === "string" ? payload.agentRunId : null;
  const repoAllowlist = githubPrWritebackRepoAllowlist();
  const tokenInfo = githubPrWritebackTokenInfo();
  const gates: GitHubPrWritebackPreflightGate[] = [];

  gates.push(
    preflightGate({
      key: "action_type",
      title: "Proposal action type",
      status: proposal.actionType === "github_pr_create" ? "passed" : "failed",
      detail: `proposal.actionType=${proposal.actionType}`,
      remediation: "Use a github_pr_create ExternalActionProposal.",
    })
  );

  const payloadOk = Boolean(repo && sourceBranch && baseBranch && agentRunId);
  gates.push(
    preflightGate({
      key: "payload_shape",
      title: "PR payload shape",
      status: payloadOk ? "passed" : "failed",
      detail: payloadOk
        ? `repo=${repo}; source=${sourceBranch}; base=${baseBranch}; agentRun=${agentRunId}`
        : "payload must include repo, sourceBranch, baseBranch and agentRunId",
      remediation: "Regenerate the github_pr_create proposal from an AgentRun patch packet.",
    })
  );

  gates.push(
    preflightGate({
      key: "writeback_enabled",
      title: "GitHub PR writeback master switch",
      status: githubPrWritebackEnabled() ? "passed" : "failed",
      detail: `AIOS_AGENT_GITHUB_PR_WRITEBACK_ENABLED=${process.env.AIOS_AGENT_GITHUB_PR_WRITEBACK_ENABLED ?? "(unset)"}`,
      remediation: "Set AIOS_AGENT_GITHUB_PR_WRITEBACK_ENABLED=true for a controlled run.",
      metadata: {
        envRef: "AIOS_AGENT_GITHUB_PR_WRITEBACK_ENABLED",
        expectedFormat: "boolean string",
        exampleValue: "true",
      },
    })
  );

  gates.push(
    preflightGate({
      key: "repo_allowlist",
      title: "Repository allowlist",
      status: repo && repoAllowlist.includes(repo) ? "passed" : "failed",
      detail: `repo=${repo ?? "(missing)"}; allowlist=[${repoAllowlist.join(",")}]`,
      remediation:
        "Set AIOS_AGENT_GITHUB_PR_WRITEBACK_REPO_ALLOWLIST to the internal owner/name repo.",
      metadata: {
        envRef: "AIOS_AGENT_GITHUB_PR_WRITEBACK_REPO_ALLOWLIST",
        expectedFormat: "CSV of owner/name repositories",
        exampleValue: "antonio-mello-ai/crewdock",
      },
    })
  );

  gates.push(
    preflightGate({
      key: "token_present",
      title: "GitHub token",
      status: tokenInfo.token ? "passed" : "failed",
      detail: tokenInfo.source
        ? `using ${tokenInfo.source}; token value redacted`
        : "GITHUB_TOKEN/GH_TOKEN is not configured",
      remediation:
        "Configure the existing daemon GitHub token as GITHUB_TOKEN or GH_TOKEN.",
      metadata: {
        tokenSource: tokenInfo.source,
        tokenPresent: Boolean(tokenInfo.token),
      },
    })
  );

  gates.push(
    preflightGate({
      key: "auth_scheme",
      title: "Git push auth scheme",
      status: "passed",
      detail:
        "GitHub API calls use Bearer, but git push uses https://x-access-token:<token>@github.com/owner/repo.git.",
      remediation: null,
      metadata: {
        api: "bearer",
        gitPush: "x-access-token-url",
      },
    })
  );

  let owner: string | null = null;
  let name: string | null = null;
  let baseBranchVisible: boolean | null = null;
  if (repo) {
    try {
      const parsed = parseGitHubRepo(repo);
      owner = parsed.owner;
      name = parsed.name;
    } catch (err) {
      gates.push(
        preflightGate({
          key: "repo_parse",
          title: "Repository parse",
          status: "failed",
          detail: err instanceof Error ? err.message : "repo parse failed",
          remediation: "Use owner/name format.",
        })
      );
    }
  }

  if (owner && name && baseBranch && tokenInfo.token) {
    try {
      await githubApiRequest<{ name: string }>(
        `/repos/${owner}/${name}/branches/${encodeURIComponent(baseBranch)}`,
        { requireToken: true }
      );
      baseBranchVisible = true;
      gates.push(
        preflightGate({
          key: "base_branch_visible",
          title: "Base branch visibility",
          status: "passed",
          detail: `baseBranch=${baseBranch} is visible via GitHub API`,
        })
      );
    } catch (err) {
      baseBranchVisible = false;
      gates.push(
        preflightGate({
          key: "base_branch_visible",
          title: "Base branch visibility",
          status: "failed",
          detail: err instanceof Error ? err.message : "base branch lookup failed",
          remediation: "Check token repo access and baseBranch.",
        })
      );
    }
  } else {
    gates.push(
      preflightGate({
        key: "base_branch_visible",
        title: "Base branch visibility",
        status: "warn",
        detail: "Skipped until repo, baseBranch and token are available.",
      })
    );
  }

  let workspacePath: string | null = null;
  if (agentRunId) {
    const run = db
      .select()
      .from(cbAgentRuns)
      .where(eq(cbAgentRuns.id, agentRunId))
      .get() as typeof cbAgentRuns.$inferSelect | undefined;
    workspacePath = run?.workspaceRef ?? null;
  }
  const workspaceReady = Boolean(workspacePath && existsSync(workspacePath));
  gates.push(
    preflightGate({
      key: "workspace_ready",
      title: "AgentRun workspace",
      status: workspaceReady ? "passed" : "failed",
      detail: workspaceReady
        ? `workspaceRef exists at ${workspacePath}`
        : agentRunId
          ? "AgentRun workspaceRef is missing or does not exist on this host"
          : "payload.agentRunId is missing",
      remediation:
        "Prepare or restore the AgentRun workspace before PR writeback.",
      metadata: {
        agentRunId,
        workspacePath,
      },
    })
  );
  const safePushProbePossible = Boolean(
    owner &&
      name &&
      sourceBranch &&
      tokenInfo.token &&
      repo &&
      repoAllowlist.includes(repo) &&
      githubPrWritebackEnabled() &&
      workspaceReady
  );

  const pushProbe: GitHubPrWritebackPushProbe = {
    requested: args.pushProbe,
    attempted: false,
    status: args.pushProbe ? "skipped" : "not_requested",
    ref: null,
    commandSummary: null,
    stdoutSnippet: null,
    stderrSnippet: null,
    errorSummary: args.pushProbe
      ? "pushProbe requested but required gates were not all ready"
      : null,
  };

  if (args.pushProbe && safePushProbePossible && owner && name && tokenInfo.token && workspacePath) {
    const ref = `refs/heads/aios-preflight/${proposal.id}-${generatedAt}`;
    const pushUrl = `https://x-access-token:${tokenInfo.token}@github.com/${owner}/${name}.git`;
    const result = spawnSync(
      "git",
      ["-C", workspacePath, "push", "--dry-run", pushUrl, `HEAD:${ref}`],
      { encoding: "utf-8" }
    );
    pushProbe.requested = true;
    pushProbe.attempted = true;
    pushProbe.ref = ref;
    pushProbe.commandSummary = `git push --dry-run https://x-access-token:[REDACTED]@github.com/${owner}/${name}.git HEAD:${ref}`;
    pushProbe.stdoutSnippet = redactSnippet(result.stdout, tokenInfo.token);
    pushProbe.stderrSnippet = redactSnippet(result.stderr, tokenInfo.token);
    pushProbe.status = result.status === 0 ? "passed" : "failed";
    pushProbe.errorSummary =
      result.status === 0
        ? null
        : (pushProbe.stderrSnippet ?? pushProbe.stdoutSnippet ?? "git push --dry-run failed");
  }

  gates.push(
    preflightGate({
      key: "push_probe",
      title: "Safe push probe",
      status:
        pushProbe.status === "passed" || pushProbe.status === "not_requested"
          ? "passed"
          : pushProbe.status === "skipped"
            ? "warn"
            : "failed",
      detail:
        pushProbe.status === "not_requested"
          ? "Not requested. Set pushProbe=true to run git push --dry-run against a temporary aios-preflight ref."
          : pushProbe.status === "skipped"
            ? pushProbe.errorSummary ?? "Skipped"
            : pushProbe.status === "passed"
              ? `Dry-run push accepted for ${pushProbe.ref}`
              : pushProbe.errorSummary ?? "Dry-run push failed",
      remediation:
        pushProbe.status === "failed"
          ? "Check token push permissions, repo allowlist and workspace branch."
          : null,
      metadata: {
        safePushProbePossible,
        ref: pushProbe.ref,
      },
    })
  );

  const failedGates = gates.filter((gate) => gate.status === "failed");
  const ready = failedGates.length === 0;
  const preflightWithoutArtifact: Omit<
    GitHubPrWritebackPreflightResponse,
    "proposal" | "artifactId"
  > = {
    generatedAt,
    proposalId: proposal.id,
    status: ready ? "ready" : "blocked",
    ready,
    repo,
    sourceBranch,
    baseBranch,
    workspacePath,
    workspaceReady,
    tokenSource: tokenInfo.source,
    tokenPresent: Boolean(tokenInfo.token),
    authScheme: {
      api: "bearer",
      gitPush: "x-access-token-url",
    },
    remoteUrlPattern: owner && name
      ? `https://x-access-token:[REDACTED]@github.com/${owner}/${name}.git`
      : repo
        ? "https://x-access-token:[REDACTED]@github.com/<owner>/<repo>.git"
        : null,
    repoAllowlist,
    baseBranchVisible,
    safePushProbePossible,
    pushProbe,
    dryRunLimitations: [
      "git push --dry-run validates auth/ref negotiation but does not create a branch.",
      "preflight does not open, merge or deploy a pull request.",
      "a ready preflight can still fail later if the workspace changes before execution.",
    ],
    gates,
  };

  const artifactId = args.persistArtifact
    ? persistGitHubPrWritebackPreflightArtifact({
        proposal,
        preflight: preflightWithoutArtifact,
      })
    : null;

  const audit = (proposal.auditTrail ?? []).concat([
    {
      at: generatedAt,
      actor: args.actor,
      event: "github_pr_writeback_preflight_checked",
      note: args.rationale,
      metadata: {
        status: preflightWithoutArtifact.status,
        ready,
        repo,
        sourceBranch,
        baseBranch,
        tokenSource: tokenInfo.source,
        pushProbe,
        failedGateKeys: failedGates.map((gate) => gate.key),
        artifactId,
        request: {
          payloadHash: currentPayloadHash(proposal),
          destinationRef: proposal.destinationRef,
          idempotencyKey: proposal.idempotencyKey,
        },
      },
    },
  ]);
  db.update(cbExternalActionProposals)
    .set({
      auditTrail: audit,
      errorSummary: ready ? null : `preflight blocked: ${failedGates.map((g) => g.key).join(",")}`,
      updatedAt: generatedAt,
    } as never)
    .where(eq(cbExternalActionProposals.id, proposal.id))
    .run();
  const refreshed = db
    .select()
    .from(cbExternalActionProposals)
    .where(eq(cbExternalActionProposals.id, proposal.id))
    .get() as ExternalActionProposal;

  return {
    ...preflightWithoutArtifact,
    artifactId,
    proposal: refreshed,
  };
}

app.post("/external-action-proposals/:id/github-pr/preflight", async (c) => {
  const id = c.req.param("id");
  const body = (await c.req.json().catch(() => ({}))) as GitHubPrWritebackPreflightRequest;
  const actor = body.actor?.trim();
  const rationale = body.rationale?.trim();
  if (!actor) {
    return c.json({ error: "validation", message: "actor is required" }, 400);
  }
  if (!rationale) {
    return c.json({ error: "validation", message: "rationale is required" }, 400);
  }
  const db = getDb();
  let proposal = db
    .select()
    .from(cbExternalActionProposals)
    .where(eq(cbExternalActionProposals.id, id))
    .get() as ExternalActionProposal | undefined;
  if (!proposal) {
    return c.json({ error: "not_found", message: `proposal ${id} not found` }, 404);
  }
  if (proposal.actionType !== "github_pr_create") {
    return c.json(
      {
        error: "validation",
        message: `proposal.actionType=${proposal.actionType}; expected github_pr_create`,
      },
      400
    );
  }
  const response = await buildGitHubPrWritebackPreflight({
    proposal,
    actor,
    rationale,
    pushProbe: Boolean(body.pushProbe),
    persistArtifact: body.persistArtifact !== false,
  });
  return c.json({ data: response }, response.ready ? 200 : 400);
});

app.post("/external-action-proposals/:id/execute-pr", async (c) => {
  const id = c.req.param("id");
  const body = (await c.req.json().catch(() => ({}))) as ExecuteGitHubPrProposalRequest;
  const actor = body.actor?.trim();
  const rationale = body.rationale?.trim();
  if (!actor) {
    return c.json({ error: "validation", message: "actor is required" }, 400);
  }
  if (!rationale) {
    return c.json(
      { error: "validation", message: "rationale is required" },
      400
    );
  }

  const db = getDb();
  let proposal = db
    .select()
    .from(cbExternalActionProposals)
    .where(eq(cbExternalActionProposals.id, id))
    .get() as ExternalActionProposal | undefined;
  if (!proposal) {
    return c.json(
      { error: "not_found", message: `proposal ${id} not found` },
      404
    );
  }
  if (proposal.actionType !== "github_pr_create") {
    return c.json(
      {
        error: "validation",
        message: `proposal.actionType=${proposal.actionType}; expected github_pr_create`,
      },
      400
    );
  }
  if (proposal.approvalStatus !== "approved") {
    return c.json(
      {
        error: "blocked",
        message: `proposal.approvalStatus=${proposal.approvalStatus}; approve via the writeback governance flow before executing`,
      },
      400
    );
  }

  // Idempotency: already executed.
  if (
    proposal.executionStatus === "executed" &&
    proposal.externalUrl &&
    proposal.externalId
  ) {
    const response: ExecuteGitHubPrProposalResponse = {
      generatedAt: now(),
      proposalId: proposal.id,
      alreadyExecuted: true,
      prNumber: Number(proposal.externalId) || null,
      prUrl: proposal.externalUrl,
      pushedBranch: (
        proposal.payload as unknown as GitHubPrProposalPayload
      ).sourceBranch,
      errorSummary: null,
      proposal,
    };
    return c.json({ data: response });
  }

  const payload = proposal.payload as unknown as GitHubPrProposalPayload;
  const repo = payload.repo;

  const preflight = await buildGitHubPrWritebackPreflight({
    proposal,
    actor,
    rationale: `execute preflight: ${rationale}`,
    pushProbe: false,
    persistArtifact: true,
  });
  if (!preflight.ready) {
    return c.json(
      {
        error: "preflight_blocked",
        message: "GitHub PR writeback preflight is not ready; refusing execute",
        data: preflight,
      },
      400
    );
  }
  proposal = preflight.proposal;

  const token = githubPrWritebackTokenInfo().token;
  if (!token) {
    return c.json(
      {
        error: "blocked",
        message: "GITHUB_TOKEN/GH_TOKEN not configured for daemon; cannot push or open PR",
      },
      400
    );
  }

  // Reload AgentRun to verify workspace still exists.
  const run = db
    .select()
    .from(cbAgentRuns)
    .where(eq(cbAgentRuns.id, payload.agentRunId))
    .get() as typeof cbAgentRuns.$inferSelect | undefined;
  if (!run) {
    return c.json(
      {
        error: "validation",
        message: `AgentRun ${payload.agentRunId} not found; cannot execute`,
      },
      400
    );
  }
  const workspacePath = run.workspaceRef ?? null;
  if (!workspacePath || !existsSync(workspacePath)) {
    return c.json(
      {
        error: "validation",
        message: `AgentRun workspace missing at ${workspacePath ?? "(null)"}; cannot push`,
      },
      400
    );
  }

  // Idempotency check: PR with marker already exists?
  const marker = buildAiosPrMarker({
    proposalId: proposal.id,
    agentRunId: payload.agentRunId,
    patchPacketSignature: payload.patchPacketSignature,
  });
  const [owner, name] = repo.split("/");
  type ExistingGitHubPr = {
    number: number;
    html_url: string;
    body: string | null;
    state?: string;
    merged?: boolean;
    head?: { ref: string };
    base?: { ref: string };
  };
  let existingPr: ExistingGitHubPr | null = null;
  let iterationPr: ExistingGitHubPr | null = null;

  if (payload.iteration?.decision === "update_existing_pr") {
    const iterationPrNumber = payload.iteration.existingPrNumber;
    if (!iterationPrNumber) {
      return c.json(
        {
          error: "iteration_blocked",
          message: "iteration decision requested update_existing_pr but existingPrNumber is missing",
        },
        400
      );
    }
    let pr: ExistingGitHubPr | null = null;
    try {
      pr = await githubApiRequest<ExistingGitHubPr>(
        `/repos/${owner}/${name}/pulls/${iterationPrNumber}`,
        { requireToken: true }
      );
    } catch (err) {
      return c.json(
        {
          error: "iteration_pr_read_failed",
          message: err instanceof Error ? err.message : "GitHub PR read failed",
        },
        400
      );
    }
    const bodyText = pr.body ?? "";
    const markerMatched =
      bodyText.includes(AIOS_PR_MARKER_PREFIX) ||
      (payload.iteration.existingProposalId
        ? bodyText.includes(`aios:proposalId=${payload.iteration.existingProposalId}`)
        : false);
    const blockers = [
      pr.state === "open" && !pr.merged ? null : `pr_not_open_or_merged:${pr.state}/${pr.merged}`,
      pr.base?.ref === payload.baseBranch
        ? null
        : `base_mismatch:${pr.base?.ref ?? "(missing)"}!=${payload.baseBranch}`,
      pr.head?.ref === payload.sourceBranch
        ? null
        : `head_mismatch:${pr.head?.ref ?? "(missing)"}!=${payload.sourceBranch}`,
      markerMatched ? null : "aios_marker_missing",
    ].filter(Boolean) as string[];
    if (blockers.length) {
      return c.json(
        {
          error: "iteration_blocked",
          message: "Existing PR is not eligible for same-PR iteration",
          data: {
            blockers,
            prNumber: pr.number,
            prUrl: pr.html_url,
            sourceBranch: payload.sourceBranch,
            baseBranch: payload.baseBranch,
          },
        },
        400
      );
    }
    if (bodyText.includes(marker) || bodyText.includes(`aios:proposalId=${proposal.id}`)) {
      existingPr = pr;
    } else {
      iterationPr = pr;
    }
  }

  if (!existingPr && !iterationPr) {
    try {
      const list = await githubApiRequest<Array<ExistingGitHubPr>>(
        `/repos/${owner}/${name}/pulls`,
        {
          params: { head: `${owner}:${payload.sourceBranch}`, state: "all" },
          requireToken: true,
        }
      );
      existingPr =
        list.find((pr) => (pr.body ?? "").includes(marker)) ??
        list.find((pr) => (pr.body ?? "").includes(`aios:proposalId=${proposal.id}`)) ??
        null;
    } catch (err) {
      console.error("[company-brain] github pr list failed", err);
    }
  }

  if (existingPr) {
    const timestamp = now();
    const audit = (proposal.auditTrail ?? []).concat([
      {
        at: timestamp,
        actor,
        event: "external_action_proposal_executed_idempotent" as const,
        note: rationale,
        metadata: {
          prNumber: existingPr.number,
          prUrl: existingPr.html_url,
          marker,
        },
      },
    ]);
    db.update(cbExternalActionProposals)
      .set({
        executionStatus: "executed",
        externalId: String(existingPr.number),
        externalUrl: existingPr.html_url,
        auditTrail: audit,
        updatedAt: timestamp,
      } as never)
      .where(eq(cbExternalActionProposals.id, proposal.id))
      .run();
    const refreshed = db
      .select()
      .from(cbExternalActionProposals)
      .where(eq(cbExternalActionProposals.id, proposal.id))
      .get() as ExternalActionProposal;
    const response: ExecuteGitHubPrProposalResponse = {
      generatedAt: timestamp,
      proposalId: proposal.id,
      alreadyExecuted: true,
      prNumber: existingPr.number,
      prUrl: existingPr.html_url,
      pushedBranch: payload.sourceBranch,
      errorSummary: null,
      proposal: refreshed,
    };
    return c.json({ data: response });
  }

  // Push branch via x-access-token URL (works for both PATs and
  // GitHub App installation tokens).
  const pushUrl = `https://x-access-token:${token}@github.com/${owner}/${name}.git`;
  let forceWithLeaseArg: string | null = null;
  if (iterationPr) {
    const remoteRef = `refs/remotes/aios-iteration/${payload.sourceBranch}`;
    const fetchResult = spawnSync(
      "git",
      [
        "-C",
        workspacePath,
        "fetch",
        pushUrl,
        `refs/heads/${payload.sourceBranch}:${remoteRef}`,
      ],
      { encoding: "utf-8" }
    );
    if (fetchResult.status !== 0) {
      const errSummary =
        redactSnippet(fetchResult.stderr, token) ??
        redactSnippet(fetchResult.stdout, token) ??
        "git fetch failed";
      const audit = (proposal.auditTrail ?? []).concat([
        {
          at: now(),
          actor,
          event: "external_action_proposal_execute_failed" as const,
          note: rationale,
          metadata: {
            phase: "git_fetch_iteration_ref",
            errorSummary: errSummary,
            prNumber: iterationPr.number,
            prUrl: iterationPr.html_url,
          },
        },
      ]);
      db.update(cbExternalActionProposals)
        .set({
          executionStatus: "failed",
          errorSummary: `git fetch iteration ref failed: ${errSummary}`,
          auditTrail: audit,
          updatedAt: now(),
        } as never)
        .where(eq(cbExternalActionProposals.id, proposal.id))
        .run();
      return c.json(
        {
          error: "git_fetch_iteration_ref_failed",
          message: `git fetch ${payload.sourceBranch} failed before iteration push`,
          data: { errorSummary: errSummary },
        },
        500
      );
    }
    const revParse = spawnSync(
      "git",
      ["-C", workspacePath, "rev-parse", remoteRef],
      { encoding: "utf-8" }
    );
    const expectedSha = (revParse.stdout ?? "").trim();
    if (revParse.status !== 0 || !expectedSha) {
      return c.json(
        {
          error: "git_fetch_iteration_ref_failed",
          message: `Could not resolve fetched iteration ref ${remoteRef}`,
        },
        500
      );
    }
    forceWithLeaseArg = `--force-with-lease=refs/heads/${payload.sourceBranch}:${expectedSha}`;
  }
  const pushArgs = [
    "-C",
    workspacePath,
    "push",
    ...(forceWithLeaseArg ? [forceWithLeaseArg] : []),
    pushUrl,
    `HEAD:${payload.sourceBranch}`,
  ];
  const pushResult = spawnSync(
    "git",
    pushArgs,
    { encoding: "utf-8" }
  );
  if (pushResult.status !== 0) {
    const errSummary = (pushResult.stderr ?? "").trim().slice(0, 400);
    const audit = (proposal.auditTrail ?? []).concat([
      {
        at: now(),
        actor,
        event: "external_action_proposal_execute_failed" as const,
        note: rationale,
        metadata: { phase: "git_push", errorSummary: errSummary },
      },
    ]);
    db.update(cbExternalActionProposals)
      .set({
        executionStatus: "failed",
        errorSummary: `git push failed: ${errSummary}`,
        auditTrail: audit,
        updatedAt: now(),
      } as never)
      .where(eq(cbExternalActionProposals.id, proposal.id))
      .run();
    return c.json(
      {
        error: "git_push_failed",
        message: `git push origin ${payload.sourceBranch} failed`,
        data: { errorSummary: errSummary },
      },
      500
    );
  }

  if (iterationPr) {
    const existingBody = iterationPr.body ?? "";
    const previousMarkerSet = new Set<string>();
    for (const match of existingBody.matchAll(/<!-- aios:proposalId=.*?-->/g)) {
      const existingMarker = match[0];
      if (existingMarker !== marker) previousMarkerSet.add(existingMarker);
    }
    const previousMarkers = Array.from(previousMarkerSet);
    const iterationNote = [
      "<!-- aios-iteration",
      `proposalId=${proposal.id}`,
      `agentRunId=${payload.agentRunId}`,
      `patchPacketSignature=${payload.patchPacketSignature.slice(0, 16)}`,
      `sourceBranch=${payload.sourceBranch}`,
      "-->",
    ].join("\n");
    const markerHistory = previousMarkers.length
      ? [
          "",
          "### Previous AIOS proposal markers",
          "",
          ...previousMarkers,
        ].join("\n")
      : "";
    const bodyWithLatestEvidence = `${marker}\n\n${payload.body}${markerHistory}\n\n${iterationNote}`;
    let prUpdated: { number: number; html_url: string } | null = null;
    let prUpdateError: string | null = null;
    try {
      prUpdated = await githubApiRequest<{ number: number; html_url: string }>(
        `/repos/${owner}/${name}/pulls/${iterationPr.number}`,
        {
          method: "PATCH",
          requireToken: true,
          body: {
            body: bodyWithLatestEvidence,
          },
        }
      );
    } catch (err) {
      prUpdateError = err instanceof Error ? err.message : "unknown";
    }

    const timestamp = now();
    if (!prUpdated) {
      const audit = (proposal.auditTrail ?? []).concat([
        {
          at: timestamp,
          actor,
          event: "external_action_proposal_execute_failed" as const,
          note: rationale,
          metadata: {
            phase: "pr_iteration_update",
            errorSummary: prUpdateError,
            prNumber: iterationPr.number,
            prUrl: iterationPr.html_url,
          },
        },
      ]);
      db.update(cbExternalActionProposals)
        .set({
          executionStatus: "failed",
          errorSummary: `gh pr update failed: ${prUpdateError ?? "unknown"}`,
          auditTrail: audit,
          updatedAt: timestamp,
        } as never)
        .where(eq(cbExternalActionProposals.id, proposal.id))
        .run();
      return c.json(
        {
          error: "pr_iteration_update_failed",
          message: "GitHub PR update failed",
          data: { errorSummary: prUpdateError },
        },
        500
      );
    }

    const audit = (proposal.auditTrail ?? []).concat([
      {
        at: timestamp,
        actor,
        event: "external_action_proposal_executed_pr_iteration" as const,
        note: rationale,
        metadata: {
          prNumber: prUpdated.number,
          prUrl: prUpdated.html_url,
          marker,
          existingProposalId: payload.iteration?.existingProposalId ?? null,
          existingPrUrl: payload.iteration?.existingPrUrl ?? null,
        },
      },
    ]);
    db.update(cbExternalActionProposals)
      .set({
        executionStatus: "executed",
        externalId: String(prUpdated.number),
        externalUrl: prUpdated.html_url,
        auditTrail: audit,
        updatedAt: timestamp,
      } as never)
      .where(eq(cbExternalActionProposals.id, proposal.id))
      .run();
    const refreshed = db
      .select()
      .from(cbExternalActionProposals)
      .where(eq(cbExternalActionProposals.id, proposal.id))
      .get() as ExternalActionProposal;
    const response: ExecuteGitHubPrProposalResponse = {
      generatedAt: timestamp,
      proposalId: proposal.id,
      alreadyExecuted: false,
      prNumber: prUpdated.number,
      prUrl: prUpdated.html_url,
      pushedBranch: payload.sourceBranch,
      errorSummary: null,
      proposal: refreshed,
    };
    return c.json({ data: response }, 200);
  }

  // Create PR via GitHub API.
  const bodyWithMarker = `${marker}\n\n${payload.body}`;
  let prCreated: { number: number; html_url: string } | null = null;
  let prError: string | null = null;
  try {
    const created = await githubApiRequest<{ number: number; html_url: string }>(
      `/repos/${owner}/${name}/pulls`,
      {
        method: "POST",
        requireToken: true,
        body: {
          title: payload.title,
          body: bodyWithMarker,
          head: payload.sourceBranch,
          base: payload.baseBranch,
          maintainer_can_modify: true,
          draft: false,
        },
      }
    );
    prCreated = created;
  } catch (err) {
    prError = err instanceof Error ? err.message : "unknown";
  }

  const timestamp = now();
  if (!prCreated) {
    const audit = (proposal.auditTrail ?? []).concat([
      {
        at: timestamp,
        actor,
        event: "external_action_proposal_execute_failed" as const,
        note: rationale,
        metadata: { phase: "pr_create", errorSummary: prError },
      },
    ]);
    db.update(cbExternalActionProposals)
      .set({
        executionStatus: "failed",
        errorSummary: `gh pr create failed: ${prError ?? "unknown"}`,
        auditTrail: audit,
        updatedAt: timestamp,
      } as never)
      .where(eq(cbExternalActionProposals.id, proposal.id))
      .run();
    return c.json(
      {
        error: "pr_create_failed",
        message: `GitHub PR creation failed`,
        data: { errorSummary: prError },
      },
      500
    );
  }

  const audit = (proposal.auditTrail ?? []).concat([
    {
      at: timestamp,
      actor,
      event: "external_action_proposal_executed" as const,
      note: rationale,
      metadata: {
        prNumber: prCreated.number,
        prUrl: prCreated.html_url,
        marker,
      },
    },
  ]);
  db.update(cbExternalActionProposals)
    .set({
      executionStatus: "executed",
      externalId: String(prCreated.number),
      externalUrl: prCreated.html_url,
      auditTrail: audit,
      updatedAt: timestamp,
    } as never)
    .where(eq(cbExternalActionProposals.id, proposal.id))
    .run();
  const refreshed = db
    .select()
    .from(cbExternalActionProposals)
    .where(eq(cbExternalActionProposals.id, proposal.id))
    .get() as ExternalActionProposal;
  const response: ExecuteGitHubPrProposalResponse = {
    generatedAt: timestamp,
    proposalId: proposal.id,
    alreadyExecuted: false,
    prNumber: prCreated.number,
    prUrl: prCreated.html_url,
    pushedBranch: payload.sourceBranch,
    errorSummary: null,
    proposal: refreshed,
  };
  return c.json({ data: response }, 201);
});

type BuildGitHubPrProposalPreviewResult =
  | {
      ok: true;
      response: PreviewGitHubPrProposalResponse;
      packet: AgentRunPatchPacket;
      workItem: WorkItem | null;
      suggestion: AgentRunSuggestion | null;
      provenanceLinks: AgentRunPrProposalProvenanceLinks;
    }
  | {
      ok: false;
      statusCode: 400 | 404;
      error: string;
      message: string;
      packet: AgentRunPatchPacket | null;
      workItem: WorkItem | null;
      suggestion: AgentRunSuggestion | null;
      provenanceLinks: AgentRunPrProposalProvenanceLinks;
    };

function findAgentRunSuggestionForRun(run: typeof cbAgentRuns.$inferSelect): AgentRunSuggestion | null {
  const db = getDb();
  const metadata = run.metadata as Record<string, unknown> | null;
  const metadataSuggestionId =
    typeof metadata?.promotedFromSuggestionId === "string"
      ? metadata.promotedFromSuggestionId
      : null;
  if (metadataSuggestionId) {
    const byId = db
      .select()
      .from(cbAgentRunSuggestions)
      .where(eq(cbAgentRunSuggestions.id, metadataSuggestionId))
      .get() as AgentRunSuggestion | undefined;
    if (byId) return byId;
  }
  return (
    (db
      .select()
      .from(cbAgentRunSuggestions)
      .where(eq(cbAgentRunSuggestions.promotedAgentRunId, run.id))
      .get() as AgentRunSuggestion | undefined) ?? null
  );
}

function appendAgentRunPrProposalAudit(args: {
  agentRunId: string;
  actor: string;
  event: string;
  note: string | null;
  metadata: Record<string, unknown>;
}) {
  const db = getDb();
  const refreshed = db
    .select()
    .from(cbAgentRuns)
    .where(eq(cbAgentRuns.id, args.agentRunId))
    .get() as AgentRun | undefined;
  if (!refreshed) return;
  const alreadyAudited = (refreshed.auditTrail ?? []).some(
    (entry) =>
      entry.event === args.event &&
      entry.metadata?.proposalId === args.metadata.proposalId &&
      entry.metadata?.patchPacketSignature === args.metadata.patchPacketSignature
  );
  if (alreadyAudited) return;
  const auditTrail = appendAgentRunAuditEntry(refreshed.auditTrail ?? [], {
    actor: args.actor,
    event: args.event,
    note: args.note,
    metadata: args.metadata,
  });
  db.update(cbAgentRuns)
    .set({ auditTrail, updatedAt: now() } as never)
    .where(eq(cbAgentRuns.id, args.agentRunId))
    .run();
}

async function buildGitHubPrProposalPreviewFromAgentRun(args: {
  run: typeof cbAgentRuns.$inferSelect;
  actor: string;
  rationale?: string | null;
  titleOverride?: string | null;
  bodyOverride?: string | null;
  requireCompleted?: boolean;
  createdFrom: string;
}): Promise<BuildGitHubPrProposalPreviewResult> {
  const db = getDb();
  const run = args.run;
  const suggestion = findAgentRunSuggestionForRun(run);
  const baseLinks: AgentRunPrProposalProvenanceLinks = {
    workItemId: run.workItemId,
    suggestionId: suggestion?.id ?? null,
    agentRunId: run.id,
    patchPacketArtifactId: null,
    proposalId: null,
    proposalIdempotencyKey: null,
    patchPacketSignature: null,
  };

  const workItem = run.workItemId
    ? ((db
        .select()
        .from(cbWorkItems)
        .where(eq(cbWorkItems.id, run.workItemId))
        .get() as WorkItem | undefined) ?? null)
    : null;

  if (args.requireCompleted && run.status !== "completed") {
    return {
      ok: false,
      statusCode: 400,
      error: "blocked",
      message: `AgentRun.status=${run.status}; expected completed before PR proposal chain`,
      packet: null,
      workItem,
      suggestion,
      provenanceLinks: baseLinks,
    };
  }
  if (!run.repo) {
    return {
      ok: false,
      statusCode: 400,
      error: "validation",
      message: "AgentRun.repo is missing; cannot build PR proposal",
      packet: null,
      workItem,
      suggestion,
      provenanceLinks: baseLinks,
    };
  }
  if (!run.branch) {
    return {
      ok: false,
      statusCode: 400,
      error: "validation",
      message: "AgentRun.branch is missing; cannot build PR proposal",
      packet: null,
      workItem,
      suggestion,
      provenanceLinks: baseLinks,
    };
  }

  const packet = collectAgentRunPatchPacket({ agentRun: run });
  if (packet.status !== "clean" && packet.status !== "dirty") {
    return {
      ok: false,
      statusCode: 400,
      error: "blocked",
      message: `patch packet status=${packet.status}; cannot build PR proposal`,
      packet,
      workItem,
      suggestion,
      provenanceLinks: baseLinks,
    };
  }
  if (
    packet.diffStat.filesChanged === 0 &&
    packet.changedFiles.length === 0 &&
    packet.commits.length === 0
  ) {
    return {
      ok: false,
      statusCode: 400,
      error: "blocked",
      message: "patch packet has no diff and no commits; nothing to propose",
      packet,
      workItem,
      suggestion,
      provenanceLinks: baseLinks,
    };
  }

  const workflow = loadWorkflowFromRepoRoot();
  const baseBranch = packet.baseRef ?? workflow.config.workspace.baseBranch ?? "main";
  const repo = run.repo;
  const iteration = await buildGitHubPrIterationPlan({
    workItemId: run.workItemId,
    repo,
    baseBranch,
  });
  const sourceBranch =
    iteration.decision === "update_existing_pr" && iteration.existingSourceBranch
      ? iteration.existingSourceBranch
      : run.branch;
  const packetSignature = computeAgentRunPatchPacketSignature({
    agentRun: run,
    packet,
    repo,
    sourceBranch,
    baseBranch,
  });
  const persistedPacket = persistAgentRunPatchPacket({
    packet,
    agentRun: run,
    packetSignature,
  });
  packet.artifactId = persistedPacket.artifactId;
  const idempotencyKey = `aios-pr-proposal:${run.id}:${packetSignature.slice(0, 16)}`;
  const provenanceLinks: AgentRunPrProposalProvenanceLinks = {
    ...baseLinks,
    patchPacketArtifactId: persistedPacket.artifactId,
    proposalId: null,
    proposalIdempotencyKey: idempotencyKey,
    patchPacketSignature: packetSignature,
  };

  const titleBase =
    args.titleOverride?.trim() ||
    (workItem ? workItem.title : `AIOS AgentRun ${run.id} proposal`);
  const title = `feat(aios): ${titleBase}`.slice(0, 240);

  const validationsSummary = packet.validations.length
    ? packet.validations
        .map((v) => `${v.kind}=${v.status}`)
        .join("; ")
        .slice(0, 240)
    : "(no validations recorded)";

  const bodyText =
    args.bodyOverride?.trim() ||
    [
      `## Summary`,
      "",
      workItem ? `Closes ${workItem.externalId ?? `#${workItem.id}`}.` : "",
      "",
      "Authored by AIOS Agent Run.",
      "",
      `### Provenance`,
      "",
      `- workItemId: ${workItem?.id ?? "-"}`,
      `- suggestionId: ${suggestion?.id ?? "-"}`,
      `- agentRunId: ${run.id}`,
      `- patchPacketArtifactId: ${persistedPacket.artifactId}`,
      `- patchPacketSignature: ${packetSignature.slice(0, 16)}`,
      `- iterationDecision: ${iteration.decision}`,
      iteration.existingPrUrl ? `- existingPrUrl: ${iteration.existingPrUrl}` : "",
      "",
      `### Patch packet`,
      "",
      `- baseRef: ${baseBranch}`,
      `- changedFiles: ${packet.changedFiles.length} (${packet.changedFiles
        .slice(0, 10)
        .map((f) => `${f.status} ${f.path}`)
        .join(", ")})`,
      `- diffStat: ${packet.diffStat.filesChanged} files / +${packet.diffStat.insertions} / -${packet.diffStat.deletions}`,
      `- commits: ${packet.commits.length} ahead of ${baseBranch}`,
      `- attempt: ${packet.attempt}`,
      `- previousPrUrl: ${packet.previousPrUrl ?? "-"}`,
      `- validationDelta: failed ${packet.validationDelta.previousFailedCount ?? "n/a"} -> ${packet.validationDelta.currentFailedCount}`,
      "",
      `### Validations`,
      "",
      validationsSummary,
      "",
      `### Safety`,
      "",
      "- AIOS-authored. Requires human review before merge.",
      "- This is a preview proposal; no GitHub mutation has occurred.",
    ]
      .filter(Boolean)
      .join("\n");

  const payload: GitHubPrProposalPayload = {
    repo,
    sourceBranch,
    baseBranch,
    title,
    body: bodyText,
    agentRunId: run.id,
    workItemId: run.workItemId,
    patchPacketArtifactId: persistedPacket.artifactId,
    patchPacketSignature: packetSignature,
    changedFileCount: packet.changedFiles.length,
    diffStat: packet.diffStat,
    commitCount: packet.commits.length,
    validationsSummary,
    safetyMarkers: {
      aiosAuthored: true,
      requiresHumanReview: true,
      dryRunOnly: true,
    },
    iteration,
  };

  const existing = db
    .select()
    .from(cbExternalActionProposals)
    .where(eq(cbExternalActionProposals.idempotencyKey, idempotencyKey))
    .get() as ExternalActionProposal | undefined;
  if (existing) {
    const links = {
      ...provenanceLinks,
      proposalId: existing.id,
      proposalIdempotencyKey: existing.idempotencyKey,
    };
    appendAgentRunPrProposalAudit({
      agentRunId: run.id,
      actor: args.actor,
      event: "agent_run_pr_proposal_preview_reused",
      note: args.rationale ?? null,
      metadata: {
        createdFrom: args.createdFrom,
        proposalId: existing.id,
        idempotencyKey,
        patchPacketArtifactId: persistedPacket.artifactId,
        patchPacketSignature: packetSignature,
        suggestionId: suggestion?.id ?? null,
      },
    });
    const response: PreviewGitHubPrProposalResponse = {
      generatedAt: now(),
      proposalId: existing.id,
      alreadyExisted: true,
      payload,
      proposal: existing,
      patchPacket: packet,
      patchPacketArtifactId: persistedPacket.artifactId,
      provenanceLinks: links,
    };
    return {
      ok: true,
      response,
      packet,
      workItem,
      suggestion,
      provenanceLinks: links,
    };
  }

  const timestamp = now();
  const proposalId = nanoid(12);
  const auditEntry = {
    at: timestamp,
    actor: args.actor,
    event: "external_action_proposal_created" as const,
    note: args.rationale?.trim() ?? null,
    metadata: {
      kind: "github_pr_create",
      idempotencyKey,
      patchPacketSignature: packetSignature,
      patchPacketArtifactId: persistedPacket.artifactId,
      suggestionId: suggestion?.id ?? null,
      createdFrom: args.createdFrom,
    },
  };
  const proposalRow: ExternalActionProposal = {
    id: proposalId,
    guidanceItemId: "", // PR proposals are AgentRun-driven, not Guidance-driven
    signalId: null,
    findingId: null,
    workItemId: run.workItemId,
    workflowRunId: null,
    title,
    rationale:
      args.rationale?.trim() ??
      `Preview-only PR proposal generated from AgentRun ${run.id} patch packet`,
    destinationType: "github",
    destinationRef: `${repo}:${sourceBranch}->${baseBranch}`,
    actionType: "github_pr_create",
    payload: payload as unknown as Record<string, unknown>,
    riskClass: workItem?.riskClass ?? "B",
    actionPolicy: "request_human",
    policySummary:
      "Preview-only PR proposal. No GitHub push/merge/deploy occurs from this record. Human review required before any executor runs.",
    approvalStatus: "pending",
    approvalRequired: true,
    requestedBy: args.actor,
    approvedBy: null,
    approvedAt: null,
    rejectionReason: null,
    executionStatus: "not_started",
    externalId: null,
    externalUrl: null,
    errorSummary: null,
    rollbackRef: null,
    idempotencyKey,
    auditTrail: [auditEntry],
    visibility: "internal",
    provenance: {
      sourceId: run.sourceId ?? "",
      rawRef: `aios://agent-run/${run.id}`,
      artifactId: persistedPacket.artifactId,
      createdFrom: "company_brain:agent_run_pr_proposal_preview",
      confidence: 1,
      extractedAt: timestamp,
      humanReviewStatus: "pending",
      visibility: "internal",
      notes: `signature=${packetSignature.slice(0, 12)}; agentRunId=${run.id}; suggestionId=${suggestion?.id ?? "-"}`,
    },
    createdAt: timestamp,
    updatedAt: timestamp,
  };
  db.insert(cbExternalActionProposals).values(proposalRow as never).run();
  const links = {
    ...provenanceLinks,
    proposalId,
    proposalIdempotencyKey: idempotencyKey,
  };
  appendAgentRunPrProposalAudit({
    agentRunId: run.id,
    actor: args.actor,
    event: "agent_run_pr_proposal_previewed",
    note: args.rationale ?? null,
    metadata: {
      createdFrom: args.createdFrom,
      proposalId,
      idempotencyKey,
      patchPacketArtifactId: persistedPacket.artifactId,
      patchPacketSignature: packetSignature,
      suggestionId: suggestion?.id ?? null,
    },
  });

  const response: PreviewGitHubPrProposalResponse = {
    generatedAt: timestamp,
    proposalId,
    alreadyExisted: false,
    payload,
    proposal: proposalRow,
    patchPacket: packet,
    patchPacketArtifactId: persistedPacket.artifactId,
    provenanceLinks: links,
  };
  return {
    ok: true,
    response,
    packet,
    workItem,
    suggestion,
    provenanceLinks: links,
  };
}

async function maybeCreateAutoDispatchPrProposal(args: {
  agentRunId: string;
  actor: string;
  rationale: string;
}): Promise<AgentRunPrProposalChainResponse | null> {
  if (!autoDispatchPrProposalEnabled()) return null;
  const db = getDb();
  const run = db
    .select()
    .from(cbAgentRuns)
    .where(eq(cbAgentRuns.id, args.agentRunId))
    .get() as AgentRun | undefined;
  if (!run) return null;

  const proposalActor = "operating-loop:auto-pr-proposal";
  const allowlist = autoDispatchPrProposalRepoAllowlist();
  const metadata = run.metadata as Record<string, unknown> | null;
  const suggestion = findAgentRunSuggestionForRun(run);
  const wasAutoDispatched = (run.auditTrail ?? []).some(
    (entry) => entry.event === "agent_run_auto_dispatched"
  ) || (typeof metadata?.promotedBy === "string" &&
    metadata.promotedBy.startsWith("operating-loop:auto-dispatch")) ||
    (typeof suggestion?.promotedBy === "string" &&
      suggestion.promotedBy.startsWith("operating-loop:auto-dispatch"));
  const blockReasons: string[] = [];
  if (!wasAutoDispatched) blockReasons.push("agent_run_not_auto_dispatched");
  if (run.status !== "completed") blockReasons.push(`agent_run_status_${run.status}`);
  if (run.riskClass !== "A") blockReasons.push(`risk_${run.riskClass}`);
  if (!run.repo) {
    blockReasons.push("repo_missing");
  } else if (!allowlist.includes(run.repo)) {
    blockReasons.push("repo_not_allowlisted");
  }

  if (blockReasons.length) {
    appendAgentRunPrProposalAudit({
      agentRunId: run.id,
      actor: proposalActor,
      event: "agent_run_auto_pr_proposal_blocked",
      note: args.rationale,
      metadata: {
        blockReasons,
        repo: run.repo,
        allowlist,
      },
    });
    return null;
  }

  const result = await buildGitHubPrProposalPreviewFromAgentRun({
    run,
    actor: proposalActor,
    rationale: args.rationale,
    requireCompleted: true,
    createdFrom: "operating-loop:auto-pr-proposal",
  });
  if (!result.ok) {
    appendAgentRunPrProposalAudit({
      agentRunId: run.id,
      actor: proposalActor,
      event: "agent_run_auto_pr_proposal_blocked",
      note: result.message,
      metadata: {
        error: result.error,
        message: result.message,
        provenanceLinks: result.provenanceLinks,
      },
    });
    return {
      generatedAt: now(),
      status: "blocked",
      agentRun: run,
      workItem: result.workItem,
      suggestion: result.suggestion,
      patchPacket: result.packet,
      patchPacketArtifactId: result.provenanceLinks.patchPacketArtifactId,
      proposal: null,
      proposalId: null,
      alreadyExisted: false,
      provenanceLinks: result.provenanceLinks,
      errorSummary: result.message,
    };
  }
  return {
    generatedAt: now(),
    status: result.response.alreadyExisted ? "reused" : "created",
    agentRun: run,
    workItem: result.workItem,
    suggestion: result.suggestion,
    patchPacket: result.packet,
    patchPacketArtifactId: result.response.patchPacketArtifactId ?? null,
    proposal: result.response.proposal,
    proposalId: result.response.proposalId,
    alreadyExisted: result.response.alreadyExisted,
    provenanceLinks: result.provenanceLinks,
    errorSummary: null,
  };
}

