app.post("/pilot-targets", async (c) => {
  try {
    const body = (await c.req
      .json<CreatePilotTargetRequest>()
      .catch(() => ({}))) as CreatePilotTargetRequest;
    const projectName = requireText(body.projectName, "projectName");
    const repo = requireText(body.repo, "repo");
    if (!/^[^/\s]+\/[^/\s]+$/.test(repo)) {
      return c.json(
        { error: "validation", message: "repo must be in owner/name form" },
        400
      );
    }
    const id =
      body.id?.trim() ||
      `pilot-target-${sanitizeWorkspaceKey(repo).toLowerCase()}`;
    if (!/^[A-Za-z0-9._:-]+$/.test(id)) {
      return c.json(
        {
          error: "validation",
          message: "id may contain only letters, numbers, dot, underscore, colon or dash",
        },
        400
      );
    }
    const status = body.status ?? "active";
    if (!["active", "paused", "disabled"].includes(status)) {
      return c.json(
        { error: "validation", message: "status must be active, paused or disabled" },
        400
      );
    }
    const riskCeiling = body.riskCeiling ?? "A";
    if (!["A", "B", "C", "unknown"].includes(riskCeiling)) {
      return c.json(
        { error: "validation", message: "riskCeiling must be A, B, C or unknown" },
        400
      );
    }
    const allowedRunnerProfileIds =
      body.allowedRunnerProfileIds && body.allowedRunnerProfileIds.length > 0
        ? body.allowedRunnerProfileIds
        : ["dogfood-semantic-doc-change"];
    const unknownProfiles = allowedRunnerProfileIds.filter((profileId) => !getRunnerProfile(profileId));
    if (unknownProfiles.length) {
      return c.json(
        {
          error: "validation",
          message: `unknown runner profile(s): ${unknownProfiles.join(", ")}`,
        },
        400
      );
    }
    const defaultWorkflowBlueprintId =
      body.defaultWorkflowBlueprintId?.trim() || "development-blueprint-v0";
    const db = getDb();
    const blueprint = db
      .select()
      .from(cbWorkflowBlueprints)
      .where(eq(cbWorkflowBlueprints.id, defaultWorkflowBlueprintId))
      .get();
    if (!blueprint) {
      return c.json(
        {
          error: "validation",
          message: `workflow blueprint ${defaultWorkflowBlueprintId} not found`,
        },
        400
      );
    }
    const existing = db
      .select()
      .from(cbPilotTargets)
      .where(eq(cbPilotTargets.id, id))
      .get() as PilotTarget | undefined;
    if (existing) {
      return c.json(
        {
          error: "already_exists",
          message: `pilot target ${id} already exists`,
          data: { target: existing, readiness: buildPilotTargetReadiness(existing) },
        },
        409
      );
    }
    const timestamp = now();
    const row: PilotTarget = {
      id,
      projectName,
      repo,
      area: body.area ?? "development",
      defaultWorkflowBlueprintId,
      allowedRunnerProfileIds,
      riskCeiling,
      owner: body.owner ?? null,
      ownerType: body.ownerType ?? "human",
      status,
      notes: body.notes ?? null,
      visibility: body.visibility ?? "internal",
      metadata: {
        ...(body.metadata ?? {}),
        registeredFrom: "api:pilot-targets",
        registeredAt: timestamp,
      },
      createdAt: timestamp,
      updatedAt: timestamp,
    };
    db.insert(cbPilotTargets).values(row as never).run();
    return c.json(
      { data: { target: row, readiness: buildPilotTargetReadiness(row) } },
      201
    );
  } catch (err) {
    const message = err instanceof Error ? err.message : "Unknown error";
    return c.json({ error: "pilot_target_create_failed", message }, 400);
  }
});

app.patch("/pilot-targets/:id", async (c) => {
  try {
    const id = c.req.param("id");
    const body = (await c.req
      .json<UpdatePilotTargetRequest>()
      .catch(() => ({}))) as UpdatePilotTargetRequest;
    if (!body.actor || !body.actor.trim()) {
      return c.json({ error: "validation", message: "actor is required" }, 400);
    }
    if (!body.rationale || !body.rationale.trim()) {
      return c.json({ error: "validation", message: "rationale is required" }, 400);
    }
    const db = getDb();
    const existing = db
      .select()
      .from(cbPilotTargets)
      .where(eq(cbPilotTargets.id, id))
      .get() as PilotTarget | undefined;
    if (!existing) {
      return c.json(
        { error: "not_found", message: `pilot target ${id} not found` },
        404
      );
    }

    const updates: Partial<PilotTarget> = {};
    if (body.projectName !== undefined) {
      updates.projectName = requireText(body.projectName, "projectName");
    }
    if (body.area !== undefined) updates.area = body.area;
    if (body.riskCeiling !== undefined) {
      if (!["A", "B", "C", "unknown"].includes(body.riskCeiling)) {
        return c.json(
          { error: "validation", message: "riskCeiling must be A, B, C or unknown" },
          400
        );
      }
      updates.riskCeiling = body.riskCeiling;
    }
    if (body.status !== undefined) {
      if (!["active", "paused", "disabled"].includes(body.status)) {
        return c.json(
          { error: "validation", message: "status must be active, paused or disabled" },
          400
        );
      }
      updates.status = body.status;
    }
    if (body.allowedRunnerProfileIds !== undefined) {
      if (!body.allowedRunnerProfileIds.length) {
        return c.json(
          { error: "validation", message: "allowedRunnerProfileIds cannot be empty" },
          400
        );
      }
      const unknownProfiles = body.allowedRunnerProfileIds.filter(
        (profileId) => !getRunnerProfile(profileId)
      );
      if (unknownProfiles.length) {
        return c.json(
          {
            error: "validation",
            message: `unknown runner profile(s): ${unknownProfiles.join(", ")}`,
          },
          400
        );
      }
      updates.allowedRunnerProfileIds = body.allowedRunnerProfileIds;
    }
    if (body.defaultWorkflowBlueprintId !== undefined) {
      const blueprintId =
        body.defaultWorkflowBlueprintId?.trim() || "development-blueprint-v0";
      const blueprint = db
        .select()
        .from(cbWorkflowBlueprints)
        .where(eq(cbWorkflowBlueprints.id, blueprintId))
        .get();
      if (!blueprint) {
        return c.json(
          {
            error: "validation",
            message: `workflow blueprint ${blueprintId} not found`,
          },
          400
        );
      }
      updates.defaultWorkflowBlueprintId = blueprintId;
    }
    if (body.owner !== undefined) updates.owner = body.owner;
    if (body.ownerType !== undefined) updates.ownerType = body.ownerType;
    if (body.notes !== undefined) updates.notes = body.notes;
    if (body.visibility !== undefined) updates.visibility = body.visibility;

    const timestamp = now();
    const metadata = {
      ...metadataRecord(existing.metadata),
      ...(body.metadata ?? {}),
      lastUpdatedFrom: "api:pilot-targets:update",
      lastUpdatedAt: timestamp,
      lastUpdatedBy: body.actor.trim(),
      lastUpdateRationale: body.rationale.trim(),
    };
    const row: PilotTarget = {
      ...existing,
      ...updates,
      metadata,
      updatedAt: timestamp,
    };
    db.update(cbPilotTargets)
      .set({
        projectName: row.projectName,
        area: row.area,
        defaultWorkflowBlueprintId: row.defaultWorkflowBlueprintId,
        allowedRunnerProfileIds: row.allowedRunnerProfileIds,
        riskCeiling: row.riskCeiling,
        owner: row.owner,
        ownerType: row.ownerType,
        status: row.status,
        notes: row.notes,
        visibility: row.visibility,
        metadata: row.metadata,
        updatedAt: row.updatedAt,
      })
      .where(eq(cbPilotTargets.id, id))
      .run();

    return c.json({ data: { target: row, readiness: buildPilotTargetReadiness(row) } });
  } catch (err) {
    const message = err instanceof Error ? err.message : "Unknown error";
    return c.json({ error: "pilot_target_update_failed", message }, 400);
  }
});

