function buildOperatingPackRegistry(timestamp = now()): CompanyBrainOperatingPackRegistry {
  const totals: CompanyBrainOperatingPackRegistry["totals"] = {
    entryCount: OPERATING_PACK_REGISTRY_ENTRIES.length,
    activeCount: 0,
    draftCount: 0,
    pausedCount: 0,
    archivedCount: 0,
    operatingPackRunnerCount: 0,
    agentRouteSkillCount: 0,
    watcherAdapterCount: 0,
    noExternalWriteCount: 0,
    proposalOnlyCount: 0,
    approvedWritebackCount: 0,
  };

  for (const entry of OPERATING_PACK_REGISTRY_ENTRIES) {
    if (entry.status === "active") totals.activeCount += 1;
    if (entry.status === "draft") totals.draftCount += 1;
    if (entry.status === "paused") totals.pausedCount += 1;
    if (entry.status === "archived") totals.archivedCount += 1;
    if (entry.executionMode === "operating_pack_runner") {
      totals.operatingPackRunnerCount += 1;
    }
    if (entry.executionMode === "agent_route_skill") {
      totals.agentRouteSkillCount += 1;
    }
    if (entry.executionMode === "watcher_adapter") {
      totals.watcherAdapterCount += 1;
    }
    if (entry.externalWritePolicy === "none") totals.noExternalWriteCount += 1;
    if (entry.externalWritePolicy === "proposal_only") totals.proposalOnlyCount += 1;
    if (entry.externalWritePolicy === "approved_writeback") {
      totals.approvedWritebackCount += 1;
    }
  }

  return {
    generatedAt: timestamp,
    entries: OPERATING_PACK_REGISTRY_ENTRIES,
    totals,
  };
}

function getOperatingMapAreaSlugForArea(area: CompanyBrainArea): CompanyOperatingMapAreaSlug {
  const matched = AREA_BLUEPRINT_REGISTRY_BASE.find(
    (spec) => spec.primaryArea === area || spec.alternateAreas.includes(area)
  );
  return matched?.slug ?? "development";
}

function normalizeOperatingPackRouteText(value: string): string {
  return normalizeOperatingPackMatchText(value)
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function operatingPackRouteTextIncludes(text: string, term: string): boolean {
  const normalizedText = normalizeOperatingPackRouteText(text);
  const normalizedTerm = normalizeOperatingPackRouteText(term);
  if (!normalizedTerm) return false;
  if (normalizedTerm.length <= 2) {
    return normalizedText.split(" ").includes(normalizedTerm);
  }
  const compactText = normalizedText.replace(/\s+/g, "");
  const compactTerm = normalizedTerm.replace(/\s+/g, "");
  return normalizedText.includes(normalizedTerm) || compactText.includes(compactTerm);
}

function operatingPackRouteTextIncludesAny(text: string, terms: string[]): boolean {
  return terms.some((term) => operatingPackRouteTextIncludes(text, term));
}

function operatingPackRegistryEntryMatchesText(
  entry: CompanyBrainOperatingPackRegistryEntry,
  text: string
): boolean {
  const hints = entry.routingHints;
  if (operatingPackRouteTextIncludesAny(text, hints.directTerms)) return true;
  if (hints.intentTerms.length === 0 || hints.targetTerms.length === 0) return false;
  return (
    operatingPackRouteTextIncludesAny(text, hints.intentTerms) &&
    operatingPackRouteTextIncludesAny(text, hints.targetTerms)
  );
}

function getOperatingPackRegistryEntry(
  slug: CompanyBrainOperatingPackSlug | null | undefined
): CompanyBrainOperatingPackRegistryEntry | null {
  if (!slug) return null;
  return OPERATING_PACK_REGISTRY_ENTRIES.find((entry) => entry.slug === slug) ?? null;
}

function findOperatingPackRegistryEntryForText(
  text: string,
  options: {
    executionModes?: CompanyBrainOperatingPackExecutionMode[];
    slugs?: CompanyBrainOperatingPackSlug[];
  } = {}
): CompanyBrainOperatingPackRegistryEntry | null {
  const entries = OPERATING_PACK_REGISTRY_ENTRIES.filter((entry) => {
    if (entry.status !== "active") return false;
    if (options.executionModes && !options.executionModes.includes(entry.executionMode)) return false;
    if (options.slugs && !options.slugs.includes(entry.slug)) return false;
    return true;
  });
  return entries.find((entry) => operatingPackRegistryEntryMatchesText(entry, text)) ?? null;
}

function getDefaultOperatingPackRunnerEntry(): CompanyBrainOperatingPackRegistryEntry | null {
  return (
    OPERATING_PACK_REGISTRY_ENTRIES.find(
      (entry) => entry.status === "active" && entry.executionMode === "operating_pack_runner"
    ) ?? null
  );
}

function normalizeOperatingPackMatchText(value: string): string {
  return value
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase();
}

function slugifyOperatingPackPart(value: string, fallback = "item", maxLength = 80): string {
  const slug = normalizeOperatingPackMatchText(value)
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, maxLength)
    .replace(/-+$/g, "");
  return slug || fallback;
}

function getSaoPauloDateParts(timestamp: number): {
  date: string;
  time: string;
  compactTime: string;
} {
  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: "America/Sao_Paulo",
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false,
  }).formatToParts(new Date(timestamp));
  const part = (type: string) => parts.find((entry) => entry.type === type)?.value ?? "00";
  const hour = part("hour") === "24" ? "00" : part("hour");
  const date = `${part("year")}-${part("month")}-${part("day")}`;
  const time = `${hour}:${part("minute")}:${part("second")}`;
  return { date, time, compactTime: `${hour}${part("minute")}${part("second")}` };
}

function inferMarketingNr1Segment(text: string): string {
  const normalized = normalizeOperatingPackMatchText(text);
  if (/\b(?:contabil|contabilidade|contabilidades|contador|consultoria|consultorias)\b/.test(normalized)) {
    return MARKETING_NR1_DEFAULT_SEGMENT;
  }
  if (/\b(?:rh|recursos humanos|dp|departamento pessoal)\b/.test(normalized)) {
    return "RHs e departamentos pessoais de empresas de 50-500 colaboradores";
  }
  if (/\b(?:clinica|clinicas|saude|medicina ocupacional|sst)\b/.test(normalized)) {
    return "clinicas de medicina ocupacional e parceiros de SST";
  }
  return MARKETING_NR1_DEFAULT_SEGMENT;
}

function marketingNr1SegmentSlug(segment: string): string {
  if (segment === MARKETING_NR1_DEFAULT_SEGMENT) return "contabilidades-consultorias-50-500";
  if (/RHs e departamentos pessoais/i.test(segment)) return "rhs-dps-50-500";
  if (/medicina ocupacional|SST/i.test(segment)) return "clinicas-ocupacionais-sst";
  return slugifyOperatingPackPart(segment, "segmento", 72);
}

function buildMarketingNr1BriefingIdentity(segment: string, timestamp: number) {
  const parts = getSaoPauloDateParts(timestamp);
  const segmentSlug = marketingNr1SegmentSlug(segment);
  const semanticKey = `marketing.nr1.briefing.${parts.date}.${segmentSlug}`;
  const artifactName = `${semanticKey}.${parts.compactTime}`;
  const rawRef = `aios://operating-packs/marketing/nr1/briefings/${parts.date}/${segmentSlug}/${parts.compactTime}`;
  return {
    ...parts,
    segmentSlug,
    semanticKey,
    artifactName,
    rawRef,
  };
}

function buildMarketingNr1FeedbackIdentity(
  targetArtifactId: string,
  feedbackStatus: GuidanceFeedbackStatus,
  timestamp: number
) {
  const parts = getSaoPauloDateParts(timestamp);
  const targetSlug = slugifyOperatingPackPart(targetArtifactId, "artifact", 32);
  const semanticKey = `marketing.nr1.feedback.${parts.date}.${targetSlug}`;
  const artifactName = `${semanticKey}.${feedbackStatus}.${parts.compactTime}`;
  const rawRef = `aios://operating-packs/marketing/nr1/feedback/${parts.date}/${targetSlug}/${parts.compactTime}`;
  return {
    ...parts,
    targetSlug,
    semanticKey,
    artifactName,
    rawRef,
  };
}

function inferOperatingPackAction(
  request: RunCompanyBrainOperatingPackRequest
): CompanyBrainOperatingPackAction {
  if (request.action) return request.action;
  const normalized = normalizeOperatingPackMatchText(request.text ?? "");
  if (/\b(?:feedback|aprovado|aprovei|aceito|rejeitado|corrigir|ajustar|executado|concluido|concluido)\b/.test(normalized)) {
    return "feedback";
  }
  if (/\b(?:promover|salvar|registrar|persistir)\b/.test(normalized)) {
    return "promote";
  }
  return "run";
}

function inferOperatingPackSlug(
  request: RunCompanyBrainOperatingPackRequest,
  router: CompanyBrainCommandRouterResult
): CompanyBrainOperatingPackSlug | null {
  if (request.packSlug) return request.packSlug;
  const matchedEntry = findOperatingPackRegistryEntryForText(request.text ?? "", {
    executionModes: ["operating_pack_runner"],
  });
  if (matchedEntry) return matchedEntry.slug;
  const areaEntry = OPERATING_PACK_REGISTRY_ENTRIES.find(
    (entry) =>
      entry.status === "active" &&
      entry.executionMode === "operating_pack_runner" &&
      entry.area === router.classification.area &&
      operatingPackRegistryEntryMatchesText(entry, request.text ?? "")
  );
  if (areaEntry) return areaEntry.slug;
  return null;
}

function buildOperatingPackRouterResult(
  request: RunCompanyBrainOperatingPackRequest,
  timestamp: number,
  preliminaryPackSlug: CompanyBrainOperatingPackSlug | null
): CompanyBrainCommandRouterResult {
  const preliminaryPackEntry = getOperatingPackRegistryEntry(preliminaryPackSlug);
  const routerRequest: RouteCompanyBrainCommandRequest = {
    text: request.text,
    area: request.area ?? preliminaryPackEntry?.area,
    actor: request.actor ?? null,
    visibility: request.visibility ?? "internal",
    dryRun: true,
  };
  const classification = buildCommandRouterClassification(routerRequest);
  const routing = executeCommandRouterClassification(routerRequest, classification, timestamp);
  return {
    generatedAt: timestamp,
    request: routerRequest,
    classification,
    routing,
  };
}

function formatCommandRouterPreview(router: CompanyBrainCommandRouterResult): string {
  const hint = router.request.actor ? `\nHint usado: actor=${router.request.actor}` : "";
  return [
    "AIOS preview (dryRun=true)",
    `Decisao: ${router.routing.decision}`,
    `Area: ${router.classification.primaryAreaSlug} / ${router.classification.area}`,
    `Intencao: ${router.classification.intentKind} -> ${router.classification.targetKind}`,
    `Risco: ${router.classification.riskClass} | confianca: ${router.classification.confidence.toFixed(2)}${hint}`,
    "",
    `Proximo: ${router.routing.nextActionLabel}`,
    router.routing.nextActionDetail,
    "",
    "Racional:",
    ...router.routing.rationale.map((line) => `- ${line}`),
  ].join("\n");
}

function getMarketingNr1Guidance(): GuidanceItem | null {
  const db = getDb();
  const explicit = db
    .select()
    .from(cbGuidanceItems)
    .where(eq(cbGuidanceItems.id, MARKETING_NR1_GUIDANCE_ID))
    .get();
  if (explicit) return explicit as unknown as GuidanceItem;

  const guidanceItems = db
    .select()
    .from(cbGuidanceItems)
    .orderBy(desc(cbGuidanceItems.updatedAt))
    .limit(50)
    .all() as unknown as GuidanceItem[];
  return (
    guidanceItems.find((item) => {
      const text = normalizeOperatingPackMatchText(`${item.title}\n${item.action}`);
      return item.area === "marketing" && /nr\s*-?\s*1|nr1|spa da vida empresas/.test(text);
    }) ?? null
  );
}

