function normalizeMarketingFeedbackStatus(text: string | null | undefined): {
  feedbackStatus: GuidanceFeedbackStatus;
  humanReviewStatus: ReviewStatus;
  label: string;
} {
  const normalized = normalizeOperatingPackMatchText(text ?? "");
  if (/\b(?:rejeitado|rejeitar|recusado|nao aprovado|nao usar|ruim)\b/.test(normalized)) {
    return { feedbackStatus: "rejected", humanReviewStatus: "rejected", label: "rejected" };
  }
  if (/\b(?:feito|executado|concluido|concluida|usei|publicado|enviado)\b/.test(normalized)) {
    return { feedbackStatus: "completed", humanReviewStatus: "approved", label: "completed" };
  }
  if (/\b(?:ajustar|ajuste|corrigir|melhorar|revisar)\b/.test(normalized)) {
    return { feedbackStatus: "pending", humanReviewStatus: "needs_review", label: "needs-review" };
  }
  if (/\b(?:aprovado|aprovei|aceito|ok|bom|vou usar|valido)\b/.test(normalized)) {
    return { feedbackStatus: "accepted", humanReviewStatus: "approved", label: "accepted" };
  }
  return { feedbackStatus: "pending", humanReviewStatus: "pending", label: "pending" };
}

function ensureOperatingPackSource(
  sourceId: string | null | undefined,
  timestamp: number,
  visibility: Visibility
): string {
  const db = getDb();
  const preferredSourceId = sourceId?.trim() || TELEGRAM_BOT_GATEWAY_SOURCE_ID;
  const existing = db.select().from(cbSources).where(eq(cbSources.id, preferredSourceId)).get();
  if (existing) return existing.id;

  db.insert(cbSources)
    .values({
      id: preferredSourceId,
      name: preferredSourceId === TELEGRAM_BOT_GATEWAY_SOURCE_ID
        ? "Telegram Bot Gateway"
        : `Operating Pack Source ${preferredSourceId}`,
      sourceType: "runtime",
      area: "marketing",
      externalRef: preferredSourceId === TELEGRAM_BOT_GATEWAY_SOURCE_ID
        ? "telegram://aios-bots"
        : `aios://operating-pack-sources/${preferredSourceId}`,
      status: "active",
      healthStatus: "healthy",
      owner: "Felhen",
      ownerType: "team",
      visibility,
      lastSyncAt: timestamp,
      syncError: null,
      metadata: {
        createdBy: "company_brain:operating_pack_runner",
        sourceRole: "gateway",
      },
      createdAt: timestamp,
      updatedAt: timestamp,
    })
    .run();
  return preferredSourceId;
}

function createOperatingPackArtifact(args: {
  sourceId: string;
  artifactType: string;
  area: CompanyBrainArea;
  title: string;
  summary: string;
  rawRef: string;
  author: string | null;
  visibility: Visibility;
  humanReviewStatus: ReviewStatus;
  confidence: number;
  metadata: Record<string, unknown>;
  timestamp: number;
}): CompanyBrainOperatingPackArtifactRef {
  const db = getDb();
  const source = db.select().from(cbSources).where(eq(cbSources.id, args.sourceId)).get();
  if (!source) throw new Error("sourceId not found");

  const artifactName = String(args.metadata.artifactName ?? args.title);
  const semanticKey = String(args.metadata.semanticKey ?? artifactName);
  const row = {
    id: nanoid(12),
    sourceId: args.sourceId,
    artifactType: args.artifactType,
    area: args.area,
    title: args.title,
    summary: args.summary,
    contentRef: null,
    rawRef: args.rawRef,
    author: args.author,
    occurredAt: args.timestamp,
    ingestedAt: args.timestamp,
    hash: stableHash(`${args.sourceId}:${args.rawRef}:${args.title}:${args.summary}`),
    visibility: args.visibility,
    provenance: {
      sourceId: args.sourceId,
      rawRef: args.rawRef,
      createdFrom: "company_brain:operating_pack_runner",
      confidence: args.confidence,
      extractedAt: args.timestamp,
      humanReviewStatus: args.humanReviewStatus,
      visibility: args.visibility,
      retentionPolicy: "ephemeral_by_default_promoted_by_human",
      notes: `artifactName=${artifactName}; semanticKey=${semanticKey}`,
    },
    humanReviewStatus: args.humanReviewStatus,
    confidence: args.confidence,
    metadata: args.metadata,
  };
  db.insert(cbArtifacts).values(row as never).run();
  return {
    id: row.id,
    artifactType: row.artifactType,
    title: row.title,
    rawRef: row.rawRef,
    artifactName,
    semanticKey,
  };
}

function buildOperatingPackResponse(args: {
  timestamp: number;
  request: RunCompanyBrainOperatingPackRequest;
  router: CompanyBrainCommandRouterResult;
  handled: boolean;
  packSlug: CompanyBrainOperatingPackSlug | null;
  action: CompanyBrainOperatingPackAction;
  responseText: string;
  memoryPolicy: CompanyBrainOperatingPackMemoryPolicy;
  promotedArtifact?: CompanyBrainOperatingPackArtifactRef | null;
  feedbackArtifact?: CompanyBrainOperatingPackArtifactRef | null;
  guidanceUpdated?: { id: string; feedbackStatus: GuidanceFeedbackStatus } | null;
  suggestedCommands?: string[];
}): CompanyBrainOperatingPackRunResponse {
  return {
    generatedAt: args.timestamp,
    handled: args.handled,
    packSlug: args.packSlug ?? undefined,
    action: args.action,
    request: args.request,
    router: args.router,
    responseText: args.responseText,
    memoryPolicy: args.memoryPolicy,
    noExternalAction: true,
    promotedArtifact: args.promotedArtifact ?? null,
    feedbackArtifact: args.feedbackArtifact ?? null,
    guidanceUpdated: args.guidanceUpdated ?? null,
    suggestedCommands: args.suggestedCommands ?? [],
  };
}

function runMarketingNr1OperatingPack(args: {
  request: RunCompanyBrainOperatingPackRequest;
  router: CompanyBrainCommandRouterResult;
  action: CompanyBrainOperatingPackAction;
  timestamp: number;
}): CompanyBrainOperatingPackRunResponse {
  const { request, router, action, timestamp } = args;
  const visibility = request.visibility ?? "internal";
  const actor = request.actor ?? "telegram";
  const guidance = getMarketingNr1Guidance();
  const briefing = buildMarketingNr1BriefingText(request, guidance);
  const sourceId = ensureOperatingPackSource(request.sourceId ?? null, timestamp, visibility);

  if (action === "feedback") {
    const note = request.feedbackNote ?? request.text;
    const targetArtifactId = request.targetArtifactId?.trim();
    const feedback = normalizeMarketingFeedbackStatus(request.feedbackStatus ?? note);
    if (!targetArtifactId) {
      return buildOperatingPackResponse({
        timestamp,
        request,
        router,
        handled: true,
        packSlug: "marketing.nr1",
        action,
        responseText: [
          "Feedback HITL nao registrado.",
          "Falta o artifact tecnico do briefing promovido.",
          "Use /aios feedback <artifactId> aprovado|rejeitado|executado [nota].",
          "Nenhum envio externo foi executado.",
        ].join("\n"),
        memoryPolicy: "promote_required",
        suggestedCommands: ["/aios feedback <artifactId> aprovado [nota]"],
      });
    }

    const identity = buildMarketingNr1FeedbackIdentity(
      targetArtifactId,
      feedback.feedbackStatus,
      timestamp
    );
    let feedbackArtifact: CompanyBrainOperatingPackArtifactRef | null = null;
    let guidanceUpdated: { id: string; feedbackStatus: GuidanceFeedbackStatus } | null = null;
    if (request.dryRun !== true) {
      feedbackArtifact = createOperatingPackArtifact({
        sourceId,
        artifactType: "marketing_feedback",
        area: "marketing",
        title: `Marketing NR-1 feedback - ${feedback.label}`,
        summary: `Feedback HITL para briefing ${targetArtifactId}: ${note}`,
        rawRef: identity.rawRef,
        author: actor,
        visibility,
        humanReviewStatus: feedback.humanReviewStatus,
        confidence: 1,
        metadata: {
          packSlug: "marketing.nr1",
          action: "feedback",
          artifactName: identity.artifactName,
          semanticKey: identity.semanticKey,
          namingScheme: "operating-pack-semantic-v1",
          targetArtifactId,
          feedbackStatus: feedback.feedbackStatus,
          feedbackNote: note,
          sourceChannel: request.channel ?? null,
        },
        timestamp,
      });

      if (guidance) {
        const nextStatus =
          feedback.feedbackStatus === "completed"
            ? "done"
            : feedback.feedbackStatus === "accepted"
              ? "accepted"
              : guidance.status;
        getDb()
          .update(cbGuidanceItems)
          .set({
            status: nextStatus,
            feedbackStatus: feedback.feedbackStatus,
            feedbackNote: note,
            feedbackAt: timestamp,
            updatedAt: timestamp,
          })
          .where(eq(cbGuidanceItems.id, guidance.id))
          .run();
        guidanceUpdated = {
          id: guidance.id,
          feedbackStatus: feedback.feedbackStatus,
        };
      }
    }

    return buildOperatingPackResponse({
      timestamp,
      request,
      router,
      handled: true,
      packSlug: "marketing.nr1",
      action,
      responseText: [
        request.dryRun === true ? "Feedback HITL preview" : "Feedback HITL registrado",
        `Briefing: ${targetArtifactId}`,
        `Status: ${feedback.feedbackStatus}`,
        `Nota: ${note}`,
        feedbackArtifact ? `Artifact feedback: ${feedbackArtifact.id}` : null,
        feedbackArtifact ? `Nome: ${feedbackArtifact.artifactName}` : null,
        guidanceUpdated ? `Guidance atualizada: ${guidanceUpdated.id} (${guidanceUpdated.feedbackStatus})` : null,
        "Nenhum envio externo foi executado.",
      ]
        .filter(Boolean)
        .join("\n"),
      memoryPolicy: request.dryRun === true ? "promote_required" : "promoted",
      feedbackArtifact,
      guidanceUpdated,
      suggestedCommands: ["/aios briefing marketing nr-1"],
    });
  }

  if (action === "promote") {
    const identity = buildMarketingNr1BriefingIdentity(briefing.segment, timestamp);
    let promotedArtifact: CompanyBrainOperatingPackArtifactRef | null = null;
    if (request.dryRun !== true) {
      promotedArtifact = createOperatingPackArtifact({
        sourceId,
        artifactType: "marketing_briefing",
        area: "marketing",
        title: `Marketing NR-1 briefing - ${briefing.segment}`,
        summary: briefing.briefingContent,
        rawRef: identity.rawRef,
        author: actor,
        visibility,
        humanReviewStatus: "approved",
        confidence: router.classification.confidence,
        metadata: {
          packSlug: "marketing.nr1",
          action: "promote",
          artifactName: identity.artifactName,
          semanticKey: identity.semanticKey,
          namingScheme: "operating-pack-semantic-v1",
          segment: briefing.segment,
          guidanceId: briefing.guidanceId,
          promoteReason: request.promoteReason ?? null,
          sourceChannel: request.channel ?? null,
          memoryPolicy: "promoted_by_human",
        },
        timestamp,
      });
    }

    return buildOperatingPackResponse({
      timestamp,
      request,
      router,
      handled: true,
      packSlug: "marketing.nr1",
      action,
      responseText: [
        request.dryRun === true
          ? "Promocao AIOS preview"
          : "Briefing promovido para memoria AIOS",
        promotedArtifact ? `Nome: ${promotedArtifact.artifactName}` : `Nome: ${identity.artifactName}`,
        promotedArtifact ? `ID tecnico: ${promotedArtifact.id}` : "ID tecnico: preview",
        `Ref: ${identity.rawRef}`,
        request.promoteReason ? `Motivo: ${request.promoteReason}` : null,
        "Politica: este briefing foi persistido somente por comando explicito.",
        "Nenhum envio externo foi executado.",
      ]
        .filter(Boolean)
        .join("\n"),
      memoryPolicy: request.dryRun === true ? "promote_required" : "promoted",
      promotedArtifact,
      suggestedCommands: promotedArtifact
        ? [`/aios feedback ${promotedArtifact.id} aprovado [nota]`]
        : ["/aios promover briefing [motivo]"],
    });
  }

  return buildOperatingPackResponse({
    timestamp,
    request,
    router,
    handled: true,
    packSlug: "marketing.nr1",
    action,
    responseText: briefing.responseText,
    memoryPolicy: "ephemeral",
    suggestedCommands: ["/aios promover briefing [motivo]"],
  });
}

app.post("/operating-packs/run", async (c) => {
  try {
    const body = (await c.req
      .json<RunCompanyBrainOperatingPackRequest>()
      .catch(() => ({ text: "" } as RunCompanyBrainOperatingPackRequest))) as RunCompanyBrainOperatingPackRequest;
    if (!body.text || !body.text.trim()) {
      return c.json({ error: "validation", message: "text is required" }, 400);
    }

    const timestamp = now();
    const action = inferOperatingPackAction(body);
    const explicitEntry = getOperatingPackRegistryEntry(body.packSlug);
    const matchedEntry =
      explicitEntry ??
      findOperatingPackRegistryEntryForText(body.text, {
        executionModes: ["operating_pack_runner"],
      }) ??
      (action !== "run" ? getDefaultOperatingPackRunnerEntry() : null);
    const preliminaryPackSlug = matchedEntry?.slug ?? null;
    const router = buildOperatingPackRouterResult(body, timestamp, preliminaryPackSlug);
    const request: RunCompanyBrainOperatingPackRequest = {
      ...body,
      action,
      packSlug: preliminaryPackSlug ?? body.packSlug,
      text: body.text.trim(),
      visibility: body.visibility ?? "internal",
    };
    const packSlug = inferOperatingPackSlug(request, router) ?? preliminaryPackSlug;

    if (packSlug === "marketing.nr1") {
      const result = runMarketingNr1OperatingPack({
        request,
        router,
        action,
        timestamp,
      });
      return c.json({ data: result });
    }

    const result = buildOperatingPackResponse({
      timestamp,
      request,
      router,
      handled: false,
      packSlug,
      action,
      responseText: formatCommandRouterPreview(router),
      memoryPolicy: "ephemeral",
      suggestedCommands: [],
    });
    return c.json({ data: result });
  } catch (err) {
    const message = err instanceof Error ? err.message : "Unknown error";
    return c.json({ error: "operating_pack_run_failed", message }, 400);
  }
});

app.get("/operating-packs", (c) => {
  return c.json({ data: buildOperatingPackRegistry() });
});

function buildOperationalSkillRefFromRegistryEntry(
  entry: CompanyBrainOperatingPackRegistryEntry | null
): CompanyBrainOperationalSkillRef | null {
  if (!entry || entry.executionMode !== "agent_route_skill") return null;
  if (entry.slug !== "operations.pulso_dags") return null;
  return {
    slug: entry.slug,
    title: entry.title,
    area: entry.area,
    docsPath: entry.docsPath,
    summary: entry.summary,
    memoryPolicy: entry.memoryPolicy,
  };
}

function findAgentRouteSkillRegistryEntry(
  text: string
): CompanyBrainOperatingPackRegistryEntry | null {
  return findOperatingPackRegistryEntryForText(text, {
    executionModes: ["agent_route_skill"],
  });
}

function buildAgentRouteRouterResult(
  request: ResolveCompanyBrainAgentRouteRequest,
  timestamp: number,
  preliminarySkill: CompanyBrainOperationalSkillRef | null
): CompanyBrainCommandRouterResult {
  const routerRequest: RouteCompanyBrainCommandRequest = {
    text: request.text,
    area: request.area ?? preliminarySkill?.area,
    actor: request.actor ?? null,
    visibility: request.visibility ?? "internal",
    dryRun: true,
  };
  const classification = buildCommandRouterClassification(routerRequest);
  const routing = executeCommandRouterClassification(routerRequest, classification, timestamp);
  return {
    generatedAt: timestamp,
    request: routerRequest,
    classification,
    routing,
  };
}

function resolveAgentRouteSkill(
  request: ResolveCompanyBrainAgentRouteRequest,
  router: CompanyBrainCommandRouterResult
): CompanyBrainOperationalSkillRef | null {
  const matchedEntry = findAgentRouteSkillRegistryEntry(request.text);
  if (matchedEntry) return buildOperationalSkillRefFromRegistryEntry(matchedEntry);

  const areaEntry = OPERATING_PACK_REGISTRY_ENTRIES.find(
    (entry) =>
      entry.status === "active" &&
      entry.executionMode === "agent_route_skill" &&
      entry.area === router.classification.area &&
      operatingPackRegistryEntryMatchesText(entry, request.text)
  );
  return buildOperationalSkillRefFromRegistryEntry(areaEntry ?? null);
}

function resolveAgentRouteCwd(
  router: CompanyBrainCommandRouterResult,
  skill: CompanyBrainOperationalSkillRef | null
): string {
  if (skill?.slug === "operations.pulso_dags") {
    return config.companyBrainAgentRouting.pulsoBackendCwd;
  }

  switch (router.classification.area) {
    case "marketing":
      return config.companyBrainAgentRouting.marketingCwd;
    case "strategy":
    case "sales":
    case "finance":
    case "people":
      return config.companyBrainAgentRouting.corpCwd;
    case "platform":
      return config.companyBrainAgentRouting.runtimeCwd;
    case "development":
    case "operations":
    case "product":
    case "customer":
    case "unknown":
    default:
      return config.companyBrainAgentRouting.projectsCwd;
  }
}

function buildAgentRoutePrompt(args: {
  request: ResolveCompanyBrainAgentRouteRequest;
  router: CompanyBrainCommandRouterResult;
  skill: CompanyBrainOperationalSkillRef | null;
  executionCwd: string;
}): string {
  const { request, router, skill, executionCwd } = args;
  const header = [
    "AIOS routed agent request",
    `Channel: ${request.channel ?? "unknown"}`,
    `Actor: ${request.actor ?? "unknown"}`,
    `Area: ${router.classification.area}`,
    `Intent: ${router.classification.intentKind}`,
    `Risk: ${router.classification.riskClass}`,
    `Execution cwd: ${executionCwd}`,
  ];

  const commonRules = [
    "AIOS rules:",
    "1. Treat this as an AIOS-governed request regardless of the channel that delivered it.",
    "2. Read local AGENTS.md and relevant docs/skills before acting when the checkout has them.",
    "3. Start read-only. Do not perform external sends, destructive actions, deploys, restarts, reruns, retries, unpauses or writes unless the user explicitly asked for that action and HITL is clear.",
    "4. Keep temporary operational output ephemeral. Persist to Company Brain only for strategic learning, incident evidence, repeated failure, accepted guidance or explicit user promotion.",
    "5. Return a concise operational answer with evidence, impact, recommended next action and any HITL needed.",
  ];

  const skillRules =
    skill?.slug === "operations.pulso_dags"
      ? [
          "",
          "Operational skill: operations.pulso_dags",
          `Skill docs: ${skill.docsPath}`,
          "Pulso local skill to reuse when current: .claude/skills/dag-check.md",
          "Pulso DAG rules:",
          "0. Live Pulso Airflow is on GCP: pulso-live-airflow in project felhen-pulso-live-prod, zone southamerica-east1-b. VM200/airflow-200 is legacy cold rollback and must not be used to determine current production DAG status.",
          "1. Verify scheduled DAG health using the Pulso checkout context, Airflow metadata/API and docs/architecture/etl-flow.md.",
          "2. Separate execution status, structural timeout/error, output freshness/volume and customer impact.",
          "3. Classify active DAGs into mutually exclusive categories: ran ok, failed, outside schedule, anomaly. Do not report generic success ratios that include DAGs outside today's schedule.",
          "4. If failures have later successful reruns, report them as historical noise unless there is remaining business impact.",
          "5. List corrective actions only. Do not rerun, restart, unpause or backfill unless the user explicitly asks.",
          "6. Prefer gcloud compute ssh pulso-live-airflow --project=felhen-pulso-live-prod --zone=southamerica-east1-b --tunnel-through-iap for live Airflow checks; use pulso-live-clickhouse for destination-table freshness.",
          "7. If local docs or skills mention VM200, postgres-201 metastore or airflow-200 as production, treat that as stale context and say so.",
          "8. Keep the Telegram answer under 4000 characters when possible.",
        ]
      : [];

  return [
    ...header,
    "",
    ...commonRules,
    ...skillRules,
    "",
    "Original request:",
    request.text.trim(),
  ].join("\n");
}

function buildAgentRouteResponse(args: {
  timestamp: number;
  request: ResolveCompanyBrainAgentRouteRequest;
  router: CompanyBrainCommandRouterResult;
  skill: CompanyBrainOperationalSkillRef | null;
  executionCwd: string;
}): CompanyBrainAgentRouteResponse {
  const { timestamp, request, router, skill, executionCwd } = args;
  const cwdExists = existsSync(executionCwd);
  const rationale = [
    `Router classified area=${router.classification.area}, intent=${router.classification.intentKind}, target=${router.classification.targetKind}, risk=${router.classification.riskClass}.`,
    skill
      ? `Matched operational skill ${skill.slug}; channel is only transport.`
      : "No operational skill matched; routing to area default executor.",
    cwdExists
      ? `Execution cwd exists: ${executionCwd}.`
      : `Execution cwd configured but not present from daemon host view: ${executionCwd}.`,
  ];

  if (router.classification.riskClass === "C") {
    return {
      generatedAt: timestamp,
      request,
      router,
      executionMode: "blocked",
      decision: "blocked",
      executionCwd: null,
      skill,
      prompt: null,
      responseText: formatCommandRouterPreview(router),
      noExternalAction: true,
      rationale: [
        ...rationale,
        "Risk C is blocked before any agent fallback.",
      ],
    };
  }

  const prompt = buildAgentRoutePrompt({
    request,
    router,
    skill,
    executionCwd,
  });

  return {
    generatedAt: timestamp,
    request,
    router,
    executionMode: "agent_fallback",
    decision: "route_to_agent",
    executionCwd,
    skill,
    prompt,
    responseText: [
      "AIOS agent route",
      skill ? `Skill: ${skill.slug}` : `Area: ${router.classification.area}`,
      `Executor cwd: ${executionCwd}`,
      `Risk: ${router.classification.riskClass} | confianca: ${router.classification.confidence.toFixed(2)}`,
      "Politica: canal e transporte; skill e regras vivem no AIOS.",
      "HITL: nenhuma acao externa foi executada pelo router.",
    ].join("\n"),
    noExternalAction: true,
    rationale,
  };
}

app.post("/agent-routing/resolve", async (c) => {
  try {
    const body = (await c.req
      .json<ResolveCompanyBrainAgentRouteRequest>()
      .catch(() => ({ text: "" } as ResolveCompanyBrainAgentRouteRequest))) as ResolveCompanyBrainAgentRouteRequest;
    if (!body.text || !body.text.trim()) {
      return c.json({ error: "validation", message: "text is required" }, 400);
    }

    const timestamp = now();
    const request: ResolveCompanyBrainAgentRouteRequest = {
      ...body,
      text: body.text.trim(),
      visibility: body.visibility ?? "internal",
    };
    const preliminarySkill = buildOperationalSkillRefFromRegistryEntry(
      findAgentRouteSkillRegistryEntry(request.text)
    );
    const router = buildAgentRouteRouterResult(request, timestamp, preliminarySkill);
    const skill = resolveAgentRouteSkill(request, router);
    const executionCwd = resolveAgentRouteCwd(router, skill);
    const result = buildAgentRouteResponse({
      timestamp,
      request,
      router,
      skill,
      executionCwd,
    });
    return c.json({ data: result });
  } catch (err) {
    const message = err instanceof Error ? err.message : "Unknown error";
    return c.json({ error: "agent_route_resolve_failed", message }, 400);
  }
});

const SESSION_RESULT_DEFAULT_SOURCE_REF = "aios:session-results";
const SESSION_RESULT_DEFAULT_SOURCE_NAME = "AIOS Session Results";

function ensureSessionResultsSource(
  area: CompanyBrainArea,
  visibility: Visibility,
  timestamp: number
): string {
  const db = getDb();
  const existing = db
    .select()
    .from(cbSources)
    .where(eq(cbSources.externalRef, SESSION_RESULT_DEFAULT_SOURCE_REF))
    .get();
  if (existing) return existing.id;
  const id = nanoid(12);
  db.insert(cbSources)
    .values({
      id,
      name: SESSION_RESULT_DEFAULT_SOURCE_NAME,
      sourceType: "runtime",
      area,
      externalRef: SESSION_RESULT_DEFAULT_SOURCE_REF,
      status: "active",
      healthStatus: "healthy",
      owner: "Felhen",
      ownerType: "team",
      visibility,
      lastSyncAt: timestamp,
      syncError: null,
      metadata: { runtime: SESSION_RESULT_DEFAULT_SOURCE_REF },
      createdAt: timestamp,
      updatedAt: timestamp,
    })
    .run();
  return id;
}

function findWorkItemForSessionResult(
  workItemId: string | null | undefined,
  externalIssueRef: string | null | undefined
): WorkItem | null {
  const db = getDb();
  if (workItemId) {
    const row = db
      .select()
      .from(cbWorkItems)
      .where(eq(cbWorkItems.id, workItemId))
      .get();
    if (row) return row as unknown as WorkItem;
  }
  if (externalIssueRef) {
    const all = db.select().from(cbWorkItems).all() as unknown as WorkItem[];
    const found = all.find((item) => item.externalId === externalIssueRef);
    if (found) return found;
  }
  return null;
}

function sessionResultSignalSource(
  outcome: SessionResultOutcome,
  validationStatus?: SessionResultValidation["status"]
): SignalSource {
  if (validationStatus === "failed") return "qa";
  if (outcome === "failed") return "error";
  if (outcome === "blocked") return "feedback";
  return "feedback";
}

app.post("/session-results", async (c) => {
  try {
    const db = getDb();
    const body = (await c.req
      .json<SubmitSessionResultRequest>()
      .catch(() => ({}))) as SubmitSessionResultRequest;
    if (!body.summary || !body.summary.trim()) {
      return c.json({ error: "validation", message: "summary is required" }, 400);
    }
    if (!body.runnerType) {
      return c.json({ error: "validation", message: "runnerType is required" }, 400);
    }
    if (!body.outcome) {
      return c.json({ error: "validation", message: "outcome is required" }, 400);
    }

    const timestamp = now();
    const visibility = body.visibility ?? "internal";

    const workItemRow = findWorkItemForSessionResult(
      body.workItemId ?? null,
      body.externalIssueRef ?? null
    );
    const area: CompanyBrainArea =
      body.area ?? workItemRow?.area ?? "platform";
    const sourceId = workItemRow?.sourceId
      ? workItemRow.sourceId
      : ensureSessionResultsSource(area, visibility, timestamp);

    const rawRef = `aios://session-result/${nanoid(8)}-${timestamp}`;
    const hashPayload = JSON.stringify({
      runnerType: body.runnerType,
      outcome: body.outcome,
      summary: body.summary,
      workItemId: workItemRow?.id ?? null,
      prUrl: body.prUrl ?? null,
      timestamp,
    });
    const hash = createHash("sha256").update(hashPayload).digest("hex");

    const metadata: Record<string, unknown> = {
      runnerType: body.runnerType,
      outcome: body.outcome,
    };
    if (body.workItemId) metadata.workItemId = body.workItemId;
    if (body.workflowRunId) metadata.workflowRunId = body.workflowRunId;
    if (body.externalIssueRef) metadata.externalIssueRef = body.externalIssueRef;
    if (body.branch) metadata.branch = body.branch;
    if (body.prUrl) metadata.prUrl = body.prUrl;
    if (body.workspaceRef) metadata.workspaceRef = body.workspaceRef;
    if (body.commits?.length) metadata.commits = body.commits;
    if (body.changedFiles?.length) metadata.changedFiles = body.changedFiles;
    if (body.validations?.length) metadata.validations = body.validations;
    if (body.blockers?.length) metadata.blockers = body.blockers;
    if (body.nextSteps?.length) metadata.nextSteps = body.nextSteps;
    if (body.startedAt) metadata.startedAt = body.startedAt;
    if (body.finishedAt) metadata.finishedAt = body.finishedAt;
    if (body.tokensInput !== undefined && body.tokensInput !== null) {
      metadata.tokensInput = body.tokensInput;
    }
    if (body.tokensOutput !== undefined && body.tokensOutput !== null) {
      metadata.tokensOutput = body.tokensOutput;
    }
    if (body.tokensTotal !== undefined && body.tokensTotal !== null) {
      metadata.tokensTotal = body.tokensTotal;
    }
    if (body.costUsd !== undefined && body.costUsd !== null) {
      metadata.costUsd = body.costUsd;
    }
    if (body.agentSessionId) metadata.agentSessionId = body.agentSessionId;
    if (body.agentThreadId) metadata.agentThreadId = body.agentThreadId;
    if (body.detail) metadata.detail = body.detail;

    const titleParts: string[] = [];
    if (workItemRow) titleParts.push(workItemRow.title);
    else if (body.externalIssueRef) titleParts.push(body.externalIssueRef);
    titleParts.push(`(${body.runnerType}/${body.outcome})`);
    const artifactTitle = `Session result: ${titleParts.join(" ")}`.slice(0, 240);

    const artifactId = nanoid(12);
    const artifactRow: Artifact = {
      id: artifactId,
      sourceId,
      artifactType: "session_result",
      area,
      title: artifactTitle,
      summary: body.summary,
      contentRef: body.detail ?? null,
      rawRef,
      author: body.actor ?? null,
      occurredAt: body.finishedAt ?? timestamp,
      ingestedAt: timestamp,
      hash,
      visibility,
      provenance: {
        sourceId,
        rawRef,
        artifactId,
        createdFrom: "company_brain:session_result_intake",
        confidence: 1,
        extractedAt: timestamp,
        humanReviewStatus: "pending",
        visibility,
        notes: `runner=${body.runnerType}; outcome=${body.outcome}`,
      },
      humanReviewStatus: "pending",
      confidence: 1,
      metadata,
    };
    db.insert(cbArtifacts).values(artifactRow as never).run();

    let workItemUpdated = false;
    let prLinkRecorded = false;
    if (workItemRow) {
      const updates: Record<string, unknown> = { updatedAt: timestamp };
      let dirty = false;
      if (body.prUrl) {
        prLinkRecorded = true;
      }
      if (
        body.outcome === "pr_opened" &&
        ["new", "triage", "planned", "in_progress"].includes(workItemRow.status)
      ) {
        updates.status = "review";
        dirty = true;
      } else if (
        body.outcome === "awaiting_review" &&
        ["new", "triage", "planned", "in_progress"].includes(workItemRow.status)
      ) {
        updates.status = "review";
        dirty = true;
      } else if (body.outcome === "blocked") {
        updates.blockedReason = body.summary.slice(0, 500);
        updates.status = "blocked";
        dirty = true;
      } else if (body.outcome === "failed") {
        updates.blockedReason = body.summary.slice(0, 500);
        updates.status = "needs_human";
        dirty = true;
      }
      if (!workItemRow.artifactId) {
        updates.artifactId = artifactId;
        dirty = true;
      }
      if (dirty) {
        db.update(cbWorkItems)
          .set(updates)
          .where(eq(cbWorkItems.id, workItemRow.id))
          .run();
        workItemUpdated = true;
      }
    }

    const signalsCreated: Signal[] = [];
    const insertSignal = (input: {
      summary: string;
      severity: SignalSeverity;
      source: SignalSource;
      tags: string[];
      metadataExtra: Record<string, unknown>;
      noteSuffix: string;
    }) => {
      const signalId = nanoid(12);
      const signalRow = {
        id: signalId,
        source: input.source,
        scope: "core" as const,
        entityType: "job" as const,
        entityId: workItemRow?.id ?? artifactId,
        timestamp,
        summary: input.summary,
        rawRef,
        severity: input.severity,
        confidence: 0.9,
        tags: input.tags,
        area,
        sourceId,
        artifactId,
        workItemId: workItemRow?.id ?? null,
        workflowRunId: body.workflowRunId ?? null,
        watcherId: null,
        watcherRunId: null,
        visibility,
        provenance: {
          sourceId,
          rawRef,
          artifactId,
          createdFrom: `company_brain:session_result_intake:${input.noteSuffix}`,
          confidence: 0.9,
          extractedAt: timestamp,
          humanReviewStatus: "pending" as const,
          visibility,
          notes: `runner=${body.runnerType}; outcome=${body.outcome}; ${input.noteSuffix}`,
        },
        metadata: input.metadataExtra,
        createdAt: timestamp,
        updatedAt: timestamp,
      };
      db.insert(cbSignals).values(signalRow as never).run();
      signalsCreated.push(signalRow as unknown as Signal);
    };

    if (body.blockers?.length) {
      for (const blocker of body.blockers) {
        insertSignal({
          summary: blocker.description,
          severity: blocker.severity ?? "warn",
          source: "feedback",
          tags: ["session_result", "blocker", body.runnerType, blocker.kind],
          metadataExtra: { blocker },
          noteSuffix: `blocker:${blocker.kind}`,
        });
      }
    }
    if (body.validations?.length) {
      for (const validation of body.validations) {
        if (validation.status !== "failed") continue;
        insertSignal({
          summary: `Validation failed: ${validation.kind}${
            validation.notes ? ` - ${validation.notes}` : ""
          }`,
          severity: "critical",
          source: sessionResultSignalSource(body.outcome, validation.status),
          tags: [
            "session_result",
            "validation_failed",
            body.runnerType,
            validation.kind,
          ],
          metadataExtra: { validation },
          noteSuffix: `validation_failed:${validation.kind}`,
        });
      }
    }
    if (body.outcome === "failed" && !body.validations?.some((v) => v.status === "failed")) {
      insertSignal({
        summary: `Session reported outcome=failed: ${body.summary.slice(0, 200)}`,
        severity: "critical",
        source: "error",
        tags: ["session_result", "outcome_failed", body.runnerType],
        metadataExtra: {},
        noteSuffix: "outcome_failed",
      });
    }

    const guidanceCreated: GuidanceItem[] = [];
    if (body.nextSteps?.length) {
      for (const next of body.nextSteps) {
        const guidanceId = nanoid(12);
        const guidanceRow = {
          id: guidanceId,
          audience: next.audience ?? "human",
          priorityId: workItemRow?.priorityId ?? null,
          goalId: workItemRow?.goalId ?? null,
          findingId: null,
          signalId: null,
          workItemId: workItemRow?.id ?? null,
          workflowRunId: body.workflowRunId ?? null,
          area,
          title: next.action.slice(0, 120),
          action: next.action,
          dueAt: null,
          severity: next.severity ?? "info",
          status: "new" as const,
          feedbackStatus: "pending" as const,
          feedbackNote: null,
          feedbackAt: null,
          generatedFrom: {
            sessionResultArtifactId: artifactId,
            runnerType: body.runnerType,
            outcome: body.outcome,
          },
          visibility,
          provenance: {
            sourceId,
            rawRef,
            artifactId,
            createdFrom: "company_brain:session_result_intake:next_step",
            confidence: 0.9,
            extractedAt: timestamp,
            humanReviewStatus: "pending" as const,
            visibility,
            notes: `runner=${body.runnerType}; outcome=${body.outcome}`,
          },
          createdAt: timestamp,
          updatedAt: timestamp,
        };
        db.insert(cbGuidanceItems).values(guidanceRow as never).run();
        guidanceCreated.push(guidanceRow as unknown as GuidanceItem);
      }
    }

    let updatedWorkItem: WorkItem | null = null;
    if (workItemRow) {
      const refreshed = db
        .select()
        .from(cbWorkItems)
        .where(eq(cbWorkItems.id, workItemRow.id))
        .get();
      if (refreshed) updatedWorkItem = refreshed as unknown as WorkItem;
    }

    const response: SubmitSessionResultResponse = {
      artifact: artifactRow,
      workItem: updatedWorkItem,
      signalsCreated,
      guidanceItemsCreated: guidanceCreated,
      workItemUpdated,
      prLinkRecorded,
      metadataMerged: metadata,
    };
    return c.json({ data: response });
  } catch (err) {
    const message = err instanceof Error ? err.message : "Unknown error";
    return c.json({ error: "session_result_failed", message }, 400);
  }
});

app.get("/operating-cadence", (c) => {
  const data = buildOperatingCadence(listAll());
  return c.json({ data });
});

export async function runCompanyBrainOperatingCadence(
  body: RunOperatingCadenceRequest = {}
): Promise<RunOperatingCadenceResponse> {
  const startedAt = now();
  const requestedWatcherIds = body.watcherIds?.length
    ? body.watcherIds
    : body.mode === "due"
      ? buildOperatingCadence(listAll()).watchers
          .filter(
            (watcher) =>
              OPERATING_CADENCE_WATCHER_IDS.includes(watcher.watcherId) &&
              watcher.actionPolicy === "observe_only" &&
              ["due", "stale"].includes(watcher.cadenceStatus)
          )
          .map((watcher) => watcher.watcherId)
      : OPERATING_CADENCE_WATCHER_IDS;
  const scheduleId = body.scheduleId ?? "company-brain:operating-cadence-v0";
  const scheduledAt = body.scheduledAt ?? startedAt;
  const runs: RunOperatingCadenceResponse["runs"] = [];

  const runPrCi = requestedWatcherIds.includes(GITHUB_PR_CI_WATCHER_ID);
  if (runPrCi) {
    try {
      const result = await runGitHubPrCiWatcherSync({
        repo: body.githubPrCi?.repo ?? OPERATING_CADENCE_DEFAULT_REPO,
        state: body.githubPrCi?.state ?? "open",
        limit: body.githubPrCi?.limit ?? 5,
        sourceId: body.githubPrCi?.sourceId ?? null,
        sourceName:
          body.githubPrCi?.sourceName ??
          "Felhen GitHub PR/CI scheduled cadence watcher",
        area: body.githubPrCi?.area ?? "development",
        owner: body.githubPrCi?.owner ?? "Felhen",
        visibility: body.githubPrCi?.visibility ?? "internal",
        createSignals: body.githubPrCi?.createSignals ?? true,
        triggerSource: "schedule",
        scheduleId,
        scheduledAt,
      });
      runs.push({
        watcherId: GITHUB_PR_CI_WATCHER_ID,
        status: result.watcherRun.status,
        watcherRunId: result.watcherRun.id,
        artifactId: result.watcherRun.artifactsCreated[0] ?? null,
        triggerRef: result.watcherRun.triggerRef,
        artifactsCreated: result.artifactsCreated.length,
        signalsCreated: result.signalsCreated.length,
        errorSummary: result.watcherRun.errorSummary,
      });
    } catch (err) {
      const lastFailedRun = lastRunForWatcher(
        getDb().select().from(cbWatcherRuns).all(),
        GITHUB_PR_CI_WATCHER_ID
      );
      runs.push({
        watcherId: GITHUB_PR_CI_WATCHER_ID,
        status: "failed",
        watcherRunId: lastFailedRun?.id ?? null,
        artifactId: lastFailedRun?.artifactsCreated[0] ?? null,
        triggerRef: lastFailedRun?.triggerRef ?? null,
        artifactsCreated: 0,
        signalsCreated: 0,
        errorSummary: err instanceof Error ? err.message : "Unknown error",
      });
    }
  }

  const runBriefing = requestedWatcherIds.includes(AIOS_BRIEFING_WATCHER_ID);
  if (runBriefing) {
    const watcher = getDb()
      .select()
      .from(cbWatchers)
      .where(eq(cbWatchers.id, AIOS_BRIEFING_WATCHER_ID))
      .get();
    if (watcher) {
      try {
        const result = runAiosBriefingWatcher({
          watcher,
          startedAt: now(),
          runId: nanoid(12),
          triggerSource: "schedule",
          scheduleId,
          scheduledAt,
        });
        runs.push({
          watcherId: AIOS_BRIEFING_WATCHER_ID,
          status: result.run.status,
          watcherRunId: result.run.id,
          artifactId: result.run.artifactsCreated[0] ?? null,
          triggerRef: result.run.triggerRef,
          artifactsCreated: result.run.artifactsCreated.length,
          signalsCreated: result.run.signalsCreated.length,
          errorSummary: result.run.errorSummary,
        });
      } catch (err) {
        runs.push({
          watcherId: AIOS_BRIEFING_WATCHER_ID,
          status: "failed",
          watcherRunId: null,
          artifactId: null,
          triggerRef: null,
          artifactsCreated: 0,
          signalsCreated: 0,
          errorSummary: err instanceof Error ? err.message : "Unknown error",
        });
      }
    }
  }

  for (const watcherId of requestedWatcherIds) {
    if (!runs.some((run) => run.watcherId === watcherId)) {
      runs.push({
        watcherId,
        status: "skipped",
        watcherRunId: null,
        artifactId: null,
        triggerRef: null,
        artifactsCreated: 0,
        signalsCreated: 0,
        errorSummary: "Watcher is not part of Operating Cadence v0.",
      });
    }
  }

  const operatingCadence = buildOperatingCadence(listAll());

  // Observe-only: generate AgentRun suggestions for next-work without auto-dispatch.
  try {
    generateAgentRunSuggestionsForOperatingLoop({
      scheduleId,
      scheduledAt,
    });
  } catch (err) {
    console.error(
      "[company-brain] generateAgentRunSuggestionsForOperatingLoop failed",
      err
    );
  }

  // Reconcile running AgentRuns + suggestions vs current state (no destructive
  // cleanup, no external writeback). Runs before auto-dispatch so closed
  // WorkItems are not eligible for new dispatch.
  try {
    const reconOutcome = await runOperatingLoopReconciliationTick({
      scheduleId,
      scheduledAt,
    });
    operatingLoopState.lastReconciliationOutcome = reconOutcome;
    operatingLoopState.reconciliationTickCount += 1;
    operatingLoopState.reconciliationFindingsCount += reconOutcome.findings.length;
  } catch (err) {
    console.error(
      "[company-brain] runOperatingLoopReconciliationTick failed",
      err
    );
    operatingLoopState.lastReconciliationOutcome = {
      generatedAt: now(),
      scheduleId,
      scheduledAt,
      scannedRunCount: 0,
      scannedSuggestionCount: 0,
      findings: [],
      errorSummary: err instanceof Error ? err.message : "unknown error",
    };
  }

  // Single-run controlled auto-dispatch (default-blocked).
  // Spawns a subprocess only when AIOS_AGENT_AUTODISPATCH_ENABLED=true and
  // every gate in evaluateAutoDispatchEligibility passes. Max one per tick.
  try {
    const autoOutcome = await runOperatingLoopAutoDispatchTick({
      scheduleId,
      scheduledAt,
    });
    operatingLoopState.lastAutoDispatchOutcome = autoOutcome;
    operatingLoopState.autoDispatchTickCount += 1;
    if (autoOutcome.status === "dispatched") {
      operatingLoopState.autoDispatchSuccessCount += 1;
    } else if (
      autoOutcome.status === "blocked_eligibility" ||
      autoOutcome.status === "blocked_concurrency" ||
      autoOutcome.status === "blocked_cooldown"
    ) {
      operatingLoopState.autoDispatchBlockedCount += 1;
    }
  } catch (err) {
    console.error(
      "[company-brain] runOperatingLoopAutoDispatchTick failed",
      err
    );
    operatingLoopState.lastAutoDispatchOutcome = {
      generatedAt: now(),
      status: "error",
      scheduleId,
      scheduledAt,
      suggestionId: null,
      agentRunId: null,
      blockReasons: [],
      errorSummary: err instanceof Error ? err.message : "unknown error",
      decision: null,
    };
  }

  const response: RunOperatingCadenceResponse = {
    scheduleId,
    scheduledAt,
    runs,
    artifactsCreated: runs.reduce((sum, run) => sum + run.artifactsCreated, 0),
    signalsCreated: runs.reduce((sum, run) => sum + run.signalsCreated, 0),
    watcherRunsCreated: runs.filter((run) => run.watcherRunId).length,
    operatingCadence,
  };
  return response;
}

function buildAgentRunSuggestionSignature(args: {
  workItemId: string;
  runnerType: AgentRunRunnerType;
  policyDecision: RunnerPolicyDecision;
  satisfiedGates: string[];
  blockedGates: string[];
  workItemTitle: string;
  workItemStatus: string;
  workItemUpdatedAt: number;
}): string {
  const payload = JSON.stringify({
    workItemId: args.workItemId,
    runnerType: args.runnerType,
    policyDecision: args.policyDecision,
    satisfiedGates: [...args.satisfiedGates].sort(),
    blockedGates: [...args.blockedGates].sort(),
    workItemTitle: args.workItemTitle,
    workItemStatus: args.workItemStatus,
    workItemUpdatedAt: args.workItemUpdatedAt,
  });
  return createHash("sha256").update(payload).digest("hex");
}

async function runOperatingLoopAutoDispatchTick(args: {
  scheduleId: string | null;
  scheduledAt: number | null;
}): Promise<OperatingLoopAutoDispatchOutcome> {
  const generatedAt = now();
  const baseOutcome: OperatingLoopAutoDispatchOutcome = {
    generatedAt,
    status: "skipped_disabled",
    scheduleId: args.scheduleId,
    scheduledAt: args.scheduledAt,
    suggestionId: null,
    agentRunId: null,
    blockReasons: [],
    errorSummary: null,
    decision: null,
  };

  if (!autoDispatchEnabled()) {
    return baseOutcome;
  }

  const db = getDb();

  // Pick the oldest active suggestion that has not been promoted yet,
  // ordered by createdAt ascending (FIFO). Limit to 1 — single-run dispatch.
  const candidates = db
    .select()
    .from(cbAgentRunSuggestions)
    .where(eq(cbAgentRunSuggestions.status, "active"))
    .orderBy(cbAgentRunSuggestions.createdAt)
    .all() as AgentRunSuggestion[];
  const target = candidates.find((s) => !s.promotedAgentRunId) ?? null;
  if (!target) {
    return { ...baseOutcome, status: "skipped_no_suggestion" };
  }

  const workItem =
    (db
      .select()
      .from(cbWorkItems)
      .where(eq(cbWorkItems.id, target.workItemId))
      .get() as WorkItem | undefined) ?? null;
  if (!workItem) {
    return {
      ...baseOutcome,
      status: "error",
      suggestionId: target.id,
      errorSummary: `WorkItem ${target.workItemId} not found`,
    };
  }

  const eligibility = evaluateAutoDispatchEligibility({
    workItem,
    suggestion: target,
  });

  if (!eligibility.eligible) {
    return {
      ...baseOutcome,
      status:
        eligibility.decision === "blocked_concurrency"
          ? "blocked_concurrency"
          : eligibility.decision === "blocked_cooldown"
            ? "blocked_cooldown"
            : "blocked_eligibility",
      suggestionId: target.id,
      blockReasons: eligibility.blockReasons,
      decision: eligibility.decision,
    };
  }

  const autoActor = eligibility.config.defaultActor;
  const autoRationale = eligibility.config.defaultRationale;

  // Promote internally via the existing endpoint (preserves auto-dispatch
  // policy chain + audit trail).
  let promotedAgentRunId: string | null = null;
  try {
    const promoteResp = await app.request(
      "/agent-run-suggestions/" + target.id + "/promote",
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ actor: autoActor, rationale: autoRationale }),
      }
    );
    if (!promoteResp.ok) {
      const errBody = (await promoteResp.json().catch(() => ({}))) as {
        message?: string;
      };
      return {
        ...baseOutcome,
        status: "error",
        suggestionId: target.id,
        errorSummary: `promote failed: ${errBody.message ?? promoteResp.status}`,
        decision: eligibility.decision,
      };
    }
    const promoted = (await promoteResp.json()) as {
      data: PromoteAgentRunSuggestionResponse;
    };
    promotedAgentRunId = promoted.data.agentRun.id;
  } catch (err) {
    return {
      ...baseOutcome,
      status: "error",
      suggestionId: target.id,
      errorSummary: `promote threw: ${err instanceof Error ? err.message : "unknown"}`,
      decision: eligibility.decision,
    };
  }

  if (!promotedAgentRunId) {
    return {
      ...baseOutcome,
      status: "promoted_only",
      suggestionId: target.id,
      decision: eligibility.decision,
    };
  }

  try {
    const prepareResp = await app.request(
      "/agent-runs/" + promotedAgentRunId + "/workspace/prepare",
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          actor: autoActor,
          rationale: `${autoRationale}; prepare git worktree before auto-dispatch execution`,
          dryRun: false,
        }),
      }
    );
    if (!prepareResp.ok) {
      const errBody = (await prepareResp.json().catch(() => ({}))) as {
        message?: string;
      };
      return {
        ...baseOutcome,
        status: "error",
        suggestionId: target.id,
        agentRunId: promotedAgentRunId,
        errorSummary: `workspace prepare failed: ${errBody.message ?? prepareResp.status}`,
        decision: eligibility.decision,
      };
    }
    const prepared = (await prepareResp.json()) as {
      data?: WorkspacePreparationResult;
    };
    const prepareStatus = prepared.data?.status;
    if (prepareStatus !== "created" && prepareStatus !== "reused") {
      return {
        ...baseOutcome,
        status: "error",
        suggestionId: target.id,
        agentRunId: promotedAgentRunId,
        errorSummary: `workspace prepare status=${prepareStatus ?? "unknown"}; expected created/reused before execute-async`,
        decision: eligibility.decision,
      };
    }
  } catch (err) {
    return {
      ...baseOutcome,
      status: "error",
      suggestionId: target.id,
      agentRunId: promotedAgentRunId,
      errorSummary: `workspace prepare threw: ${err instanceof Error ? err.message : "unknown"}`,
      decision: eligibility.decision,
    };
  }

  // Trigger async execution. Profile selection takes precedence over
  // commandOverride; both produce execute-async commandOverride/argsOverride.
  const execBody: Record<string, unknown> = {
    actor: autoActor,
    rationale: autoRationale,
  };
  if (eligibility.config.profileId) {
    const profile = getRunnerProfile(eligibility.config.profileId);
    if (profile) {
      execBody.commandOverride = profile.command;
      execBody.argsOverride = profile.args;
    }
  } else if (eligibility.config.commandOverride) {
    execBody.commandOverride = eligibility.config.commandOverride;
  }
  try {
    const execResp = await app.request(
      "/agent-runs/" + promotedAgentRunId + "/execute-async",
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(execBody),
      }
    );
    if (!execResp.ok) {
      const errBody = (await execResp.json().catch(() => ({}))) as {
        message?: string;
      };
      return {
        ...baseOutcome,
        status: "error",
        suggestionId: target.id,
        agentRunId: promotedAgentRunId,
        errorSummary: `execute-async failed: ${errBody.message ?? execResp.status}`,
        decision: eligibility.decision,
      };
    }
  } catch (err) {
    return {
      ...baseOutcome,
      status: "error",
      suggestionId: target.id,
      agentRunId: promotedAgentRunId,
      errorSummary: `execute-async threw: ${err instanceof Error ? err.message : "unknown"}`,
      decision: eligibility.decision,
    };
  }

  // Append audit entry on the AgentRun marking it as auto-dispatched.
  try {
    const refreshed = db
      .select()
      .from(cbAgentRuns)
      .where(eq(cbAgentRuns.id, promotedAgentRunId))
      .get() as AgentRun | undefined;
    if (refreshed) {
      const updatedAudit = appendAgentRunAuditEntry(refreshed.auditTrail ?? [], {
        actor: autoActor,
        event: "agent_run_auto_dispatched",
        note: autoRationale,
        metadata: {
          suggestionId: target.id,
          signature: target.signature,
          decision: eligibility.decision,
          scheduleId: args.scheduleId,
          scheduledAt: args.scheduledAt,
        },
      });
      db.update(cbAgentRuns)
        .set({ auditTrail: updatedAudit, updatedAt: now() } as never)
        .where(eq(cbAgentRuns.id, promotedAgentRunId))
        .run();
    }
  } catch (err) {
    console.error(
      "[company-brain] auto-dispatch audit append failed",
      err
    );
  }

  return {
    ...baseOutcome,
    status: "dispatched",
    suggestionId: target.id,
    agentRunId: promotedAgentRunId,
    decision: eligibility.decision,
  };
}

async function runOperatingLoopReconciliationTick(args: {
  scheduleId: string | null;
  scheduledAt: number | null;
}): Promise<OperatingLoopReconciliationOutcome> {
  const generatedAt = now();
  const findings: AgentRunReconciliationFinding[] = [];
  const db = getDb();
  // Heartbeat threshold: 5 minutes since last log update
  const STALE_HEARTBEAT_MS = 5 * 60 * 1000;
  // Default max runtime when AgentRun has no metadata.maxRuntimeMs
  const DEFAULT_MAX_RUNTIME_MS = 60 * 60 * 1000; // 60 min

  let scannedRunCount = 0;
  let scannedSuggestionCount = 0;

  try {
    // 1. Reconcile running/claimed AgentRuns.
    const activeRuns = db
      .select()
      .from(cbAgentRuns)
      .where(
        sqlOr(
          eq(cbAgentRuns.status, "running"),
          eq(cbAgentRuns.status, "claimed")
        )
      )
      .all() as AgentRun[];
    scannedRunCount = activeRuns.length;
    for (const run of activeRuns) {
      const inRegistry = agentRunProcesses.has(run.id);
      // Stale: status=running, started before now, no process in registry,
      // and pid recorded — likely daemon restart
      if (run.status === "running" && run.pid && !inRegistry) {
        const audit = appendAgentRunAuditEntry(run.auditTrail ?? [], {
          actor: "operating-loop:reconciliation",
          event: "agent_run_reconciled_stale_no_process",
          note: "Subprocess registry missing after daemon restart; marked failed.",
          metadata: {
            previousPid: run.pid,
            previousStatus: run.status,
          },
        });
        db.update(cbAgentRuns)
          .set({
            status: "failed",
            errorSummary:
              run.errorSummary ??
              "reconciliation: subprocess registry missing after daemon restart",
            finishedAt: generatedAt,
            auditTrail: audit,
            updatedAt: generatedAt,
          } as never)
          .where(eq(cbAgentRuns.id, run.id))
          .run();
        findings.push({
          kind: "stale_no_process",
          agentRunId: run.id,
          suggestionId: null,
          workItemId: run.workItemId,
          rationale:
            "Subprocess not present in agentRunProcesses Map; daemon restart suspected",
          newStatus: "failed",
          appliedAt: generatedAt,
          evidence: {
            previousPid: run.pid,
            previousStatus: run.status,
          },
        });
        continue;
      }
      // Stale heartbeat
      if (
        run.status === "running" &&
        run.lastLogAt &&
        generatedAt - run.lastLogAt > STALE_HEARTBEAT_MS &&
        !inRegistry
      ) {
        const audit = appendAgentRunAuditEntry(run.auditTrail ?? [], {
          actor: "operating-loop:reconciliation",
          event: "agent_run_reconciled_stale_heartbeat",
          note: `lastLogAt heartbeat exceeded ${STALE_HEARTBEAT_MS}ms; moved to needs_review.`,
          metadata: {
            lastLogAt: run.lastLogAt,
            heartbeatGapMs: generatedAt - run.lastLogAt,
          },
        });
        db.update(cbAgentRuns)
          .set({
            status: "needs_review",
            auditTrail: audit,
            updatedAt: generatedAt,
          } as never)
          .where(eq(cbAgentRuns.id, run.id))
          .run();
        findings.push({
          kind: "stale_heartbeat",
          agentRunId: run.id,
          suggestionId: null,
          workItemId: run.workItemId,
          rationale: `Last log heartbeat ${Math.round((generatedAt - run.lastLogAt) / 1000)}s old, no active subprocess`,
          newStatus: "needs_review",
          appliedAt: generatedAt,
          evidence: {
            lastLogAt: run.lastLogAt,
            heartbeatGapMs: generatedAt - run.lastLogAt,
          },
        });
        continue;
      }
      // Timed out
      const maxRuntimeMs =
        ((run.metadata as Record<string, unknown> | null)?.maxRuntimeMs as
          | number
          | undefined) ?? DEFAULT_MAX_RUNTIME_MS;
      if (
        run.status === "running" &&
        run.startedAt &&
        generatedAt - run.startedAt > maxRuntimeMs &&
        !inRegistry
      ) {
        const audit = appendAgentRunAuditEntry(run.auditTrail ?? [], {
          actor: "operating-loop:reconciliation",
          event: "agent_run_reconciled_timed_out",
          note: `Run exceeded maxRuntimeMs=${maxRuntimeMs}; subprocess no longer in registry; marked timed_out.`,
          metadata: {
            startedAt: run.startedAt,
            ageMs: generatedAt - run.startedAt,
            maxRuntimeMs,
          },
        });
        db.update(cbAgentRuns)
          .set({
            status: "failed",
            errorSummary:
              run.errorSummary ??
              `reconciliation: timed_out (age ${Math.round(
                (generatedAt - run.startedAt) / 1000
              )}s > ${maxRuntimeMs}ms)`,
            finishedAt: generatedAt,
            auditTrail: audit,
            updatedAt: generatedAt,
          } as never)
          .where(eq(cbAgentRuns.id, run.id))
          .run();
        findings.push({
          kind: "timed_out",
          agentRunId: run.id,
          suggestionId: null,
          workItemId: run.workItemId,
          rationale: `Run age ${Math.round((generatedAt - run.startedAt) / 1000)}s exceeds maxRuntimeMs=${maxRuntimeMs}ms`,
          newStatus: "failed",
          appliedAt: generatedAt,
          evidence: {
            startedAt: run.startedAt,
            ageMs: generatedAt - run.startedAt,
            maxRuntimeMs,
          },
        });
        continue;
      }
    }

    // 2. Reconcile suggestions linked to closed/done WorkItems.
    const activeSuggestions = db
      .select()
      .from(cbAgentRunSuggestions)
      .where(eq(cbAgentRunSuggestions.status, "active"))
      .all() as AgentRunSuggestion[];
    scannedSuggestionCount = activeSuggestions.length;
    for (const sug of activeSuggestions) {
      const wi =
        (db
          .select()
          .from(cbWorkItems)
          .where(eq(cbWorkItems.id, sug.workItemId))
          .get() as WorkItem | undefined) ?? null;
      if (!wi) continue;
      if (wi.status === "done" || wi.status === "cancelled") {
        db.update(cbAgentRunSuggestions)
          .set({
            status: "superseded",
            updatedAt: generatedAt,
          } as never)
          .where(eq(cbAgentRunSuggestions.id, sug.id))
          .run();
        findings.push({
          kind: "suggestion_superseded_done_work_item",
          agentRunId: null,
          suggestionId: sug.id,
          workItemId: wi.id,
          rationale: `WorkItem ${wi.id} status=${wi.status}; suggestion superseded`,
          newStatus: null,
          appliedAt: generatedAt,
          evidence: { workItemStatus: wi.status },
        });
        continue;
      }
      if (wi.status === "blocked") {
        db.update(cbAgentRunSuggestions)
          .set({
            status: "superseded",
            updatedAt: generatedAt,
          } as never)
          .where(eq(cbAgentRunSuggestions.id, sug.id))
          .run();
        findings.push({
          kind: "suggestion_superseded_blocked_work_item",
          agentRunId: null,
          suggestionId: sug.id,
          workItemId: wi.id,
          rationale: `WorkItem ${wi.id} blocked: ${wi.blockedReason ?? "no reason recorded"}`,
          newStatus: null,
          appliedAt: generatedAt,
          evidence: {
            workItemStatus: wi.status,
            blockedReason: wi.blockedReason,
          },
        });
      }
    }

    // 3. Reconcile via session_result artifacts (running -> needs_review/completed).
    // We look for session_result artifacts whose metadata.workItemId matches a
    // running AgentRun; if outcome=pr_opened/awaiting_review/completed, move
    // the AgentRun status accordingly.
    const stillRunning = db
      .select()
      .from(cbAgentRuns)
      .where(eq(cbAgentRuns.status, "running"))
      .all() as AgentRun[];
    for (const run of stillRunning) {
      if (!run.workItemId) continue;
      const sessionArtifacts = db
        .select()
        .from(cbArtifacts)
        .where(eq(cbArtifacts.artifactType, "session_result"))
        .all();
      const matched = (sessionArtifacts as Array<{
        ingestedAt: number;
        metadata: Record<string, unknown> | null;
      }>)
        .filter((a) => {
          const md = a.metadata ?? {};
          return md["workItemId"] === run.workItemId &&
            (md["outcome"] === "pr_opened" ||
              md["outcome"] === "awaiting_review" ||
              md["outcome"] === "completed");
        })
        .sort((a, b) => b.ingestedAt - a.ingestedAt)[0];
      if (!matched) continue;
      const outcome = (matched.metadata ?? {})["outcome"] as string;
      const newStatus =
        outcome === "completed" ? "completed" : "needs_review";
      const audit = appendAgentRunAuditEntry(run.auditTrail ?? [], {
        actor: "operating-loop:reconciliation",
        event: "agent_run_reconciled_via_session_result",
        note: `Session result artifact outcome=${outcome}; AgentRun moved to ${newStatus}.`,
        metadata: {
          sessionResultIngestedAt: matched.ingestedAt,
          sessionResultOutcome: outcome,
        },
      });
      db.update(cbAgentRuns)
        .set({
          status: newStatus,
          finishedAt: run.finishedAt ?? matched.ingestedAt,
          auditTrail: audit,
          updatedAt: generatedAt,
        } as never)
        .where(eq(cbAgentRuns.id, run.id))
        .run();
      findings.push({
        kind:
          newStatus === "completed"
            ? "completed_via_session_result"
            : "needs_review_via_session_result",
        agentRunId: run.id,
        suggestionId: null,
        workItemId: run.workItemId,
        rationale: `session_result outcome=${outcome}`,
        newStatus,
        appliedAt: generatedAt,
        evidence: {
          sessionResultOutcome: outcome,
          sessionResultIngestedAt: matched.ingestedAt,
        },
      });
    }
  } catch (err) {
    return {
      generatedAt,
      scheduleId: args.scheduleId,
      scheduledAt: args.scheduledAt,
      scannedRunCount,
      scannedSuggestionCount,
      findings,
      errorSummary: err instanceof Error ? err.message : "unknown error",
    };
  }

  return {
    generatedAt,
    scheduleId: args.scheduleId,
    scheduledAt: args.scheduledAt,
    scannedRunCount,
    scannedSuggestionCount,
    findings,
    errorSummary: null,
  };
}

function generateAgentRunSuggestionsForOperatingLoop(args: {
  scheduleId: string | null;
  scheduledAt: number | null;
}): void {
  const db = getDb();
  const data = listAll();
  const nextWork = buildNextWork(data);
  if (!nextWork.recommended) return;

  const recommended = nextWork.recommended;
  const workItem = (data.workItems as WorkItem[]).find(
    (item) => item.id === recommended.workItem.id
  );
  if (!workItem) return;

  const existingPromotedSuggestion = (
    db
      .select()
      .from(cbAgentRunSuggestions)
      .where(
        and(
          eq(cbAgentRunSuggestions.workItemId, workItem.id),
          eq(cbAgentRunSuggestions.status, "active")
        )
      )
      .all() as AgentRunSuggestion[]
  ).find((suggestion) => Boolean(suggestion.promotedAgentRunId));
  if (existingPromotedSuggestion?.promotedAgentRunId) {
    const promotedRun = db
      .select()
      .from(cbAgentRuns)
      .where(eq(cbAgentRuns.id, existingPromotedSuggestion.promotedAgentRunId))
      .get() as AgentRun | undefined;
    if (
      promotedRun &&
      promotedRun.status !== "failed" &&
      promotedRun.status !== "cancelled"
    ) {
      return;
    }
  }

  // Build a synthetic AgentRun-shaped object to feed evaluateRunnerPolicy.
  // No DB row is created; this is preview-only.
  const workflow = loadWorkflowFromRepoRoot();
  const repo = workflow.config.tracker.repo ?? null;

  const syntheticRun = {
    id: `suggestion-${workItem.id}`,
    workItemId: workItem.id,
    workflowRunId: null,
    agentContextId: null,
    sourceId: workItem.sourceId ?? null,
    repo,
    branch: null,
    workspaceRef: null,
    runnerType: "claude_code" as AgentRunRunnerType,
    status: "queued" as AgentRunStatus,
    claimState: "unclaimed" as const,
    attempt: 0,
    startedAt: null,
    finishedAt: null,
    errorSummary: null,
    prUrl: null,
    externalRunRef: null,
    tokensInput: null,
    tokensOutput: null,
    tokensTotal: null,
    costUsd: null,
    agentSessionId: null,
    agentThreadId: null,
    area: workItem.area,
    riskClass: workItem.riskClass ?? "B",
    actionPolicy: "observe_only" as const,
    visibility: workItem.visibility ?? "internal",
    pid: null,
    executionRef: null,
    lastLogAt: null,
    lastLogLineCount: null,
    metadata: null,
    auditTrail: [],
    provenance: null,
    createdAt: now(),
    updatedAt: now(),
  } as unknown as typeof cbAgentRuns.$inferSelect;

  let policy: RunnerExecutionPolicy;
  try {
    policy = evaluateRunnerPolicy({
      agentRun: syntheticRun,
      request: {
        intent: "real_execution",
        actor: "operating-loop:suggester",
        rationale: "preview policy for queued-run suggestion",
      },
    });
  } catch (err) {
    console.error("[company-brain] evaluateRunnerPolicy failed for suggester", err);
    return;
  }

  const satisfiedGates = policy.gates
    .filter((gate) => gate.status === "passed")
    .map((gate) => gate.key);
  const blockedGates = policy.gates
    .filter((gate) => gate.status === "failed")
    .map((gate) => gate.key);

  const signature = buildAgentRunSuggestionSignature({
    workItemId: workItem.id,
    runnerType: "claude_code",
    policyDecision: policy.decision,
    satisfiedGates,
    blockedGates,
    workItemTitle: workItem.title,
    workItemStatus: workItem.status,
    workItemUpdatedAt: workItem.updatedAt,
  });

  const existingForSig = db
    .select()
    .from(cbAgentRunSuggestions)
    .where(eq(cbAgentRunSuggestions.signature, signature))
    .get();
  if (existingForSig) {
    // Already recorded (active, dismissed, or superseded). Do not regenerate.
    return;
  }

  const rationaleParts: string[] = [];
  rationaleParts.push(`Top of next-work: "${workItem.title}".`);
  if (recommended.rationale.length) {
    rationaleParts.push(...recommended.rationale.slice(0, 2));
  }
  rationaleParts.push(
    `Runner policy decision=${policy.decision}; satisfied=${satisfiedGates.length}; blocked=${blockedGates.length}.`
  );
  const rationale = rationaleParts.join(" ").slice(0, 800);

  const generatedFrom: AgentRunSuggestionGeneratedFrom = {
    nextWorkRank: 1,
    nextWorkSource: "buildNextWork:recommended",
    workItemTitle: workItem.title,
    workItemArea: workItem.area,
    suggestedAction: `Run supervised AgentRun for ${workItem.externalId ?? workItem.id} via /agent-runs/:id/execute-async after manual review`,
    sourceIssueRef:
      workItem.externalProvider === "github" && workItem.externalId
        ? workItem.externalId
        : null,
    operatingLoopScheduleId: args.scheduleId,
    operatingLoopScheduledAt: args.scheduledAt,
  };

  // Supersede any existing active rows for this work item before inserting.
  const priorActive = db
    .select()
    .from(cbAgentRunSuggestions)
    .where(
      and(
        eq(cbAgentRunSuggestions.workItemId, workItem.id),
        eq(cbAgentRunSuggestions.status, "active")
      )
    )
    .all() as AgentRunSuggestion[];
  for (const prior of priorActive) {
    db.update(cbAgentRunSuggestions)
      .set({
        status: "superseded",
        updatedAt: now(),
      } as never)
      .where(eq(cbAgentRunSuggestions.id, prior.id))
      .run();
  }

  const id = nanoid(12);
  const timestamp = now();
  const row: AgentRunSuggestion = {
    id,
    workItemId: workItem.id,
    runnerType: "claude_code",
    signature,
    status: "active",
    rationale,
    policyDecision: policy.decision as unknown as Record<string, unknown>,
    generatedFrom,
    promotedAgentRunId: null,
    promotedBy: null,
    promotedAt: null,
    promotionRationale: null,
    dismissReason: null,
    dismissedBy: null,
    dismissedAt: null,
    createdAt: timestamp,
    updatedAt: timestamp,
  };
  db.insert(cbAgentRunSuggestions).values(row as never).run();
}

function listAgentRunSuggestions(args: {
  status?: AgentRunSuggestionStatus | "all";
  workItemId?: string;
}): ListAgentRunSuggestionsResponse {
  const db = getDb();
  const all = db.select().from(cbAgentRunSuggestions).all() as AgentRunSuggestion[];
  const totals = {
    active: all.filter((row) => row.status === "active").length,
    dismissed: all.filter((row) => row.status === "dismissed").length,
    superseded: all.filter((row) => row.status === "superseded").length,
  };
  let filtered = all;
  if (args.status && args.status !== "all") {
    filtered = filtered.filter((row) => row.status === args.status);
  } else if (!args.status) {
    filtered = filtered.filter((row) => row.status === "active");
  }
  if (args.workItemId) {
    filtered = filtered.filter((row) => row.workItemId === args.workItemId);
  }
  filtered = [...filtered].sort((a, b) => b.createdAt - a.createdAt);
  return {
    generatedAt: now(),
    suggestions: filtered,
    totals,
  };
}

app.get("/agent-run-suggestions", (c) => {
  const status = c.req.query("status") as AgentRunSuggestionStatus | "all" | undefined;
  const workItemId = c.req.query("workItemId") || undefined;
  const data = listAgentRunSuggestions({ status, workItemId });
  return c.json({ data });
});

app.post("/agent-run-suggestions/:id/dismiss", async (c) => {
  const id = c.req.param("id");
  const db = getDb();
  const existing = db
    .select()
    .from(cbAgentRunSuggestions)
    .where(eq(cbAgentRunSuggestions.id, id))
    .get() as AgentRunSuggestion | undefined;
  if (!existing) {
    return c.json({ error: "not_found", message: `agent run suggestion ${id} not found` }, 404);
  }
  if (existing.status !== "active") {
    return c.json(
      {
        error: "validation",
        message: `agent run suggestion ${id} is ${existing.status}; only active suggestions can be dismissed`,
      },
      400
    );
  }
  const body = (await c.req
    .json<DismissAgentRunSuggestionRequest>()
    .catch(() => ({}))) as DismissAgentRunSuggestionRequest;
  const actor = body.actor?.trim();
  const rationale = body.rationale?.trim();
  if (!actor) {
    return c.json({ error: "validation", message: "actor is required" }, 400);
  }
  if (!rationale) {
    return c.json({ error: "validation", message: "rationale is required" }, 400);
  }
  const timestamp = now();
  db.update(cbAgentRunSuggestions)
    .set({
      status: "dismissed",
      dismissReason: rationale,
      dismissedBy: actor,
      dismissedAt: timestamp,
      updatedAt: timestamp,
    } as never)
    .where(eq(cbAgentRunSuggestions.id, id))
    .run();
  const refreshed = db
    .select()
    .from(cbAgentRunSuggestions)
    .where(eq(cbAgentRunSuggestions.id, id))
    .get() as AgentRunSuggestion;
  const response: DismissAgentRunSuggestionResponse = {
    generatedAt: timestamp,
    suggestion: refreshed,
  };
  return c.json({ data: response });
});

app.post("/agent-run-suggestions/:id/promote", async (c) => {
  const id = c.req.param("id");
  const db = getDb();
  const existing = db
    .select()
    .from(cbAgentRunSuggestions)
    .where(eq(cbAgentRunSuggestions.id, id))
    .get() as AgentRunSuggestion | undefined;
  if (!existing) {
    return c.json(
      { error: "not_found", message: `agent run suggestion ${id} not found` },
      404
    );
  }
  if (existing.status === "dismissed") {
    return c.json(
      {
        error: "validation",
        message: `suggestion ${id} is dismissed; cannot promote`,
      },
      400
    );
  }
  if (existing.status === "superseded") {
    return c.json(
      {
        error: "validation",
        message: `suggestion ${id} is superseded; only the active suggestion for this WorkItem can be promoted`,
      },
      400
    );
  }
  const body = (await c.req
    .json<PromoteAgentRunSuggestionRequest>()
    .catch(() => ({}))) as PromoteAgentRunSuggestionRequest;
  const actor = body.actor?.trim();
  const rationale = body.rationale?.trim();
  if (!actor) {
    return c.json({ error: "validation", message: "actor is required" }, 400);
  }
  if (!rationale) {
    return c.json(
      { error: "validation", message: "rationale is required" },
      400
    );
  }

  // Idempotent path: already promoted → return existing AgentRun if it still exists.
  if (existing.promotedAgentRunId) {
    const priorRun = db
      .select()
      .from(cbAgentRuns)
      .where(eq(cbAgentRuns.id, existing.promotedAgentRunId))
      .get() as AgentRun | undefined;
    if (priorRun) {
      const response: PromoteAgentRunSuggestionResponse = {
        generatedAt: now(),
        suggestion: existing,
        agentRun: priorRun,
        alreadyPromoted: true,
      };
      return c.json({ data: response });
    }
    // promoted_agent_run_id pointed to a deleted run; reset and recreate.
  }

  // Auto-dispatch actor must pass eligibility before promotion creates an AgentRun.
  const isAutoDispatchActor = actor.startsWith("operating-loop:auto-dispatch");
  if (isAutoDispatchActor) {
    const targetWorkItem =
      (db
        .select()
        .from(cbWorkItems)
        .where(eq(cbWorkItems.id, existing.workItemId))
        .get() as WorkItem | undefined) ?? null;
    const eligibility = evaluateAutoDispatchEligibility({
      workItem: targetWorkItem,
      suggestion: existing,
      actorOverride: actor,
      rationaleOverride: rationale,
    });
    if (!eligibility.eligible) {
      return c.json(
        {
          error: "auto_dispatch_blocked",
          message: `auto-dispatch actor ${actor} cannot promote: decision=${eligibility.decision}, blockReasons=[${eligibility.blockReasons.join(",")}]`,
          data: { eligibility },
        },
        403
      );
    }
  }

  // Resolve repo + workflow context for the new AgentRun.
  const workflow = loadWorkflowFromRepoRoot();
  const repo = workflow.config.tracker.repo ?? null;
  const targetWorkItem =
    (db
      .select()
      .from(cbWorkItems)
      .where(eq(cbWorkItems.id, existing.workItemId))
      .get() as WorkItem | undefined) ?? null;
  if (!targetWorkItem) {
    return c.json(
      {
        error: "validation",
        message: `WorkItem ${existing.workItemId} not found; cannot promote`,
      },
      400
    );
  }

  const timestamp = now();
  const newRunId = nanoid(12);
  const auditEntry = {
    at: timestamp,
    actor,
    event: "agent_run_promoted_from_suggestion",
    note: rationale,
    metadata: {
      suggestionId: existing.id,
      signature: existing.signature,
      autoDispatchActor: isAutoDispatchActor,
    },
  };
  const newRun: AgentRun = {
    id: newRunId,
    workItemId: existing.workItemId,
    workflowRunId: null,
    agentContextId: null,
    sourceId: targetWorkItem.sourceId ?? null,
    repo,
    branch: null,
    workspaceRef: null,
    runnerType: existing.runnerType,
    status: "queued",
    claimState: "unclaimed",
    attempt: 0,
    startedAt: null,
    finishedAt: null,
    errorSummary: null,
    prUrl: null,
    externalRunRef: null,
    tokensInput: null,
    tokensOutput: null,
    tokensTotal: null,
    costUsd: null,
    agentSessionId: null,
    agentThreadId: null,
    area: targetWorkItem.area,
    riskClass: targetWorkItem.riskClass,
    actionPolicy: "observe_only",
    visibility: targetWorkItem.visibility ?? "internal",
    pid: null,
    executionRef: null,
    lastLogAt: null,
    lastLogLineCount: null,
    metadata: {
      promotedFromSuggestionId: existing.id,
      suggestionSignature: existing.signature,
      promotedBy: actor,
      promotionRationale: rationale,
      sourceIssueRef: existing.generatedFrom.sourceIssueRef,
      operatingLoopScheduleId: existing.generatedFrom.operatingLoopScheduleId,
      operatingLoopScheduledAt: existing.generatedFrom.operatingLoopScheduledAt,
    },
    auditTrail: [auditEntry],
    provenance: {
      sourceId: targetWorkItem.sourceId ?? "",
      rawRef: `aios://agent-run-suggestion/${existing.id}`,
      createdFrom: "company_brain:agent_run_suggestion_promotion",
      confidence: 1,
      extractedAt: timestamp,
      humanReviewStatus: "pending",
      visibility: targetWorkItem.visibility ?? "internal",
      notes: `Promoted from suggestion ${existing.id} (signature ${existing.signature.slice(0, 12)}...) by ${actor}`,
    },
    createdAt: timestamp,
    updatedAt: timestamp,
  };
  db.insert(cbAgentRuns).values(newRun as never).run();
  db.update(cbAgentRunSuggestions)
    .set({
      promotedAgentRunId: newRunId,
      promotedBy: actor,
      promotedAt: timestamp,
      promotionRationale: rationale,
      updatedAt: timestamp,
    } as never)
    .where(eq(cbAgentRunSuggestions.id, id))
    .run();
  const refreshed = db
    .select()
    .from(cbAgentRunSuggestions)
    .where(eq(cbAgentRunSuggestions.id, id))
    .get() as AgentRunSuggestion;
  const response: PromoteAgentRunSuggestionResponse = {
    generatedAt: timestamp,
    suggestion: refreshed,
    agentRun: newRun,
    alreadyPromoted: false,
  };
  return c.json({ data: response }, 201);
});

