const ALLOWED_WORK_ITEM_STATUS_VALUES: ReadonlyArray<WorkItemStatus> = [
  "new",
  "triage",
  "planned",
  "in_progress",
  "review",
  "blocked",
  "done",
  "cancelled",
];

app.patch("/work-items/:id/status", async (c) => {
  const id = c.req.param("id");
  const body = (await c.req
    .json<UpdateWorkItemStatusRequest>()
    .catch(() => ({}))) as UpdateWorkItemStatusRequest;
  if (!body.actor || !body.actor.trim()) {
    return c.json({ error: "validation", message: "actor is required" }, 400);
  }
  if (!body.rationale || !body.rationale.trim()) {
    return c.json(
      { error: "validation", message: "rationale is required" },
      400
    );
  }
  if (!body.status || !ALLOWED_WORK_ITEM_STATUS_VALUES.includes(body.status)) {
    return c.json(
      {
        error: "validation",
        message: `status must be one of [${ALLOWED_WORK_ITEM_STATUS_VALUES.join(",")}]`,
      },
      400
    );
  }
  if (body.status === "blocked" && !body.blockedReason?.trim()) {
    return c.json(
      {
        error: "validation",
        message: "blockedReason is required when status=blocked",
      },
      400
    );
  }

  const db = getDb();
  const existing = db
    .select()
    .from(cbWorkItems)
    .where(eq(cbWorkItems.id, id))
    .get() as WorkItem | undefined;
  if (!existing) {
    return c.json(
      { error: "not_found", message: `work item ${id} not found` },
      404
    );
  }

  const previousStatus = existing.status;
  const timestamp = now();
  const internalOverride =
    existing.externalProvider === "github" && existing.externalId
      ? true
      : false;

  // Resolve or create the synthetic source for internal status updates so
  // the audit Artifact has a stable provenance pointer.
  const sourceArea: CompanyBrainArea = existing.area;
  const sourceVisibility: Visibility = existing.visibility ?? "internal";
  const auditSourceId = ensureSessionResultsSource(
    sourceArea,
    sourceVisibility,
    timestamp
  );

  const artifactId = nanoid(12);
  const rawRef = `aios://work-item-status-update/${id}/${timestamp}`;
  const auditTitle = `WorkItem status: ${previousStatus} -> ${body.status} (${existing.title.slice(0, 80)})`;
  const auditMetadata: Record<string, unknown> = {
    workItemId: id,
    previousStatus,
    newStatus: body.status,
    actor: body.actor.trim(),
    rationale: body.rationale.trim(),
    internalOverride,
    blockedReason: body.blockedReason ?? null,
    reviewNote: body.reviewNote ?? null,
  };
  if (internalOverride) {
    auditMetadata.externalRef = existing.externalId;
    auditMetadata.note =
      "Internal-only status override; GitHub issue was NOT mutated. Sync GitHub Issues to reconcile if needed.";
  }
  const auditRow: Artifact = {
    id: artifactId,
    sourceId: auditSourceId,
    artifactType: "session_result",
    area: existing.area,
    title: auditTitle,
    summary: `Internal status update for WorkItem ${id} by ${body.actor.trim()}: ${body.rationale.trim().slice(0, 200)}`,
    contentRef: null,
    rawRef,
    author: body.actor.trim(),
    occurredAt: timestamp,
    ingestedAt: timestamp,
    hash: createHash("sha256")
      .update(JSON.stringify({ id, previousStatus, newStatus: body.status, timestamp }))
      .digest("hex"),
    visibility: sourceVisibility,
    provenance: {
      sourceId: auditSourceId,
      rawRef,
      artifactId,
      createdFrom: "company_brain:work_item_status_update",
      confidence: 1,
      extractedAt: timestamp,
      humanReviewStatus: "approved",
      visibility: sourceVisibility,
      notes: `actor=${body.actor.trim()}; status=${previousStatus}->${body.status}; internalOverride=${internalOverride}`,
    },
    humanReviewStatus: "approved",
    confidence: 1,
    metadata: auditMetadata,
  };
  db.insert(cbArtifacts).values(auditRow as never).run();

  // Update the WorkItem.
  const updates: Record<string, unknown> = {
    status: body.status,
    updatedAt: timestamp,
  };
  if (body.status === "blocked") {
    updates.blockedReason = body.blockedReason!.trim();
  } else {
    updates.blockedReason = body.blockedReason?.trim() || null;
  }
  db.update(cbWorkItems)
    .set(updates as never)
    .where(eq(cbWorkItems.id, id))
    .run();

  const refreshed = db
    .select()
    .from(cbWorkItems)
    .where(eq(cbWorkItems.id, id))
    .get() as WorkItem;

  const response: UpdateWorkItemStatusResponse = {
    generatedAt: timestamp,
    workItem: refreshed,
    previousStatus,
    internalOverride,
    artifactId,
  };
  return c.json({ data: response });
});

app.post("/extractors/artifact-insights", async (c) => {
  try {
    const body = await c.req.json<ExtractArtifactInsightsRequest>();
    const db = getDb();
    const timestamp = now();
    const artifactId = requireText(body.artifactId, "artifactId");
    const artifact = db.select().from(cbArtifacts).where(eq(cbArtifacts.id, artifactId)).get();
    if (!artifact) throw new Error("artifactId not found");
    const source = db.select().from(cbSources).where(eq(cbSources.id, artifact.sourceId)).get();
    const priorityId = body.priorityId ?? null;
    if (priorityId) {
      const priority = db
        .select()
        .from(cbStrategicPriorities)
        .where(eq(cbStrategicPriorities.id, priorityId))
        .get();
      if (!priority) throw new Error("priorityId not found");
    }
    const goalId = body.goalId ?? null;
    if (goalId) {
      const goal = db.select().from(cbGoals).where(eq(cbGoals.id, goalId)).get();
      if (!goal) throw new Error("goalId not found");
    }
    const workItemId = body.workItemId ?? null;
    if (workItemId) {
      const workItem = db
        .select()
        .from(cbWorkItems)
        .where(eq(cbWorkItems.id, workItemId))
        .get();
      if (!workItem) throw new Error("workItemId not found");
    }

    const mode = body.mode ?? "both";
    const text = candidateText(artifact.title, artifact.summary);
    const owner = body.owner ?? source?.owner ?? null;
    let decision = null;
    let signal = null;
    let decisionCreated = false;
    let signalCreated = false;

    if (mode === "decision" || mode === "both") {
      decision =
        db
          .select()
          .from(cbDecisions)
          .all()
          .find(
            (item) =>
              item.sourceArtifactIds.includes(artifact.id) &&
              item.provenance?.createdFrom === "extractor:artifact_insights"
          ) ?? null;
      if (!decision) {
        decision = {
          id: nanoid(12),
          title: `Decision candidate: ${artifact.title.slice(0, 90)}`,
          summary: text,
          rationale:
            "Candidate extracted from an artifact by extractor v0. Human review is required before treating it as an accepted decision.",
          area: artifact.area,
          owner,
          ownerType: owner ? (source?.ownerType ?? "human") : ("unknown" as const),
          status: "proposed" as const,
          decidedAt: null,
          sourceArtifactIds: [artifact.id],
          priorityIds: priorityId ? [priorityId] : [],
          goalIds: goalId ? [goalId] : [],
          visibility: artifact.visibility,
          provenance: {
            sourceId: artifact.sourceId,
            rawRef: artifact.rawRef,
            artifactId: artifact.id,
            createdFrom: "extractor:artifact_insights",
            confidence: 0.65,
            extractedAt: timestamp,
            humanReviewStatus: "pending" as const,
            visibility: artifact.visibility,
            notes: "candidate=true; extractor=artifact_insights_v0",
          },
          createdAt: timestamp,
          updatedAt: timestamp,
        };
        db.insert(cbDecisions).values(decision).run();
        db.insert(cbArtifactLinks)
          .values({
            id: nanoid(12),
            artifactId: artifact.id,
            targetType: "decision",
            targetId: decision.id,
            relationship: "candidate_source_for_decision",
            confidence: 0.65,
            rationale: "Decision candidate extracted from this artifact.",
            createdAt: timestamp,
          })
          .run();
        decisionCreated = true;
      }
    }

    if (mode === "signal" || mode === "both") {
      signal =
        db
          .select()
          .from(cbSignals)
          .all()
          .find(
            (item) =>
              item.artifactId === artifact.id &&
              item.metadata?.extractor === "artifact_insights_v0"
          ) ?? null;
      if (!signal) {
        signal = {
          id: nanoid(12),
          source: body.signalSource ?? signalSourceFromArtifact(artifact.artifactType),
          scope: "core" as const,
          entityType: "job" as const,
          entityId: workItemId ?? artifact.id,
          timestamp: artifact.occurredAt,
          summary: `Candidate signal: ${text}`,
          rawRef: artifact.rawRef,
          severity: body.signalSeverity ?? "info",
          confidence: 0.65,
          tags: ["candidate", "artifact_extractor_v0", artifact.artifactType],
          area: artifact.area,
          sourceId: artifact.sourceId,
          artifactId: artifact.id,
          workItemId,
          workflowRunId: null,
          watcherId: null,
          watcherRunId: null,
          visibility: artifact.visibility,
          provenance: {
            sourceId: artifact.sourceId,
            rawRef: artifact.rawRef,
            artifactId: artifact.id,
            createdFrom: "extractor:artifact_insights",
            confidence: 0.65,
            extractedAt: timestamp,
            humanReviewStatus: "pending" as const,
            visibility: artifact.visibility,
            notes: "candidate=true; extractor=artifact_insights_v0",
          },
          metadata: {
            extractor: "artifact_insights_v0",
            candidate: true,
            mode,
            priorityId,
            goalId,
          },
          createdAt: timestamp,
          updatedAt: timestamp,
        };
        db.insert(cbSignals).values(signal).run();
        signalCreated = true;
      }
    }

    return c.json(
      {
        data: {
          artifact,
          decision,
          signal,
          decisionCreated,
          signalCreated,
        },
      },
      201
    );
  } catch (err) {
    const message = err instanceof Error ? err.message : "Unknown error";
    return c.json({ error: "extract_failed", message }, 400);
  }
});

